interface GoalWorkflowFormsProps {
    goal: any;
    role: 'TEACHER' | 'LEADER' | 'ADMIN';
    onComplete: () => void;
    onClose: () => void;
}

type Phase = 'SELF_REFLECTION' | 'GOAL_SETTING' | 'GOAL_COMPLETION' | 'VIEW' | 'MASTER_FORM';

export const GoalWorkflowForms = ({ goal, role, onComplete, onClose }: GoalWorkflowFormsProps) => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const { getRedirectionPath } = useFormFlow();
    const getInitialPhase = (r: string, status: string): Phase => {
        if (r === 'TEACHER') {
            if (status === 'SELF_REFLECTION_PENDING' || status === 'IN_PROGRESS') return 'SELF_REFLECTION';
            return 'VIEW';
        } else if (r === 'LEADER') {
            if (status === 'SELF_REFLECTION_SUBMITTED') return 'GOAL_SETTING';
            if (status === 'GOAL_SET') return 'GOAL_COMPLETION';
            return 'VIEW';
        } else if (r === 'ADMIN') {
            return 'MASTER_FORM';
        }
        return 'VIEW';
    };

    const [phase, setPhase] = useState<Phase>(() => getInitialPhase(role, goal.status));
    const [formData, setFormData] = useState<any>({});
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [windows, setWindows] = useState<any[]>([]);
    const [formStep, setFormStep] = useState(0); // wizard step (growth module pattern)

    const getFrameworkType = (g: any, u: any) => {
        const email = g.teacherEmail?.toLowerCase() || u?.email?.toLowerCase() || '';
        const dept = g.teacherDepartment || u?.department || '';
        const title = g.title?.toLowerCase() || '';
        const category = g.category || '';

        const isPE = dept === 'Physical Education' || email.includes('.pe') || category === 'Physical Education' || title.includes('physical education') || title.includes('p.e');
        if (isPE) return 'PE';

        const isVA = dept === 'Visual Arts' || email.includes('.va') || category === 'Visual Arts' || title.includes('visual arts');
        if (isVA) return 'VA';

        const isPA = dept === 'Performing Arts' || dept === 'Arts' || email.includes('.art') || category === 'Performing Arts' || title.includes('performing arts') || title.includes('arts');
        if (isPA) return 'PA';

        if (g.academicType === 'CORE') return 'CORE';
        return 'SIMPLE';
    };

    useEffect(() => {
        fetchWindows();
        if (phase === 'VIEW') determinePhase();

        // 🚨 FIX: Only override formData if we don't have local unsaved changes for THIS goal
        // or if the goal ID has changed.
        const currentRefData = safeJsonParse(goal.selfReflectionForm);
        setFormData((prev: any) => {
            // If goal ID changed, reset everything
            if (prev?._lastGoalId !== goal.id) {
                return { ...currentRefData, _lastGoalId: goal.id };
            }
            // If we have local state, keep it (don't overwrite with server data while editing)
            return prev;
        });
    }, [goal.id, goal.selfReflectionForm, phase]); // Refined dependencies

    const fetchWindows = async () => {
        try {
            const res = await api.get('/goal-windows');
            setWindows(res.data.data.windows);
        } catch (err) {
            console.error("Failed to fetch goal windows", err);
        }
    };

    const determinePhase = () => {
        setPhase(getInitialPhase(role, goal.status));
    };

    const isWindowOpen = (p: string) => {
        const win = windows.find(w => w.phase === p);
        if (!win || win.status === 'CLOSED') return false;
        const now = new Date();
        if (win.startDate && now < new Date(win.startDate)) return false;
        if (win.endDate && now > new Date(win.endDate)) return false;
        return true;
    };

    const validateStep = (currentStep: number): boolean => {
        if (phase !== 'SELF_REFLECTION') return true;
        
        const fwType = getFrameworkType(goal, user);
        const isPE = fwType === 'PE';
        const isPA = fwType === 'PA';
        const isVA = fwType === 'VA';
        const isCore = fwType === 'CORE';

        if (isCore) {
            const isFinalCoreStep = currentStep === CORE_FRAMEWORK.length;
            if (isFinalCoreStep) {
                const r = formData?.reflection;
                if (!r?.strengths || !r?.improvement || !r?.goal) {
                    toast.error("Please fill all mandatory fields (marked with *)");
                    return false;
                }
                return true;
            } else {
                const section = CORE_FRAMEWORK[currentStep];
                // Check ratings
                const missingRating = section.items.some(item => !formData?.ratings?.[item]);
                if (missingRating) {
                    toast.error(`Please provide ratings for all items in "${section.section.split(': ')[1]}"`);
                    return false;
                }
                // Check evidence
                if (!formData?.evidence?.[section.evidenceId]) {
                    toast.error(`Please provide evidence for "${section.section.split(': ')[1]}"`);
                    return false;
                }
                return true;
            }
        }

        if (isPA || isPE || isVA) {
            const framework = isPA ? PA_FRAMEWORK : isPE ? PE_FRAMEWORK : VA_FRAMEWORK;
            const isBlockStep = currentStep === 0;
            const isDynamicsStep = currentStep === framework.length + 1;
            const isFinalStep = currentStep === framework.length + 2;
            const sectionIdx = !isBlockStep && !isDynamicsStep && !isFinalStep ? currentStep - 1 : null;

            if (isBlockStep) {
                if (!formData?.block) {
                    toast.error("Please select a category block before proceeding");
                    return false;
                }
                return true;
            }

            if (sectionIdx !== null) {
                const section = framework[sectionIdx];
                const missingRating = section.items.some(item => !formData?.ratings?.[item]);
                if (missingRating) {
                    toast.error(`Please provide ratings for all items in "${section.section}"`);
                    return false;
                }
                if (!formData?.evidence?.[section.id]) {
                    toast.error(`Please provide evidence for "${section.section}"`);
                    return false;
                }
                return true;
            }

            if (isDynamicsStep) {
                if (!formData?.overallRating) {
                    toast.error("Please provide an overall classroom rating");
                    return false;
                }
                return true;
            }

            if (isFinalStep) {
                const r = formData?.reflection;
                if (!r?.strengths || !r?.improvement || !r?.goal) {
                    toast.error("Please fill all mandatory fields (marked with *)");
                    return false;
                }
                return true;
            }
        }

        if (fwType === 'SIMPLE') {
            if (!formData?.impact || !formData?.evidence || !formData?.text) {
                toast.error("Please fill all mandatory fields (Impact, Evidence, and Summary)");
                return false;
            }
            return true;
        }

        return true;
    };

    const handleSubmit = async () => {
        if (role !== 'ADMIN' && !isWindowOpen(phase)) {
            toast.error("Submission window is currently closed");
            return;
        }

        if (phase === 'SELF_REFLECTION' && !validateStep(formStep)) {
            return;
        }

        setIsSubmitting(true);
        try {
            let endpoint = '';
            let payload = {};

            if (phase === 'SELF_REFLECTION') {
                endpoint = `/goals/${goal.id}/self-reflection`;
                payload = { reflectionData: formData };
            } else if (phase === 'GOAL_SETTING') {
                endpoint = `/goals/${goal.id}/goal-setting`;
                payload = { settingData: formData };
            } else if (phase === 'GOAL_COMPLETION') {
                endpoint = `/goals/${goal.id}/goal-completion`;
                payload = { completionData: formData, status: formData.status || 'GOAL_COMPLETED' };
            }

            const res = await api.post(endpoint, payload);
            if (res.data.status === 'success') {
                toast.success("Submitted successfully");

                if (user?.role) {
                    const formName = phase === 'SELF_REFLECTION' ? 'GOAL_REFLECTION'
                        : phase === 'GOAL_SETTING' ? 'GOAL_SETTING'
                            : 'GOAL_COMPLETION';
                    const redirectPath = getRedirectionPath(formName, user.role);
                    if (redirectPath) {
                        navigate(redirectPath);
                        return;
                    }
                }

                onComplete();
            }
        } catch (err: any) {
            toast.error(err.response?.data?.message || "Failed to submit");
        } finally {
            setIsSubmitting(false);
        }
    };

    const renderContent = () => {
        if (phase === 'MASTER_FORM') {
            return (
                <ScrollArea className="h-[65vh] w-full">
                    <GoalSettingForm
                        userCampus={user?.campusId}
                        isLeader={role === 'LEADER'}
                        teachers={[{ id: goal.teacherId || "temp-id", name: goal.teacher || "Unknown", email: goal.teacherEmail || "", academics: goal.academicType || "CORE" }]}
                        defaultCoachName={goal.assignedBy || "Admin"}
                        initialData={{
                            educatorName: goal.teacher,
                            teacherEmail: goal.teacherEmail || "",
                            coachName: goal.assignedBy || "Admin",
                            campus: goal.campus || "HQ",
                            dateOfGoalSetting: goal.createdAt ? new Date(goal.createdAt) : new Date(),
                            goalForYear: goal.title,
                            reasonForGoal: goal.description || "Defined during goal setting",
                            actionStep: goal.actionStep || "Initial planning",
                            pillarTag: goal.category || goal.pillar || "Professional Practice",
                            goalEndDate: goal.dueDate ? new Date(goal.dueDate) : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
                            awareOfProcess: "yes",
                            awareOfFramework: "yes",
                            reflectionCompleted: "yes",
                            evidenceProvided: "yes",
                            ...safeJsonParse(goal.goalSettingForm)
                        }}
                        onSubmit={async (data) => {
                            if (role !== 'ADMIN') return;
                            try {
                                setIsSubmitting(true);
                                const payload = {
                                    title: data.goalForYear || goal.title,
                                    description: data.reasonForGoal !== undefined ? data.reasonForGoal : goal.description,
                                    actionStep: data.actionStep !== undefined ? data.actionStep : goal.actionStep,
                                    pillar: data.pillarTag || goal.pillar,
                                    category: data.pillarTag || goal.category,
                                    campus: data.campus || goal.campus,
                                    dueDate: data.goalEndDate ? new Date(data.goalEndDate).toISOString() : goal.dueDate,
                                    goalSettingForm: JSON.stringify(data)
                                };
                                const res = await api.patch(`/goals/${goal.id}`, payload);
                                if (res.data?.status === 'success' || res.status === 200) {
                                    toast.success(`Goal master form updated for ${goal.teacher}.`);

                                    if (user?.role) {
                                        const redirectPath = getRedirectionPath('GOAL_SETTING', user.role);
                                        if (redirectPath) {
                                            navigate(redirectPath);
                                            return;
                                        }
                                    }

                                    onComplete();
                                }
                            } catch (err) {
                                toast.error("Failed to update goal via master form.");
                            } finally {
                                setIsSubmitting(false);
                            }
                        }}
                        onCancel={onClose}
                    />
                </ScrollArea>
            );
        }

        if (phase === 'SELF_REFLECTION') {
            const fwType = getFrameworkType(goal, user);
            const isPE = fwType === 'PE';
            const isPA = fwType === 'PA';
            const isVA = fwType === 'VA';
            const isCore = fwType === 'CORE';

            if (isCore) {
                const isFinalCoreStep = formStep === CORE_FRAMEWORK.length;
                const coreSection = !isFinalCoreStep ? CORE_FRAMEWORK[formStep] : null;
                return (
                    <div className="space-y-6">
                        <div className="mb-8">
                            <div className="flex items-center justify-between mb-4">
                                <div className="flex items-center gap-4">
                                    <div className="p-3 rounded-2xl bg-primary shadow-[0_8px_20px_rgba(234,16,74,0.25)] text-white">
                                        {isFinalCoreStep ? <CheckCircle2 className="w-6 h-6" /> : <Sparkles className="w-6 h-6" />}
                                    </div>
                                    <div className="space-y-1">
                                        <h3 className="text-xl font-black text-foreground tracking-tight">
                                            {isFinalCoreStep ? 'Final Reflection' : coreSection?.section.split(': ')[1] || coreSection?.section}
                                        </h3>
                                        <div className="flex items-center gap-2">
                                            <Badge variant="outline" className="text-[10px] font-bold capitalize tracking-widest border-primary/20 text-primary">
                                                {isFinalCoreStep ? 'Review Phase' : `Step ${formStep + 1} of ${CORE_FRAMEWORK.length}`}
                                            </Badge>
                                            <div className="flex gap-1">
                                                {CORE_FRAMEWORK.map((_, i) => (
                                                    <div
                                                        key={i}
                                                        className={cn(
                                                            "h-1 rounded-full transition-all duration-500",
                                                            i < formStep ? "w-4 bg-emerald-500" : i === formStep ? "w-8 bg-primary shadow-[0_0_10px_rgba(234,16,74,0.3)]" : "w-4 bg-muted"
                                                        )}
                                                    />
                                                ))}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                        {
                            !isFinalCoreStep && coreSection ? (
                                <>
                                    <div className="grid gap-3">
                                        {coreSection.items.map((item, itemIdx) => (
                                            <div key={itemIdx} className="p-4 rounded-xl bg-muted/30 border border-muted-foreground/10 hover:border-primary/20 transition-colors space-y-3">
                                                <p className="text-sm font-semibold text-foreground/90">{item}</p>
                                                <RadioGroup
                                                    name={`core-ratings-${coreSection.id}-${itemIdx}`}
                                                    onValueChange={(val) => setFormData((prev: any) => ({ ...(prev || {}), ratings: { ...(prev?.ratings || {}), [item]: val } }))}
                                                    value={formData?.ratings?.[item] || ''}
                                                    className="flex flex-wrap gap-2 pt-1"
                                                >
                                                    {RATING_LEVELS.map((level, levelIdx) => {
                                                        const sId = `core-${coreSection.id}-${itemIdx}-${levelIdx}`;
                                                        return (
                                                            <div key={levelIdx} className="flex items-center space-x-2 bg-background px-3 py-1.5 rounded-full border border-muted hover:border-primary/30 transition-colors cursor-pointer">
                                                                <RadioGroupItem value={level} id={sId} className="w-4 h-4" />
                                                                <Label htmlFor={sId} className="text-xs cursor-pointer font-medium">{level}</Label>
                                                            </div>
                                                        );
                                                    })}
                                                </RadioGroup>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="space-y-2">
                                        <Label htmlFor={`core-evidence-${coreSection.id}`} className="text-xs font-bold text-muted-foreground capitalize flex items-center gap-1.5">
                                            <FileText className="w-3.5 h-3.5" /> Evidence for {coreSection.evidenceId}
                                        </Label>
                                        <Textarea
                                            id={`core-evidence-${coreSection.id}`}
                                            name={`core-evidence-${coreSection.id}`}
                                            placeholder="Provide specific evidence to support your ratings..."
                                            className="min-h-[90px] rounded-xl"
                                            value={formData?.evidence?.[coreSection.evidenceId] || ''}
                                            onChange={(e) => {
                                                const newEvidence = { ...(formData?.evidence || {}), [coreSection.evidenceId]: e.target.value };
                                                setFormData((prev: any) => ({ ...(prev || {}), evidence: newEvidence }));
                                            }}
                                        />
                                    </div>
                                </>
                            ) : (
                                <div className="space-y-4">
                                    {[
                                        { id: 'strengths', l: 'What are your strengths? *' },
                                        { id: 'improvement', l: 'What do you need to improve on? *' },
                                        { id: 'goal', l: 'What goal would you like to set for yourself? *' },
                                        { id: 'anythingElse', l: "Anything else you'd like to share" }
                                    ].map(field => {
                                        const fieldId = `core-reflection-${field.id}`;
                                        return (
                                            <div key={field.id} className="space-y-2">
                                                <Label htmlFor={fieldId} className="text-xs font-bold">{field.l}</Label>
                                                <Textarea
                                                    id={fieldId}
                                                    name={fieldId}
                                                    className="min-h-[80px] rounded-xl bg-background"
                                                    value={formData?.reflection?.[field.id] || ''}
                                                    onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), reflection: { ...(prev?.reflection || {}), [field.id]: e.target.value } }))}
                                                />
                                            </div>
                                        );
                                    })}
                                </div>
                            )
                        }
                    </div >
                );
            }

            if (isPA || isPE || isVA) {
                const framework = isPA ? PA_FRAMEWORK : isPE ? PE_FRAMEWORK : VA_FRAMEWORK;
                const frameworkName = isPA ? 'Performing Arts' : isPE ? 'Physical Education' : 'Visual Arts';
                const ratingOptions = isVA ? ['Yes', 'No', 'Not Applicable'] : ['Yes', 'No'];

                // Steps: 0=block, 1..N=sections, N+1=classroom dynamics, N+2=final reflection
                const isBlockStep = formStep === 0;
                const isDynamicsStep = formStep === framework.length + 1;
                const isFinalStep = formStep === framework.length + 2;
                const sectionIdx = !isBlockStep && !isDynamicsStep && !isFinalStep ? formStep - 1 : null;
                const currentSection = sectionIdx !== null ? framework[sectionIdx] : null;

                const stepLabel = isBlockStep ? 'Grade Level'
                    : isDynamicsStep ? 'Classroom Dynamics'
                        : isFinalStep ? 'Final Reflection'
                            : `Section ${sectionIdx !== null ? sectionIdx + 1 : ''}`;

                return (
                    <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                        <div className="flex items-center gap-3 mb-2">
                            <div className="flex items-center justify-center w-10 h-10 rounded-full bg-primary/10 text-primary font-bold text-lg border border-primary/20">
                                {isBlockStep ? '⊞' : isFinalStep ? '✓' : isDynamicsStep ? '⚡' : (sectionIdx ?? 0) + 1}
                            </div>
                            <div>
                                <p className="text-xs font-bold text-muted-foreground capitalize tracking-wider">
                                    {frameworkName} Track · {stepLabel}
                                </p>
                                <p className="font-semibold text-foreground">
                                    {isBlockStep ? 'Select your category block'
                                        : isDynamicsStep ? 'Classroom Dynamics & Tools'
                                            : isFinalStep ? 'Strengths, Goals & Improvements'
                                                : currentSection?.section}
                                </p>
                            </div>
                        </div>

                        {isBlockStep && (
                            <div className="space-y-3">
                                <Label htmlFor="grade-level-select" className="text-xs font-bold text-muted-foreground capitalize">Select your current category block *</Label>
                                <RadioGroup
                                    id="grade-level-select"
                                    name="grade-level"
                                    onValueChange={(b) => setFormData((prev: any) => ({ ...(prev || {}), block: b }))}
                                    value={formData?.block || ''}
                                    className="flex flex-wrap gap-3 pt-1"
                                >
                                    {['Early Years', 'Primary', 'Middle', 'Senior', 'Whole School'].map((b, bIdx) => {
                                        const bId = `block-${bIdx}`;
                                        const isSelected = formData?.block === b;
                                        return (
                                            <div key={bIdx} className="flex items-center">
                                                <RadioGroupItem value={b} id={bId} className="sr-only" />
                                                <Label
                                                    htmlFor={bId}
                                                    className={`flex items-center gap-2 px-4 py-2.5 rounded-xl border cursor-pointer transition-all ${isSelected ? 'bg-primary/10 border-primary/50 font-bold text-primary' : 'bg-muted/30 border-muted-foreground/10 hover:border-primary/20'}`}
                                                >
                                                    <span className={`w-3 h-3 rounded-full border-2 ${isSelected ? 'border-primary bg-primary' : 'border-muted-foreground/40'}`} />
                                                    <span className="text-sm">{b}</span>
                                                </Label>
                                            </div>
                                        );
                                    })}
                                </RadioGroup>
                            </div>
                        )}

                        {currentSection && (
                            <>
                                <div className="grid gap-3">
                                    {currentSection.items.map((item, itemIdx) => (
                                        <div key={itemIdx} className="p-4 rounded-xl bg-muted/30 border border-muted-foreground/10 hover:border-primary/20 transition-colors space-y-3">
                                            <p className="text-sm font-semibold text-foreground/90">{item}</p>
                                            <RadioGroup
                                                name={`spec-ratings-${currentSection.id}-${itemIdx}`}
                                                onValueChange={(val) => setFormData((prev: any) => ({ ...(prev || {}), ratings: { ...(prev?.ratings || {}), [item]: val } }))}
                                                value={formData?.ratings?.[item] || ''}
                                                className="flex flex-wrap gap-2 pt-1"
                                            >
                                                {RATING_LEVELS.map((level, levelIdx) => {
                                                    const sId = `spec-${currentSection.id}-${itemIdx}-${levelIdx}`;
                                                    return (
                                                        <div key={levelIdx} className="flex items-center space-x-2 bg-background px-3 py-1.5 rounded-full border border-muted hover:border-primary/30 transition-colors cursor-pointer">
                                                            <RadioGroupItem value={level} id={sId} className="w-4 h-4" />
                                                            <Label htmlFor={sId} className="text-xs cursor-pointer font-medium">{level}</Label>
                                                        </div>
                                                    );
                                                })}
                                            </RadioGroup>
                                        </div>
                                    ))}
                                </div>
                                <div className="space-y-2">
                                    <Label htmlFor={`spec-evidence-${currentSection.id}`} className="text-xs font-bold text-muted-foreground capitalize flex items-center gap-1.5">
                                        <FileText className="w-3.5 h-3.5" /> Evidence for {currentSection.id}
                                    </Label>
                                    <Textarea
                                        id={`spec-evidence-${currentSection.id}`}
                                        name={`spec-evidence-${currentSection.id}`}
                                        placeholder="Provide specific evidence..."
                                        className="min-h-[80px] rounded-xl"
                                        value={formData?.evidence?.[currentSection.id] || ''}
                                        onChange={(e) => {
                                            const newEvidence = { ...(formData?.evidence || {}), [currentSection.id]: e.target.value };
                                            setFormData((prev: any) => ({ ...(prev || {}), evidence: newEvidence }));
                                        }}
                                    />
                                </div>
                            </>
                        )}

                        {isDynamicsStep && (
                            <div className="space-y-6">
                                <div className="space-y-3">
                                    <Label htmlFor="overall-rating-radio" className="text-xs font-bold">How would you rate your classroom overall?</Label>
                                    <div className="flex items-center gap-4 flex-wrap">
                                        <span className="text-xs text-muted-foreground font-medium">Basic</span>
                                        <RadioGroup
                                            id="overall-rating-radio"
                                            name="overall-rating"
                                            className="flex gap-3"
                                            onValueChange={(val) => setFormData((prev: any) => ({ ...(prev || {}), overallRating: val }))}
                                            value={formData?.overallRating || ''}
                                        >
                                            {['1', '2', '3', '4'].map((r, rIdx) => (
                                                <div key={rIdx} className="flex flex-col items-center gap-1 bg-background p-2 rounded-xl border border-muted hover:border-primary/30 transition-colors cursor-pointer min-w-[48px]">
                                                    <RadioGroupItem value={r} id={`rating-${rIdx}`} />
                                                    <Label htmlFor={`rating-${rIdx}`} className="text-xs font-bold cursor-pointer">{r}</Label>
                                                </div>
                                            ))}
                                        </RadioGroup>
                                        <span className="text-xs text-primary font-bold">Highly Effective</span>
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold">Tools you actively use in your classroom:</Label>
                                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-2 mt-1">
                                        {SPECIALIST_TOOLS.map((tool, tIdx) => (
                                            <div key={tIdx} className="flex items-center gap-2 bg-muted/30 p-2 px-3 rounded-lg border border-muted hover:border-primary/20 transition-colors">
                                                <Checkbox
                                                    id={`tool-${tIdx}`}
                                                    name={`tool-${tool}`}
                                                    checked={(formData?.tools || []).includes(tool)}
                                                    onCheckedChange={(checked) => {
                                                        setFormData((prev: any) => {
                                                            const tools = prev?.tools || [];
                                                            return { ...(prev || {}), tools: checked ? [...tools, tool] : tools.filter((t: string) => t !== tool) };
                                                        });
                                                    }}
                                                />
                                                <Label htmlFor={`tool-${tIdx}`} className="text-xs cursor-pointer font-medium leading-tight">{tool}</Label>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold">Routines you actively use in your classroom:</Label>
                                    <div className="grid grid-cols-2 lg:grid-cols-3 gap-2 mt-1">
                                        {SPECIALIST_ROUTINES.map((routine, rIdx) => (
                                            <div key={rIdx} className="flex items-center gap-2 bg-muted/30 p-2 px-3 rounded-lg border border-muted hover:border-primary/20 transition-colors">
                                                <Checkbox
                                                    id={`routine-${rIdx}`}
                                                    name={`routine-${routine}`}
                                                    checked={(formData?.routines || []).includes(routine)}
                                                    onCheckedChange={(checked) => {
                                                        setFormData((prev: any) => {
                                                            const routines = prev?.routines || [];
                                                            return { ...(prev || {}), routines: checked ? [...routines, routine] : routines.filter((r: string) => r !== routine) };
                                                        });
                                                    }}
                                                />
                                                <Label htmlFor={`routine-${rIdx}`} className="text-xs cursor-pointer font-medium leading-tight">{routine}</Label>
                                            </div>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        )}

                        {isFinalStep && (
                            <div className="space-y-4">
                                {[
                                    { id: 'strengths', l: isPE ? 'What are your strengths as a PE educator? *' : isVA ? 'What are your strengths as a visual arts educator? *' : 'What are your strengths? *' },
                                    { id: 'improvement', l: 'What do you need to improve on? *' },
                                    { id: 'goal', l: 'What goal would you like to set for yourself? *' },
                                    { id: 'anythingElse', l: "Anything else you'd like to share" }
                                ].map(field => {
                                    const fieldId = `spec-reflection-${field.id}`;
                                    return (
                                        <div key={field.id} className="space-y-2">
                                            <Label htmlFor={fieldId} className="text-xs font-bold">{field.l}</Label>
                                            <Textarea
                                                id={fieldId}
                                                name={fieldId}
                                                className="min-h-[80px] rounded-xl bg-background"
                                                value={formData?.reflection?.[field.id] || ''}
                                                onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), reflection: { ...(prev?.reflection || {}), [field.id]: e.target.value } }))}
                                            />
                                        </div>
                                    );
                                })}
                            </div>
                        )}
                    </div>
                );
            }

            return (
                <div className="space-y-4">
                    <div className="bg-primary/5 p-4 rounded-xl border border-primary/20">
                        <p className="text-sm font-medium">Goal: {goal.title}</p>
                        <Badge variant="secondary" className="mt-2 text-[10px] capitalize">Non-Core Track</Badge>
                    </div>

                    <Card className="  shadow-sm bg-primary/5 overflow-hidden">
                        <CardHeader className="pb-2">
                            <CardTitle className="text-xs font-bold capitalize text-primary">Non-Core Self-Reflection</CardTitle>
                        </CardHeader>
                        <CardContent className="p-6 space-y-6">
                            <div className="space-y-2">
                                <Label htmlFor="simple-impact" className="text-xs font-bold text-muted-foreground capitalize">Professional Contribution</Label>
                                <Textarea
                                    id="simple-impact"
                                    name="simple-impact"
                                    placeholder="Describe your professional contribution and collaboration..."
                                    className="min-h-[100px] bg-background"
                                    value={formData?.impact || ''}
                                    onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), impact: e.target.value }))}
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="simple-evidence" className="text-xs font-bold text-muted-foreground capitalize">Skill Development & Alignment</Label>
                                <Textarea
                                    id="simple-evidence"
                                    name="simple-evidence"
                                    placeholder="Describe skills developed and alignment with school needs..."
                                    className="min-h-[100px] bg-background"
                                    value={formData?.evidence || ''}
                                    onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), evidence: e.target.value }))}
                                />
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="simple-summary" className="text-xs font-bold text-muted-foreground capitalize">Summary</Label>
                                <Textarea
                                    id="simple-summary"
                                    name="simple-summary"
                                    placeholder="Final summary and any additional support required..."
                                    className="min-h-[120px] bg-background"
                                    value={formData?.text || ''}
                                    onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), text: e.target.value }))}
                                />
                            </div>
                        </CardContent>
                    </Card>
                </div>
            );
        }

        const renderDetailedReflection = () => {
            if (!goal.selfReflectionForm) return null;
            const refData = safeJsonParse(goal.selfReflectionForm);

            const fwType = getFrameworkType(goal, user);
            const isPE = fwType === 'PE';
            const isVA = fwType === 'VA';
            const isPA = fwType === 'PA';
            const isCore = fwType === 'CORE';

            if (isPA || isPE || isVA) {
                const framework = isPA ? PA_FRAMEWORK : isPE ? PE_FRAMEWORK : VA_FRAMEWORK;
                return (
                    <div className="space-y-6">
                        <div className="flex justify-between items-center bg-primary/5 p-4 rounded-xl border border-primary/10">
                            <div>
                                <p className="text-[10px] font-bold text-primary capitalize">Category Block</p>
                                <p className="text-sm font-semibold">{refData.block}</p>
                            </div>
                            <div className="text-right">
                                <p className="text-[10px] font-bold text-primary capitalize">Overall Rating</p>
                                <Badge className="bg-primary text-white">{refData.overallRating || 'N/A'}/4</Badge>
                            </div>
                        </div>

                        {framework.map(section => (
                            <Card key={section.id} className="shadow-sm bg-muted/20 overflow-hidden">
                                <CardHeader className="bg-primary/5 pb-2">
                                    <CardTitle className="text-xs font-bold capitalize tracking-tight text-primary">
                                        {section.section}
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="pt-4 space-y-3">
                                    <div className="grid gap-2">
                                        {section.items.map(item => (
                                            <div key={item} className="flex justify-between items-center text-[11px] p-2 bg-background rounded border border-muted-foreground/5 shadow-sm">
                                                <span className="font-medium max-w-[80%]">{item}</span>
                                                <Badge variant={refData.ratings?.[item] === 'Yes' ? 'default' : 'outline'} className="text-[10px]">
                                                    {refData.ratings?.[item] || 'N/A'}
                                                </Badge>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="mt-2 p-3 bg-primary/5 rounded-lg border border-primary/10">
                                        <p className="text-[10px] font-bold text-primary/70 capitalize mb-1 flex items-center gap-1.5">
                                            <FileText className="w-3 h-3" /> Evidence ({section.id})
                                        </p>
                                        <p className="text-xs italic leading-relaxed text-muted-foreground line-clamp-3">
                                            {refData.evidence?.[section.id] || 'No evidence provided'}
                                        </p>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}

                        <Card className="bg-primary/5">
                            <CardContent className="p-4 space-y-4">
                                <div>
                                    <p className="text-[10px] font-bold text-primary uppercase mb-2">Classroom Tools Used</p>
                                    <div className="flex flex-wrap gap-2">
                                        {(refData.tools || []).map((tool: string) => (
                                            <Badge key={tool} variant="outline" className="bg-background text-[10px]">{tool}</Badge>
                                        ))}
                                        {(!refData.tools || refData.tools.length === 0) && <p className="text-xs italic text-muted-foreground">None listed</p>}
                                    </div>
                                </div>
                                <Separator className="bg-primary/10" />
                                <div>
                                    <p className="text-[10px] font-bold text-primary uppercase mb-2">Active Routines</p>
                                    <div className="flex flex-wrap gap-2">
                                        {(refData.routines || []).map((routine: string) => (
                                            <Badge key={routine} variant="outline" className="bg-background text-[10px]">{routine}</Badge>
                                        ))}
                                        {(!refData.routines || refData.routines.length === 0) && <p className="text-xs italic text-muted-foreground">None listed</p>}
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        <div className="grid md:grid-cols-2 gap-4 pt-4">
                            {[
                                { l: 'Strengths', v: refData.reflection?.strengths, icon: <Sparkles className="w-3 h-3" /> },
                                { l: 'Areas for Improvement', v: refData.reflection?.improvement, icon: <TrendingUp className="w-3 h-3" /> },
                                { l: 'Set Goal', v: refData.reflection?.goal, icon: <Target className="w-3 h-3" /> },
                                { l: 'Additional Notes', v: refData.reflection?.anythingElse, icon: <MessageSquare className="w-3 h-3" /> }
                            ].map(item => (
                                <Card key={item.l} className="bg-primary/5 border border-primary/10">
                                    <CardContent className="p-4 space-y-2">
                                        <p className="text-[10px] font-bold text-primary uppercase flex items-center gap-1.5">
                                            {item.icon} {item.l}
                                        </p>
                                        <p className="text-xs leading-relaxed font-medium">
                                            {item.v || 'N/A'}
                                        </p>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    </div>
                );
            }

            if (isCore) {
                return (
                    <div className="space-y-6">
                        {CORE_FRAMEWORK.map(section => (
                            <Card key={section.id} className="shadow-sm bg-muted/20 overflow-hidden">
                                <CardHeader className="bg-primary/5 pb-2">
                                    <CardTitle className="text-xs font-bold capitalize tracking-tight text-primary">
                                        {section.section}
                                    </CardTitle>
                                </CardHeader>
                                <CardContent className="pt-4 space-y-3">
                                    <div className="grid gap-2">
                                        {section.items.map(item => (
                                            <div key={item} className="flex justify-between items-center text-[11px] p-2 bg-background rounded border border-muted-foreground/5 shadow-sm">
                                                <span className="font-medium">{item}</span>
                                                <Badge variant="outline" className="text-[10px] bg-background">
                                                    {refData.ratings?.[item] || 'Not Rated'}
                                                </Badge>
                                            </div>
                                        ))}
                                    </div>
                                    <div className="mt-2 p-3 bg-primary/5 rounded-lg border border-primary/10">
                                        <p className="text-[10px] font-bold text-primary/70 capitalize mb-1 flex items-center gap-1.5">
                                            <FileText className="w-3 h-3" /> Evidence ({section.evidenceId})
                                        </p>
                                        <p className="text-xs italic leading-relaxed text-muted-foreground line-clamp-3">
                                            {refData.evidence?.[section.evidenceId] || 'No evidence provided'}
                                        </p>
                                    </div>
                                </CardContent>
                            </Card>
                        ))}

                        <div className="grid md:grid-cols-2 gap-4 pt-4">
                            {[
                                { l: 'Strengths', v: refData.reflection?.strengths, icon: <Sparkles className="w-3 h-3" /> },
                                { l: 'Areas for Improvement', v: refData.reflection?.improvement, icon: <TrendingUp className="w-3 h-3" /> },
                                { l: 'Set Goal', v: refData.reflection?.goal, icon: <Target className="w-3 h-3" /> },
                                { l: 'Additional Notes', v: refData.reflection?.anythingElse, icon: <MessageSquare className="w-3 h-3" /> }
                            ].map(item => (
                                <Card key={item.l} className="bg-primary/5 border border-primary/10">
                                    <CardContent className="p-4 space-y-2">
                                        <p className="text-[10px] font-bold text-primary uppercase flex items-center gap-1.5">
                                            {item.icon} {item.l}
                                        </p>
                                        <p className="text-xs leading-relaxed font-medium">
                                            {item.v || 'N/A'}
                                        </p>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    </div>
                );
            }

            return (
                <div className="space-y-3">
                    {['Impact', 'Evidence', 'Text'].map(field => (
                        <div key={field} className="p-3 bg-muted/30 rounded-lg">
                            <p className="text-[9px] font-bold text-muted-foreground capitalize mb-1">{field}</p>
                            <p className="text-xs italic">"{refData[field.toLowerCase()] || 'N/A'}"</p>
                        </div>
                    ))}
                </div>
            );
        };

        if (phase === 'GOAL_SETTING') {
            return (
                <ScrollArea className="h-[75vh] pr-4">
                    <div className="space-y-8">
                        {/* Reference Section for HOS */}
                        <div className="space-y-4 bg-muted/20 p-6 rounded-2xl border border-muted-foreground/10">
                            <h3 className="text-sm font-bold flex items-center gap-2 text-primary">
                                <FileText className="w-4 h-4" />
                                Review Teacher's Self-Reflection
                            </h3>
                            <div className="bg-background/50 rounded-xl border border-muted p-4">
                                {renderDetailedReflection()}
                            </div>
                        </div>

                        <Separator className="my-8" />

                        {/* HOS Formal Goal Setting Form */}
                        <div className="space-y-4">
                            <div className="flex items-center gap-2 mb-2">
                                <Badge className="bg-primary hover:bg-primary/90">Step 6: HOS Goal Setting</Badge>
                                <span className="text-xs font-medium text-muted-foreground italic">Fill the formal goal setting details below</span>
                            </div>

                            <div className="bg-background rounded-2xl border border-primary/20 shadow-sm overflow-hidden">
                                <GoalSettingForm
                                    userCampus={user?.campusId}
                                    isLeader={role === 'LEADER'}
                                    teachers={[{ id: goal.teacherId || "temp-id", name: goal.teacher || "Unknown", email: goal.teacherEmail || "", academics: goal.academicType || "CORE" }]}
                                    defaultCoachName={user?.fullName || "Coach"}
                                    initialData={{
                                        educatorName: goal.teacher,
                                        teacherEmail: goal.teacherEmail || "",
                                        coachName: user?.fullName || "Coach",
                                        campus: goal.campus || "HQ",
                                        dateOfGoalSetting: new Date(),
                                        goalForYear: goal.title,
                                        reasonForGoal: goal.description || "",
                                        actionStep: goal.actionStep || "",
                                        pillarTag: goal.category || goal.pillar || "Professional Practice",
                                        goalEndDate: goal.dueDate ? new Date(goal.dueDate) : new Date(new Date().setFullYear(new Date().getFullYear() + 1)),
                                        awareOfProcess: "yes",
                                        awareOfFramework: "yes",
                                        reflectionCompleted: "yes",
                                        evidenceProvided: "yes",
                                        ...safeJsonParse(goal.goalSettingForm)
                                    }}
                                    onSubmit={async (data) => {
                                        try {
                                            setIsSubmitting(true);
                                            const payload = {
                                                settingData: data
                                            };
                                            const res = await api.post(`/goals/${goal.id}/goal-setting`, payload);
                                            if (res.data?.status === 'success') {
                                                toast.success(`HOS Goal Setting completed for ${goal.teacher}.`);
                                                onComplete();
                                            }
                                        } catch (err) {
                                            toast.error("Failed to complete goal setting.");
                                        } finally {
                                            setIsSubmitting(false);
                                        }
                                    }}
                                    onCancel={onClose}
                                />
                            </div>
                        </div>
                    </div>
                </ScrollArea>
            );
        }

        if (phase === 'GOAL_COMPLETION') {
            return (
                <ScrollArea className="h-[60vh] pr-4">
                    <div className="space-y-6">
                        <div className="p-4 rounded-xl bg-emerald-50 border border-emerald-200">
                            <div className="flex items-center gap-2 mb-4">
                                <Badge className="bg-emerald-600">Final Evaluation</Badge>
                                <span className="text-xs font-medium text-emerald-800">Phase 3: Goal Outcome</span>
                            </div>

                            <div className="space-y-4">
                                <div className="p-3 bg-white rounded-lg border border-emerald-100 shadow-sm">
                                    <p className="text-[10px] font-bold text-emerald-700 uppercase mb-1">Expectations Set Previously (Action Step):</p>
                                    <p className="text-xs font-medium">{goal.actionStep || safeJsonParse(goal.goalSettingForm).actionStep || '-'}</p>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="hos-final-feedback" className="text-xs font-bold text-emerald-900">Final Feedback & Narrative</Label>
                                    <Textarea
                                        id="hos-final-feedback"
                                        name="hos-final-feedback"
                                        placeholder="Final assessment of teacher's accomplishments..."
                                        className="min-h-[120px] text-xs bg-white"
                                        value={formData?.text || ''}
                                        onChange={(e) => setFormData((prev: any) => ({ ...(prev || {}), text: e.target.value }))}
                                    />
                                </div>

                                <div className="space-y-2">
                                    <Label className="text-xs font-bold text-emerald-900">Final Goal Status</Label>
                                    <div className="flex flex-wrap gap-2">
                                        {[
                                            { id: 'GOAL_COMPLETED', label: 'Goal Completed', color: 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200 border-emerald-200' },
                                            { id: 'PARTIALLY_MET', label: 'Partially Met', color: 'bg-blue-100 text-blue-700 hover:bg-blue-200 border-blue-200' },
                                            { id: 'NOT_MET', label: 'Not Met', color: 'bg-red-100 text-red-700 hover:bg-red-200 border-red-200' }
                                        ].map(s => (
                                            <Button
                                                key={s.id}
                                                variant="outline"
                                                size="sm"
                                                onClick={() => setFormData((prev: any) => ({ ...(prev || {}), status: s.id }))}
                                                className={cn(
                                                    "text-[10px] h-8 font-bold",
                                                    formData?.status === s.id ? s.color : "opacity-60"
                                                )}
                                            >
                                                {s.label}
                                            </Button>
                                        ))}
                                    </div>
                                </div>
                            </div>
                        </div>

                        <Separator />

                        <div className="space-y-4 opacity-80 scale-[0.98] origin-top">
                            <h3 className="text-sm font-bold flex items-center gap-2">
                                <FileText className="w-4 h-4 text-primary" />
                                Reference: Teacher's Reflection
                            </h3>
                            {renderDetailedReflection()}
                        </div>
                    </div>
                </ScrollArea>
            );
        }

        // VIEW mode
        const refData = safeJsonParse(goal.selfReflectionForm);
        const fwType = getFrameworkType(goal, user);
        const isPE = fwType === 'PE';
        const isPA = fwType === 'PA';
        const isVA = fwType === 'VA';
        const framework = isPA ? PA_FRAMEWORK : isPE ? PE_FRAMEWORK : isVA ? VA_FRAMEWORK : null;
        const isComplex = !!(refData?.ratings) || !!framework;

        return (
            <ScrollArea className="h-[60vh] pr-4">
                <div className="space-y-6">
                    {goal.selfReflectionForm && (
                        <div className="space-y-8">
                            <div className="flex items-center gap-2 text-xs font-bold text-primary capitalize">
                                <Badge>Teacher Reflection</Badge>
                                {isComplex ? "Ekya Danielson Framework" : "Simple Track"}
                            </div>

                            {isComplex && refData.block && framework ? (
                                <div className="space-y-6">
                                    <div className="flex justify-between items-center bg-primary/5 p-4 rounded-xl border border-primary/10">
                                        <div>
                                            <p className="text-[10px] font-bold text-primary capitalize">Category Block</p>
                                            <p className="text-sm font-semibold">{refData.block}</p>
                                        </div>
                                        <div className="text-right">
                                            <p className="text-[10px] font-bold text-primary capitalize">Overall Rating</p>
                                            <Badge className="bg-primary text-white">{refData.overallRating || 'N/A'}/4</Badge>
                                        </div>
                                    </div>

                                    {framework.map(section => (
                                        <Card key={section.id} className="shadow-sm bg-muted/20 overflow-hidden">
                                            <CardHeader className="bg-primary/5 pb-2">
                                                <CardTitle className="text-xs font-bold capitalize tracking-tight text-primary">
                                                    {section.section}
                                                </CardTitle>
                                            </CardHeader>
                                            <CardContent className="pt-4 space-y-4">
                                                <div className="grid gap-2">
                                                    {section.items.map(item => (
                                                        <div key={item} className="flex justify-between items-center text-[11px] p-2 bg-background rounded border border-muted-foreground/5 shadow-sm">
                                                            <span className="font-medium max-w-[80%]">{item}</span>
                                                            <Badge variant={refData.ratings?.[item] === 'Yes' ? 'default' : 'outline'} className="text-[10px]">
                                                                {refData.ratings?.[item] || 'N/A'}
                                                            </Badge>
                                                        </div>
                                                    ))}
                                                </div>
                                                <div className="mt-2 p-3 bg-primary/5 rounded-lg border border-primary/10">
                                                    <p className="text-[10px] font-bold text-primary/70 capitalize mb-1 flex items-center gap-1.5">
                                                        <FileText className="w-3 h-3" /> Evidence ({section.id})
                                                    </p>
                                                    <p className="text-xs italic leading-relaxed text-muted-foreground">
                                                        {refData.evidence?.[section.id] || 'No evidence provided'}
                                                    </p>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}

                                    <Card className="  bg-primary/5">
                                        <CardContent className="p-4 space-y-4">
                                            <div>
                                                <p className="text-[10px] font-bold text-primary capitalize mb-2">Classroom Tools Used</p>
                                                <div className="flex flex-wrap gap-2">
                                                    {(refData.tools || []).map((tool: string) => (
                                                        <Badge key={tool} variant="outline" className="bg-background text-[10px]">{tool}</Badge>
                                                    ))}
                                                    {(!refData.tools || refData.tools.length === 0) && <p className="text-xs italic text-muted-foreground">None listed</p>}
                                                </div>
                                            </div>
                                            <Separator className="bg-primary/10" />
                                            <div>
                                                <p className="text-[10px] font-bold text-primary capitalize mb-2">Active Routines</p>
                                                <div className="flex flex-wrap gap-2">
                                                    {(refData.routines || []).map((routine: string) => (
                                                        <Badge key={routine} variant="outline" className="bg-background text-[10px]">{routine}</Badge>
                                                    ))}
                                                    {(!refData.routines || refData.routines.length === 0) && <p className="text-xs italic text-muted-foreground">None listed</p>}
                                                </div>
                                            </div>
                                        </CardContent>
                                    </Card>

                                    <div className="grid md:grid-cols-2 gap-4 pt-4">
                                        {[
                                            { l: 'Strengths', v: refData.reflection?.strengths, icon: <Sparkles className="w-3 h-3" /> },
                                            { l: 'Areas for Improvement', v: refData.reflection?.improvement, icon: <TrendingUp className="w-3 h-3" /> },
                                            { l: 'Set Goal', v: refData.reflection?.goal, icon: <Target className="w-3 h-3" /> },
                                            { l: 'Additional Notes', v: refData.reflection?.anythingElse, icon: <MessageSquare className="w-3 h-3" /> }
                                        ].map(item => (
                                            <Card key={item.l} className="bg-primary/5 border border-primary/10">
                                                <CardContent className="p-4 space-y-2">
                                                    <p className="text-[10px] font-bold text-primary capitalize flex items-center gap-1.5">
                                                        {item.icon} {item.l}
                                                    </p>
                                                    <p className="text-xs leading-relaxed font-medium">
                                                        {item.v || 'N/A'}
                                                    </p>
                                                </CardContent>
                                            </Card>
                                        ))}
                                    </div>
                                </div>
                            ) : isComplex && !refData.block ? (
                                <div className="space-y-6">
                                    {CORE_FRAMEWORK.map(section => (
                                        <Card key={section.id} className="shadow-sm bg-muted/20 overflow-hidden">
                                            <CardHeader className="bg-primary/5 pb-2">
                                                <CardTitle className="text-xs font-bold capitalize tracking-tight text-primary">
                                                    {section.section}
                                                </CardTitle>
                                            </CardHeader>
                                            <CardContent className="pt-4 space-y-4">
                                                <div className="grid gap-2">
                                                    {section.items.map(item => (
                                                        <div key={item} className="flex justify-between items-center text-[11px] p-2 bg-background rounded border border-muted-foreground/5 shadow-sm">
                                                            <span className="font-medium">{item}</span>
                                                            <Badge variant="outline" className="text-[10px] bg-background">
                                                                {refData.ratings?.[item] || 'Not Rated'}
                                                            </Badge>
                                                        </div>
                                                    ))}
                                                </div>
                                                <div className="mt-2 p-3 bg-primary/5 rounded-lg border border-primary/10">
                                                    <p className="text-[10px] font-bold text-primary/70 capitalize mb-1 flex items-center gap-1.5">
                                                        <FileText className="w-3 h-3" /> Evidence ({section.evidenceId})
                                                    </p>
                                                    <p className="text-xs italic leading-relaxed text-muted-foreground">
                                                        {refData.evidence?.[section.evidenceId] || 'No evidence provided'}
                                                    </p>
                                                </div>
                                            </CardContent>
                                        </Card>
                                    ))}

                                    <div className="grid md:grid-cols-2 gap-4 pt-4">
                                        {[
                                            { l: 'Strengths', v: refData.reflection?.strengths, icon: <Sparkles className="w-3 h-3" /> },
                                            { l: 'Areas for Improvement', v: refData.reflection?.improvement, icon: <TrendingUp className="w-3 h-3" /> },
                                            { l: 'Set Goal', v: refData.reflection?.goal, icon: <Target className="w-3 h-3" /> },
                                            { l: 'Additional Notes', v: refData.reflection?.anythingElse, icon: <MessageSquare className="w-3 h-3" /> }
                                        ].map(item => (
                                            <Card key={item.l} className="bg-primary/5 border border-primary/10">
                                                <CardContent className="p-4 space-y-2">
                                                    <p className="text-[10px] font-bold text-primary capitalize flex items-center gap-1.5">
                                                        {item.icon} {item.l}
                                                    </p>
                                                    <p className="text-xs leading-relaxed font-medium">
                                                        {item.v || 'N/A'}
                                                    </p>
                                                </CardContent>
                                            </Card>
                                        ))}
                                    </div>
                                </div>
                            ) : (
                                <div className="space-y-4">
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-bold text-muted-foreground capitalize">Impact / Contribution</p>
                                        <div className="p-3 bg-muted/30 rounded-lg text-sm italic">
                                            "{refData.impact || 'N/A'}"
                                        </div>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-bold text-muted-foreground capitalize">Evidence / Skills</p>
                                        <div className="p-3 bg-muted/30 rounded-lg text-sm italic">
                                            "{refData.evidence || 'N/A'}"
                                        </div>
                                    </div>
                                    <div className="space-y-1">
                                        <p className="text-[10px] font-bold text-muted-foreground capitalize">Summary</p>
                                        <div className="p-3 bg-muted/30 rounded-lg text-sm italic">
                                            "{refData.text || 'N/A'}"
                                        </div>
                                    </div>
                                </div>
                            )}
                        </div>
                    )}
                    {goal.goalSettingForm && (
                        <div className="space-y-1 pt-4 border-t border-muted">
                            <p className="text-[10px] font-bold text-primary capitalize">HOS Expectations</p>
                            <div className="p-3 bg-info/5 border border-info/10 rounded-lg text-sm font-medium">
                                {safeJsonParse(goal.goalSettingForm).text}
                            </div>
                        </div>
                    )}
                    {goal.goalCompletionForm && (
                        <div className="space-y-1 pt-4 border-t border-muted">
                            <p className="text-[10px] font-bold text-emerald-600 capitalize">Final Evaluation</p>
                            <div className="p-3 bg-emerald-50 border border-emerald-100 rounded-lg text-sm">
                                {safeJsonParse(goal.goalCompletionForm).text}
                            </div>
                        </div>
                    )}
                </div>
            </ScrollArea>
        );
    };

    // ── Wizard step count logic ──────────────────────────────────────────────
    const getStepCount = () => {
        if (phase !== 'SELF_REFLECTION') return 1;
        const fwType = getFrameworkType(goal, user);
        if (fwType === 'CORE') return CORE_FRAMEWORK.length + 1;
        if (fwType === 'PE') return 1 + PE_FRAMEWORK.length + 1 + 1;
        if (fwType === 'PA') return 1 + PA_FRAMEWORK.length + 1 + 1;
        if (fwType === 'VA') return 1 + VA_FRAMEWORK.length + 1 + 1;
        return 1;
    };
    const totalSteps = getStepCount();
    const isWizard = phase === 'SELF_REFLECTION' && totalSteps > 1;
    const isLastStep = formStep === totalSteps - 1;

    return (
        <Dialog open onOpenChange={onClose}>
            <DialogContent
                onInteractOutside={(e) => e.preventDefault()}
                onEscapeKeyDown={(e) => e.preventDefault()}
                className="max-w-4xl h-[90vh] flex flex-col p-0 gap-0 border-2 shadow-2xl overflow-hidden"
            >
                {/* Sticky header */}
                <DialogHeader className="px-6 py-4 border-b bg-background shrink-0">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                            <Badge variant="outline" className="rounded-md font-mono text-[10px] capitalize">
                                {(goal.status || 'IN_PROGRESS').replace(/_/g, ' ')}
                            </Badge>
                            {role === 'ADMIN' && (
                                <Badge variant="destructive" className="rounded-md font-mono text-[10px] capitalize">
                                    Admin Override
                                </Badge>
                            )}
                        </div>
                        {isWizard && (
                            <span className="text-sm font-medium text-muted-foreground tabular-nums">
                                Step {formStep + 1} / {totalSteps}
                            </span>
                        )}
                    </div>
                    <DialogTitle className="text-xl font-bold flex items-center gap-2 mt-1">
                        <Target className="w-5 h-5 text-primary shrink-0" />
                        {phase === 'VIEW' ? 'Goal Details' : phase === 'SELF_REFLECTION' ? 'Self Reflection Form' : phase.replace(/_/g, ' ')}
                    </DialogTitle>
                    <DialogDescription className="flex items-center gap-1.5 flex-wrap">
                        <span className="font-medium text-foreground/80">{goal.teacher?.fullName || goal.teacher}</span>
                        <span>—</span>
                        <span className="italic truncate">{goal.title}</span>
                    </DialogDescription>
                    {role === 'ADMIN' && (
                        <Tabs value={phase} onValueChange={(v: any) => { setPhase(v as any); setFormStep(0); }} className="w-full mt-3">
                            <TabsList className="grid w-full grid-cols-2">
                                <TabsTrigger value="MASTER_FORM">Goal Creation</TabsTrigger>
                                <TabsTrigger value="SELF_REFLECTION">Self Reflection</TabsTrigger>
                            </TabsList>
                        </Tabs>
                    )}
                    {isWizard && (
                        <div className="w-full h-1.5 bg-muted rounded-full mt-3 overflow-hidden">
                            <div
                                className="h-full bg-primary rounded-full transition-all duration-300 ease-in-out"
                                style={{ width: `${((formStep + 1) / totalSteps) * 100}%` }}
                            />
                        </div>
                    )}
                </DialogHeader>

                {/* Scrollable content */}
                <div className="flex-1 overflow-y-auto px-6 py-6">
                    <div className="max-w-3xl mx-auto">
                        {renderContent()}
                    </div>
                </div>

                {/* Footer */}
                {phase !== 'MASTER_FORM' && (
                    <div className="px-6 py-4 border-t bg-muted/10 shrink-0">
                        <div className="flex items-center justify-between max-w-3xl mx-auto">
                            <div className="flex items-center gap-2">
                                {isWizard && formStep > 0 && (
                                    <Button variant="outline" onClick={() => setFormStep(s => Math.max(s - 1, 0))} disabled={isSubmitting}>
                                        ← Back
                                    </Button>
                                )}
                                <Button variant="ghost" onClick={onClose} disabled={isSubmitting}>
                                    {phase === 'VIEW' ? 'Close' : 'Cancel'}
                                </Button>
                            </div>
                            <div>
                                {phase !== 'VIEW' && (
                                    isWizard && !isLastStep ? (
                                        <Button 
                                            onClick={() => {
                                                if (validateStep(formStep)) {
                                                    setFormStep(s => Math.min(s + 1, totalSteps - 1));
                                                }
                                            }} 
                                            className="gap-2"
                                        >
                                            Next →
                                        </Button>
                                    ) : (
                                        <Button
                                            onClick={handleSubmit}
                                            disabled={isSubmitting || (role !== 'ADMIN' && !isWindowOpen(phase))}
                                            className="gap-2"
                                        >
                                            {isSubmitting ? <Clock className="w-4 h-4 animate-spin" /> : <CheckCircle2 className="w-4 h-4" />}
                                            Submit {phase === 'SELF_REFLECTION' ? 'self reflection' : phase.toLowerCase().replace(/_/g, ' ')}
                                        </Button>
                                    )
                                )}
                            </div>
                        </div>
                    </div>
                )}
            </DialogContent>
        </Dialog>
    );
};

import { useState } from "react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import {
    Users, BookOpen, Target, Settings, MessageSquare, Tag,
    ChevronLeft, ChevronRight, Save, Eye, CheckCircle2,
    AlertCircle, Sparkles, ClipboardCheck, Layout, Star,
    Check, ChevronsUpDown, Search, Cloud
} from "lucide-react";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { Command, CommandEmpty, CommandGroup, CommandInput, CommandItem } from "@/components/ui/command";

import { cn } from "@/lib/utils";
import { Observation, DanielsonRatingScale, DanielsonDomain } from "@/types/observation";
import { toast } from "sonner";
import { useEffect } from "react";
import { templateService } from "@/services/templateService";
import { CAMPUS_OPTIONS } from "@/lib/constants";
import api from "@/lib/api";
import { useAutoSave } from "@/hooks/useAutoSave";
import { useAIContext } from "@/contexts/AIContext";
import { ObservationReport } from "@/components/growth/ObservationReport";

interface UnifiedObservationFormProps {
    onSubmit: (observation: Partial<Observation>) => void;
    onAutoSave?: (observation: Partial<Observation>) => Promise<void>;
    onCancel: () => void;
    initialData?: Partial<Observation>;
    teachers?: { id: string; name: string; role?: string; email?: string; academics?: string; campus?: string }[];
    readOnly?: boolean;
}

const RATING_SCALE: DanielsonRatingScale[] = ["Basic", "Developing", "Effective", "Highly Effective", "Not Observed"];

const DOMAINS: { id: string; title: string; subtitle: string; indicators: string[] }[] = [
    {
        id: "3A",
        title: "3A. Planning & Preparation",
        subtitle: "Live the Lesson",
        indicators: [
            "Demonstrating Knowledge of Content and Pedagogy",
            "Demonstrating Knowledge of Students",
            "Demonstrating Knowledge of Resources",
            "Designing a Microplan",
            "Using Student Assessments"
        ]
    },
    {
        id: "3B1",
        title: "3B1. Classroom Practice",
        subtitle: "Care about Culture",
        indicators: [
            "Creating an Environment of Respect and Rapport",
            "Establishing a Culture for Learning",
            "Managing Classroom Procedures",
            "Managing Student Behaviour"
        ]
    },
    {
        id: "3B2",
        title: "3B2. Classroom Practice",
        subtitle: "Instruct to Inspire",
        indicators: [
            "Communicating with Students",
            "Using Questioning and Discussion Techniques and Learning Tools",
            "Engages in Student Learning",
            "Demonstrating Flexibility and Responsiveness"
        ]
    },
    {
        id: "3B3",
        title: "3B3. Classroom Practice",
        subtitle: "Authentic Assessments",
        indicators: [
            "Using Assessments in Instruction"
        ]
    },
    {
        id: "3B4",
        title: "3B4. Classroom Practice",
        subtitle: "Engaging Environment",
        indicators: [
            "Organizing Physical Space",
            "Cleanliness",
            "Use of Boards"
        ]
    },
    {
        id: "3C",
        title: "3C. Professional Practice",
        subtitle: "Professional Ethics",
        indicators: [
            "Reflecting on Teaching",
            "Maintaining Accurate Records",
            "Communicating with Families",
            "Participating in a Professional Community",
            "Growing and Developing Professionally"
        ]
    }
];

const SPECIALIST_DOMAINS = [
    {
        id: "S1",
        title: "S1. Specialized Instruction & Skills",
        subtitle: "Skill-Based Pedagogy",
        indicators: [
            "Skill-Based Pedagogy",
            "Use of Specialist Resources",
            "Safety & Procedure Management"
        ]
    },
    {
        id: "S2",
        title: "S2. Student Engagement & Artistic/Physical Expression",
        subtitle: "Authentic Expression",
        indicators: [
            "Engaging Diverse Talent",
            "Feedback on Skill Development"
        ]
    }
];

const ROUTINES = [
    "Arrival Routine", "Attendance Routine", "Class Cleaning Routines",
    "Collection Routine", "Departure Routine", "Grouping Routine",
    "Lining Up Strategies", "No Routines Observed"
];

const CULTURE_TOOLS = [
    "Affirmations", "Brain Breaks", "Check-In", "Countdown",
    "Positive Framing", "Precise Praise", "Morning Meetings",
    "Social Contract", "Normalise Error", "No Culture Tools Observed"
];

const INSTRUCTIONAL_TOOLS = [
    "Do Now", "Think-Pair-Share", "Exit Ticket", "Cold Call",
    "Choral Call", "Concept Map", "KWL", "See-Think-Wonder",
    "Turn & Talk", "Wait Time", "No Tools Observed"
];

const LA_TOOLS = [
    "Math Journal", "Error Analysis", "Graphic Organisers",
    "Claim-Evidence-Reasoning", "Socratic Seminar", "Silent Debate",
    "No LA Tool Observed"
];

const META_TAGS = [
    "Knowledge of Content and Pedagogy", "Knowledge of Students",
    "Knowledge of Resources", "Designing a Microplan", "Using Student Assessments",
    "Creating an Environment of Respect and Rapport", "Establishing a Culture for Learning",
    "Managing Classroom Procedures", "Managing Student Behaviour",
    "Communicating with Students", "Using Questioning and Discussion Techniques and Learning Tools",
    "Using Assessment in Instruction", "Organizing Physical Space", "Cleanliness", "Use of Boards",
    "Reflecting on Teaching", "Maintaining Accurate Records", "Communicating with Families",
    "Participating in a Professional Community", "Growing and Developing Professionally"
];

const GRADE_OPTIONS = ["Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5", "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"];
const LEARNING_AREA_CATEGORIES = [
    {
        label: "Core Subjects",
        options: ["Mathematics", "Science", "English", "Social Science", "Hindi", "Kannada", "Biology", "Physics", "Chemistry", "Computer Science"]
    },
    {
        label: "Non-Core Subjects",
        options: ["Life Skills", "Physical Education", "Visual Arts", "Music", "Value Education"]
    }
];

const ALL_LEARNING_AREAS = LEARNING_AREA_CATEGORIES.flatMap(cat => cat.options);


export function UnifiedObservationForm({ onSubmit, onAutoSave, onCancel, initialData = {}, teachers, readOnly }: UnifiedObservationFormProps) {
    const [step, setStep] = useState(1);
    const [dynamicDomains, setDynamicDomains] = useState(DOMAINS);
    const [dynamicRoutines, setDynamicRoutines] = useState(ROUTINES);
    const [dynamicCultureTools, setDynamicCultureTools] = useState(CULTURE_TOOLS);
    const [dynamicInstructionalTools, setDynamicInstructionalTools] = useState(INSTRUCTIONAL_TOOLS);
    const [dynamicLaTools, setDynamicLaTools] = useState(LA_TOOLS);
    const [openGrade, setOpenGrade] = useState(false);
    const [openLA, setOpenLA] = useState(false);

    const [teacherGoals, setTeacherGoals] = useState<any[]>([]);
    const [isLoadingGoals, setIsLoadingGoals] = useState(false);
    const { setContextData, clearContextData } = useAIContext();

    // Internal state uses flattened classroom fields for stability
    const [formData, setFormData] = useState<Partial<Observation> & { block: string; grade: string; section: string; focusArea?: string }>(() => {
        const obs = {
            id: Math.random().toString(36).substr(2, 9),
            date: new Date().toISOString().split('T')[0],
            observerRole: initialData.observerRole || "Head of School",
            focusArea: (initialData as any).focusArea || "",
            domains: initialData.domains || DOMAINS.map(d => ({
                domainId: d.id,
                title: d.title,
                indicators: d.indicators.map(i => ({ name: i, rating: "Not Observed" })),
                evidence: ""
            })),
            routines: initialData.routines || [],
            cultureTools: initialData.cultureTools || [],
            instructionalTools: initialData.instructionalTools || [],
            learningAreaTools: initialData.learningAreaTools || [],
            metaTags: initialData.metaTags || [],
            discussionMet: initialData.discussionMet || false,
            strengths: initialData.strengths || "",
            areasOfGrowth: initialData.areasOfGrowth || "",
            feedback: initialData.feedback || "",
            actionSteps: initialData.actionSteps || "",
            nextSteps: initialData.nextSteps || "",
            score: initialData.score || 0,
            status: initialData.status || "Draft",
            hasReflection: initialData.hasReflection || false,
            reflection: initialData.reflection || "",
            // Classroom fields flattened
            campus: initialData.campus || "CMR NPS",
            teacher: initialData.teacher || "",
            teacherId: initialData.teacherId || "",
            teacherEmail: initialData.teacherEmail || "",
            observerName: initialData.observerName || "Rohit",
            block: initialData.classroom?.block || "",
            grade: initialData.classroom?.grade || "",
            section: initialData.classroom?.section || "",
            ...initialData,
            learningArea: initialData.learningArea || initialData.classroom?.learningArea || ""
        };
        return obs as Partial<Observation> & { block: string; grade: string; section: string };
    });

    const { isSaving } = useAutoSave({
        data: formData,
        onSave: async (data) => {
            if (onAutoSave) {
                await onAutoSave(data);
            }
        },
        enabled: !readOnly && !!formData.teacherId,
        localStorageKey: `pdi_obs_draft_${formData.id}`
    });

    useEffect(() => {
        if (formData.teacher) {
            setContextData({
                observationType: "Danielson Framework",
                teacherDetail: formData.teacher,
                currentStep: step,
                currentDomain: step > 1 && step <= dynamicDomains.length + 1 ? dynamicDomains[step - 2]?.title : "Basic Info"
            });
        }
        return () => clearContextData();
    }, [formData.teacher, step, dynamicDomains]);

    useEffect(() => {
        if (initialData && Object.keys(initialData).length > 0) {
            // Only update if it's a different observation or we have no data
            if (!formData.id || (initialData as any).id !== formData.id) {
                setFormData((prev: any) => ({
                    ...prev,
                    ...initialData,
                    block: initialData.classroom?.block || (initialData as any).block || prev.block,
                    grade: initialData.classroom?.grade || (initialData as any).grade || prev.grade,
                    section: initialData.classroom?.section || (initialData as any).section || prev.section,
                    learningArea: initialData.classroom?.learningArea || (initialData as any).learningArea || prev.learningArea
                }));

                if (initialData.domains) {
                    setDynamicDomains(initialData.domains.map(d => ({
                        id: d.domainId,
                        title: d.title,
                        subtitle: "",
                        indicators: d.indicators.map(i => i.name)
                    })));
                }
            }
        }
    }, [initialData, formData.id]);

    useEffect(() => {
        const loadTemplate = async () => {
            try {
                const templates = await templateService.getAllTemplates('OBSERVATION');
                const selectedTeacher = teachers?.find(t => t.id === formData.teacherId);
                const isSpecialist = selectedTeacher?.academics === 'NON_CORE';

                const templateName = isSpecialist ? 'Specialist Observation' : 'Walkthrough Observation';
                const currentTemplate = templates.find(t => t.name === templateName) || templates.find(t => t.isDefault) || templates[0];

                if (currentTemplate && currentTemplate.structure) {
                    const fields = typeof currentTemplate.structure === 'string'
                        ? JSON.parse(currentTemplate.structure)
                        : currentTemplate.structure;

                    const routineField = fields.find((f: any) => f.id === 'routines' || f.label.includes('Routines'));
                    const cultureField = fields.find((f: any) => f.id === 'cultureTools' || f.label.includes('Culture Tools'));
                    const instructionalField = fields.find((f: any) => f.id === 'instructionalTools' || f.label.includes('Instructional Tools'));
                    const laField = fields.find((f: any) => f.id === 'learningAreaTools' || f.label.includes('LA Tool'));

                    if (routineField?.options) setDynamicRoutines(routineField.options);
                    if (cultureField?.options) setDynamicCultureTools(cultureField.options);
                    if (instructionalField?.options) setDynamicInstructionalTools(instructionalField.options);
                    if (laField?.options) setDynamicLaTools(laField.options);
                }
            } catch (error) {
                console.error("Failed to load observation template", error);
            }
        };
        // Only load template if we are not in "Edit" mode (or if teacher changes)
        if (!initialData?.id) {
            loadTemplate();
        }
    }, [formData.teacherId]);



    const updateField = <K extends keyof (Partial<Observation> & { block: string; grade: string; section: string; focusArea: string })>(
        field: K,
        value: (Partial<Observation> & { block: string; grade: string; section: string; focusArea: string })[K]
    ) => {
        setFormData(prev => {
            if (prev[field] === value) return prev;
            return { ...prev, [field]: value };
        });
    };

    const updateMultipleFields = (updates: Partial<typeof formData>) => {
        setFormData(prev => ({ ...prev, ...updates }));
    };

    const handleTeacherSelect = (teacherId: string) => {
        const selectedTeacher = teachers?.find(t => t.id === teacherId);
        if (selectedTeacher) {
            const isSpecialist = selectedTeacher.academics === 'NON_CORE_ACADEMICS';
            const targetDomains = isSpecialist ? SPECIALIST_DOMAINS : DOMAINS;

            setFormData(prev => ({
                ...prev,
                teacherId: selectedTeacher.id,
                teacher: selectedTeacher.name,
                teacherEmail: selectedTeacher.email || `${selectedTeacher.name.toLowerCase().replace(' ', '.')}@ekya.in`,
                domains: targetDomains.map(d => ({
                    domainId: d.id,
                    title: d.title,
                    indicators: d.indicators.map(i => ({ name: i, rating: "Not Observed" })),
                    evidence: ""
                }))
            }));

            // Force reload template options
            setDynamicDomains(targetDomains);

            // Fetch teacher goals for focus area
            fetchTeacherGoals(teacherId);
        }
    };

    const fetchTeacherGoals = async (teacherId: string) => {
        setIsLoadingGoals(true);
        try {
            const res = await api.get(`/goals?teacherId=${teacherId}`);
            if (res.data.status === 'success') {
                setTeacherGoals(res.data.data.goals || []);
            }
        } catch (err) {
            console.error("Failed to fetch teacher goals", err);
        } finally {
            setIsLoadingGoals(false);
        }
    };

    const updateIndicatorRating = (domainId: string, indicatorName: string, rating: DanielsonRatingScale) => {
        setFormData(prev => {
            const domain = prev.domains?.find(d => d.domainId === domainId);
            if (!domain) return prev;

            const indicator = domain.indicators.find(i => i.name === indicatorName);
            if (indicator?.rating === rating) return prev;

            return {
                ...prev,
                domains: prev.domains?.map(d => d.domainId === domainId ? {
                    ...d,
                    indicators: d.indicators.map(i => i.name === indicatorName ? { ...i, rating } : i)
                } : d)
            };
        });
    };

    const updateDomainEvidence = (domainId: string, evidence: string) => {
        setFormData(prev => {
            const domain = prev.domains?.find(d => d.domainId === domainId);
            if (domain?.evidence === evidence) return prev;

            return {
                ...prev,
                domains: prev.domains?.map(d => d.domainId === domainId ? { ...d, evidence } : d)
            };
        });
    };

    const setMultiSelect = (field: keyof Observation, item: string, checked: boolean) => {
        setFormData(prev => {
            const current = Array.isArray(prev[field]) ? (prev[field] as string[]) : [];
            const exists = current.includes(item);

            if (checked && !exists) {
                return { ...prev, [field]: [...current, item] };
            } else if (!checked && exists) {
                return { ...prev, [field]: current.filter(i => i !== item) };
            }
            return prev;
        });
    };

    const validateStep = () => {
        if (step === 1) {
            if (!formData.teacher?.trim() || !formData.teacherEmail?.trim() || !formData.campus) {
                toast.error("Please fill in all required teacher details");
                return false;
            }
            if (!formData.focusArea) {
                toast.error("Please select Focus Area");
                return false;
            }
        }
        if (step === 2) {
            if (!formData.block || !formData.grade || !formData.learningArea) {
                toast.error("Please fill in all required classroom details");
                return false;
            }
        }
        if (step === 3) {
            // Check if all domaines have evidence
            const missingEvidence = formData.domains?.some(d => !d.evidence.trim());
            // Requirement from prompt: "Evidence required for every rated section"
            // Let's interpret "rated section" as a domain where at least one indicator is observed
            // For simplicity, let's require evidence for all domains in Section 3
            if (missingEvidence) {
                toast.error("Please provide evidence for every rated domain");
                return false;
            }
        }
        if (step === 4) {
            // Optional but recommended
        }
        if (step === 5) {
            if (!formData.feedback?.trim() || !formData.actionSteps?.trim()) {
                toast.error("Please complete feedback and action steps");
                return false;
            }
        }
        if (step === 6) {
            if (!formData.metaTags || formData.metaTags.length === 0) {
                toast.error("Please select at least one Meta Tag for improvement");
                return false;
            }
        }
        return true;
    };

    const handleNext = () => {
        if (validateStep()) {
            setStep(prev => prev + 1);
            window.scrollTo(0, 0);
        }
    };

    const handleBack = () => {
        setStep(prev => prev - 1);
        window.scrollTo(0, 0);
    };

    const handleFormSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (validateStep()) {
            let totalPoints = 0;
            let observedCount = 0;
            formData.domains?.forEach(d => {
                d.indicators.forEach(i => {
                    if (i.rating !== "Not Observed") {
                        observedCount++;
                        if (i.rating === "Highly Effective") totalPoints += 4;
                        else if (i.rating === "Effective") totalPoints += 3;
                        else if (i.rating === "Developing") totalPoints += 2;
                        else if (i.rating === "Basic") totalPoints += 1;
                    }
                });
            });
            const scoreValue = observedCount > 0 ? Number((totalPoints / observedCount).toFixed(1)) : 0;

            const finalGrade = formData.section ? `${formData.grade} - ${formData.section}` : formData.grade;

            const finalData: Partial<Observation> = {
                ...formData,
                score: scoreValue,
                overallRating: scoreValue, // Important for the report view
                domain: formData.metaTags?.[0] || "General Instruction",
                classroom: {
                    block: formData.block || "",
                    grade: finalGrade || "",
                    section: formData.section || "",
                    learningArea: formData.learningArea || ""
                }
            };


            onSubmit(finalData);
        }
    };

    if (readOnly) {
        return (
            <div className="pt-4 animate-in fade-in duration-700">
                <ObservationReport
                    data={{
                        ...formData,
                        overallRating: formData.score, // Danielson uses score
                    }}
                    onBack={onCancel}
                />
            </div>
        );
    }

    return (
        <div className="max-w-5xl mx-auto pb-20">
            {/* Progress Header */}
            <div className="sticky top-0 z-20 bg-background/80 backdrop-blur-md pt-4 pb-6 border-b mb-8 px-4">
                <div className="flex justify-between items-center mb-4">
                    <div>
                        <h2 className="text-2xl font-bold text-primary">Observation Form</h2>
                        <p className="text-sm text-muted-foreground flex items-center gap-2">
                            <Layout className="w-4 h-4" /> Step {step} of 6: {
                                step === 1 ? "Teacher Details" :
                                    step === 2 ? "Classroom Details" :
                                        step === 3 ? "Danielson Ratings" :
                                            step === 4 ? "Routines & Tools" :
                                                step === 5 ? "Feedback" : "Meta Tags"
                            }
                        </p>
                    </div>
                    <div className="flex items-center gap-4">
                        <div className={cn(
                            "hidden md:flex items-center gap-2 px-3 py-1.5 rounded-full border transition-all duration-300",
                            isSaving
                                ? "bg-amber-50 text-amber-600 border-amber-100"
                                : "bg-emerald-50 text-emerald-600 border-emerald-100"
                        )}>
                            <Cloud className={cn("w-3.5 h-3.5", isSaving ? "animate-pulse fill-amber-600/20" : "fill-emerald-600/20")} />
                            <span className="text-[10px] font-bold uppercase tracking-wider">
                                {isSaving ? "Saving changes..." : "All changes auto-saved"}
                            </span>
                        </div>
                        <div className="flex gap-1">
                            {[1, 2, 3, 4, 5, 6].map(s => (
                                <div key={s} className={cn("w-8 h-1.5 rounded-full transition-all duration-500", step >= s ? "bg-primary" : "bg-muted")} />
                            ))}
                        </div>
                    </div>
                </div>
            </div>

            <form onSubmit={handleFormSubmit} className="px-4">
                {/* Step 1: Observation & Teacher Details */}
                {step === 1 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <Card className="  shadow-xl">
                            <CardHeader className="bg-primary/5 rounded-t-xl py-6">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center">
                                        <Users className="w-6 h-6 text-primary" />
                                    </div>
                                    <div>
                                        <CardTitle className="text-xl">Observation & Teacher Details</CardTitle>
                                        <CardDescription>Basic information about the session</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-8 space-y-8">
                                <div className="grid md:grid-cols-2 gap-8">
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Name of the Teacher *</Label>
                                        <Select
                                            value={formData.teacherId || ""}
                                            onValueChange={(val) => {
                                                const teacher = teachers?.find(t => t.id === val);
                                                if (teacher) {
                                                    updateField("teacherId", teacher.id);
                                                    updateField("teacher", teacher.name);
                                                    updateField("teacherEmail", teacher.email || "");
                                                    updateField("campus", teacher.campus || "");
                                                }
                                            }}
                                            disabled={readOnly || !!initialData.teacherId}
                                        >
                                            <SelectTrigger className={cn("h-12 text-base rounded-xl border-muted-foreground/20", (readOnly || !!initialData.teacherId) && "bg-slate-50 text-muted-foreground")}>
                                                <SelectValue placeholder="Search or Select Teacher" />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {teachers?.map(t => (
                                                    <SelectItem key={t.id} value={t.id}>{t.name} ({t.role || 'Teacher'})</SelectItem>
                                                ))}
                                                {(!teachers || teachers.length === 0) && (
                                                    <SelectItem value="manual" disabled>No teachers found</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Teacher Email ID *</Label>
                                        <Input
                                            type="email"
                                            placeholder="teacher@ekya.in"
                                            value={formData.teacherEmail || ""}
                                            onChange={(e) => updateField("teacherEmail", e.target.value)}
                                            readOnly={readOnly || !!initialData.teacherEmail}
                                            className={cn("h-12 text-base rounded-xl border-muted-foreground/20", (readOnly || !!initialData.teacherEmail) && "bg-slate-50 text-muted-foreground")}
                                        />
                                    </div>
                                </div>

                                <div className="grid md:grid-cols-2 gap-8">
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Observer's Name *</Label>
                                        <Input
                                            value={formData.observerName || ""}
                                            onChange={(e) => updateField("observerName", e.target.value)}
                                            readOnly={readOnly}
                                            className={cn("h-12 text-base rounded-xl border-muted-foreground/20", readOnly && "bg-slate-50 text-muted-foreground")}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Date of Observation *</Label>
                                        <Input
                                            type="date"
                                            value={formData.date || ""}
                                            onChange={(e) => updateField("date", e.target.value)}
                                            readOnly={readOnly}
                                            className={cn("h-12 text-base rounded-xl border-muted-foreground/20", readOnly && "bg-slate-50 text-muted-foreground")}
                                        />
                                    </div>
                                </div>

                                <div className="grid md:grid-cols-2 gap-8 pt-4">
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Observation Focus Area (Goal Alignment) *</Label>
                                        <Select
                                            value={formData.focusArea || ""}
                                            onValueChange={(val) => updateField("focusArea", val)}
                                        >
                                            <SelectTrigger className="h-12 text-base rounded-xl border-muted-foreground/20">
                                                <SelectValue placeholder={isLoadingGoals ? "Loading goals..." : "Select Focus Area"} />
                                            </SelectTrigger>
                                            <SelectContent>
                                                {teacherGoals.length > 0 ? (
                                                    teacherGoals.map(goal => (
                                                        <SelectItem key={goal.id} value={goal.title}>{goal.title}</SelectItem>
                                                    ))
                                                ) : (
                                                    <SelectItem value="General Observation">General Observation (No active goals)</SelectItem>
                                                )}
                                            </SelectContent>
                                        </Select>
                                        {teacherGoals.length > 0 && <p className="text-[10px] text-muted-foreground italic">Aligned with teacher's professional goals.</p>}
                                    </div>
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Campus *</Label>
                                    <div className="flex flex-wrap gap-2">
                                        {CAMPUS_OPTIONS.map(c => (
                                            <Badge
                                                key={c}
                                                variant={formData.campus === c ? "default" : "outline"}
                                                className={cn(
                                                    "cursor-pointer px-4 py-2 rounded-full text-xs font-semibold transition-all hover:scale-105",
                                                    formData.campus === c ? "bg-primary text-white" : "border-primary/20 text-muted-foreground hover:bg-primary/5",
                                                    readOnly && "cursor-default scale-100 opacity-80"
                                                )}
                                                onClick={() => !readOnly && updateField("campus", c)}
                                            >
                                                {c}
                                            </Badge>
                                        ))}
                                    </div>
                                </div>

                                <div className="space-y-4 pt-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Observer's Role *</Label>
                                    <RadioGroup
                                        value={formData.observerRole}
                                        onValueChange={(val) => updateField("observerRole", val)}
                                        className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4"
                                    >
                                        {["Academic Coordinator", "CCA Coordinator", "Head of School", "ELC Team Member", "PDI Team Member", "Other"].map(r => (
                                            <div key={r} className={cn("flex items-center space-x-2 border p-4 rounded-xl transition-colors", readOnly ? "cursor-default" : "hover:bg-muted/50 cursor-pointer")}>
                                                <RadioGroupItem value={r} id={`role-${r}`} disabled={readOnly} />
                                                <Label htmlFor={`role-${r}`} className={cn("font-medium", !readOnly && "cursor-pointer")}>{r}</Label>
                                            </div>
                                        ))}
                                    </RadioGroup>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}

                {/* Step 2: Classroom Details */}
                {step === 2 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <Card className="  shadow-xl">
                            <CardHeader className="bg-indigo-500/5 rounded-t-xl py-6 border-l-4 border-indigo-500">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-indigo-500/10 flex items-center justify-center">
                                        <BookOpen className="w-6 h-6 text-indigo-500" />
                                    </div>
                                    <div>
                                        <CardTitle className="text-xl">Classroom Details</CardTitle>
                                        <CardDescription>Subject and grade context</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-8 space-y-8">
                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Block *</Label>
                                    <div className="flex flex-wrap gap-4">
                                        {["Early Years", "Primary", "Middle", "Senior", "Specialist"].map(b => (
                                            <div
                                                key={b}
                                                className={cn(
                                                    "flex items-center gap-2 p-4 border-2 rounded-2xl transition-all",
                                                    formData.block === b ? "border-primary bg-primary/5" : "border-muted-foreground/10 hover:border-primary/40 hover:bg-muted/20",
                                                    readOnly ? "cursor-default" : "cursor-pointer"
                                                )}
                                                onClick={() => !readOnly && updateField("block", b)}
                                            >
                                                <div className={cn("w-4 h-4 rounded-full border-2", formData.block === b ? "bg-primary border-primary" : "border-muted-foreground/20")} />
                                                <span className="font-bold">{b}</span>
                                            </div>
                                        ))}
                                    </div>
                                </div>

                                <div className="grid md:grid-cols-2 gap-8">
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Grade *</Label>
                                        <Popover open={openGrade} onOpenChange={setOpenGrade}>
                                            <PopoverTrigger asChild>
                                                <Button
                                                    variant="outline"
                                                    role="combobox"
                                                    aria-expanded={openGrade}
                                                    disabled={readOnly}
                                                    className={cn("w-full h-12 justify-between border-muted-foreground/20 rounded-xl text-base", readOnly && "bg-slate-50 text-muted-foreground")}
                                                >
                                                    {formData.grade
                                                        ? GRADE_OPTIONS.find((g) => g === formData.grade)
                                                        : "Select Grade"}
                                                    <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                                </Button>
                                            </PopoverTrigger>
                                            <PopoverContent className="w-[--radix-popover-trigger-width] p-0">
                                                <Command>
                                                    <CommandInput placeholder="Search grade..." />
                                                    <CommandEmpty>No grade found.</CommandEmpty>
                                                    <CommandGroup>
                                                        {GRADE_OPTIONS.map((g) => (
                                                            <CommandItem
                                                                key={g}
                                                                value={g}
                                                                onSelect={(currentValue) => {
                                                                    updateField("grade", currentValue === formData.grade ? "" : currentValue);
                                                                    setOpenGrade(false);
                                                                }}
                                                            >
                                                                <Check
                                                                    className={cn(
                                                                        "mr-2 h-4 w-4",
                                                                        formData.grade === g ? "opacity-100" : "opacity-0"
                                                                    )}
                                                                />
                                                                {g}
                                                            </CommandItem>
                                                        ))}
                                                    </CommandGroup>
                                                </Command>
                                            </PopoverContent>
                                        </Popover>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Section</Label>
                                        <Input
                                            placeholder="e.g., A, B, Emerald"
                                            value={formData.section}
                                            onChange={(e) => updateField("section", e.target.value)}
                                            readOnly={readOnly}
                                            className={cn("h-12 text-base rounded-xl border-muted-foreground/20", readOnly && "bg-slate-50 text-muted-foreground")}
                                        />
                                    </div>
                                </div>

                                <div className="space-y-2">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Learning Area *</Label>
                                    <Popover open={openLA} onOpenChange={setOpenLA}>
                                        <PopoverTrigger asChild>
                                            <Button
                                                variant="outline"
                                                role="combobox"
                                                aria-expanded={openLA}
                                                disabled={readOnly}
                                                className={cn("w-full h-12 justify-between border-muted-foreground/20 rounded-xl text-base", readOnly && "bg-slate-50 text-muted-foreground")}
                                            >
                                                {formData.learningArea
                                                    ? ALL_LEARNING_AREAS.find((la) => la === formData.learningArea)
                                                    : "Search or Select Learning Area"}
                                                <ChevronsUpDown className="ml-2 h-4 w-4 shrink-0 opacity-50" />
                                            </Button>
                                        </PopoverTrigger>
                                        <PopoverContent className="w-[--radix-popover-trigger-width] p-0">
                                            <Command>
                                                <CommandInput placeholder="Search learning area..." />
                                                <CommandEmpty>No learning area found.</CommandEmpty>
                                                {LEARNING_AREA_CATEGORIES.map((category) => (
                                                    <CommandGroup key={category.label} heading={category.label}>
                                                        {category.options.map((la) => (
                                                            <CommandItem
                                                                key={la}
                                                                value={la}
                                                                onSelect={(currentValue) => {
                                                                    // Command component value is lowercase
                                                                    const matchedArea = ALL_LEARNING_AREAS.find(
                                                                        opt => opt.toLowerCase() === currentValue.toLowerCase()
                                                                    ) || currentValue;

                                                                    updateField("learningArea", matchedArea === formData.learningArea ? "" : matchedArea);
                                                                    setOpenLA(false);
                                                                }}
                                                            >
                                                                <Check
                                                                    className={cn(
                                                                        "mr-2 h-4 w-4",
                                                                        formData.learningArea === la ? "opacity-100" : "opacity-0"
                                                                    )}
                                                                />
                                                                {la}
                                                            </CommandItem>
                                                        ))}
                                                    </CommandGroup>
                                                ))}
                                            </Command>
                                        </PopoverContent>
                                    </Popover>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}

                {/* Step 3: Danielson Ratings */}
                {step === 3 && (
                    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        {dynamicDomains.map((domain, idx) => (
                            <DomainSection
                                key={domain.id}
                                domain={domain}
                                idx={idx}
                                readOnly={readOnly}
                                updateIndicatorRating={updateIndicatorRating}
                                updateDomainEvidence={updateDomainEvidence}
                                formData={formData}
                            />
                        ))}
                    </div>
                )}

                {/* Step 4: Routines, Tools & Strategies */}
                {step === 4 && (
                    <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <div className="p-6 bg-primary/5 rounded-2xl border border-primary/10 mb-8">
                            <h2 className="text-2xl font-bold flex items-center gap-3">
                                <Settings className="w-8 h-8 text-primary" />
                                Routines, Tools & Strategies
                            </h2>
                            <p className="text-muted-foreground mt-2">Select all that were observed during the session.</p>
                        </div>

                        <div className="grid md:grid-cols-2 gap-10">
                            {/* Classroom Routines */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3 border-b-2 border-primary/10 pb-2">
                                    <ClipboardCheck className="w-5 h-5 text-primary" />
                                    <h3 className="font-bold text-lg">Classroom Routines</h3>
                                </div>
                                <div className="grid grid-cols-1 gap-3">
                                    {dynamicRoutines.map((routine) => {
                                        const id = `routine-${routine.replace(/\s+/g, '-').toLowerCase()}`;
                                        const isChecked = formData.routines?.includes(routine);
                                        return (
                                            <div
                                                key={routine}
                                                className={cn(
                                                    "flex items-center space-x-3 p-3 rounded-xl border transition-all select-none",
                                                    isChecked ? "bg-primary/5 border-primary shadow-sm" : "hover:bg-muted/50 border-muted-foreground/10",
                                                    readOnly && "cursor-default"
                                                )}
                                            >
                                                <Checkbox
                                                    id={id}
                                                    checked={isChecked}
                                                    onCheckedChange={(checked) => !readOnly && setMultiSelect("routines", routine, !!checked)}
                                                    disabled={readOnly}
                                                />
                                                <Label htmlFor={id} className={cn("font-medium text-sm flex-1", !readOnly && "cursor-pointer")}>{routine}</Label>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* Culture Tools */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3 border-b-2 border-indigo-500/10 pb-2">
                                    <Star className="w-5 h-5 text-indigo-500" />
                                    <h3 className="font-bold text-lg">Culture Tools Observed</h3>
                                </div>
                                <div className="grid grid-cols-1 gap-3">
                                    {dynamicCultureTools.map((tool) => {
                                        const id = `culture-${tool.replace(/\s+/g, '-').toLowerCase()}`;
                                        const isChecked = formData.cultureTools?.includes(tool);
                                        return (
                                            <div
                                                key={tool}
                                                className={cn(
                                                    "flex items-center space-x-3 p-3 rounded-xl border transition-all select-none",
                                                    isChecked ? "bg-indigo-500/5 border-indigo-500 shadow-sm" : "hover:bg-muted/50 border-muted-foreground/10",
                                                    readOnly && "cursor-default"
                                                )}
                                            >
                                                <Checkbox
                                                    id={id}
                                                    checked={isChecked}
                                                    onCheckedChange={(checked) => !readOnly && setMultiSelect("cultureTools", tool, !!checked)}
                                                    disabled={readOnly}
                                                />
                                                <Label htmlFor={id} className={cn("font-medium text-sm flex-1", !readOnly && "cursor-pointer")}>{tool}</Label>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* Instructional Tools */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3 border-b-2 border-emerald-500/10 pb-2">
                                    <Target className="w-5 h-5 text-emerald-500" />
                                    <h3 className="font-bold text-lg">Instructional Tools Observed</h3>
                                </div>
                                <div className="grid grid-cols-1 gap-3">
                                    {dynamicInstructionalTools.map((tool) => {
                                        const id = `instructional-${tool.replace(/\s+/g, '-').toLowerCase()}`;
                                        const isChecked = formData.instructionalTools?.includes(tool);
                                        return (
                                            <div
                                                key={tool}
                                                className={cn(
                                                    "flex items-center space-x-3 p-3 rounded-xl border transition-all select-none",
                                                    isChecked ? "bg-emerald-500/5 border-emerald-500 shadow-sm" : "hover:bg-muted/50 border-muted-foreground/10",
                                                    readOnly && "cursor-default"
                                                )}
                                            >
                                                <Checkbox
                                                    id={id}
                                                    checked={isChecked}
                                                    onCheckedChange={(checked) => !readOnly && setMultiSelect("instructionalTools", tool, !!checked)}
                                                    disabled={readOnly}
                                                />
                                                <Label htmlFor={id} className={cn("font-medium text-sm flex-1", !readOnly && "cursor-pointer")}>{tool}</Label>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>

                            {/* Learning Area Tools */}
                            <div className="space-y-6">
                                <div className="flex items-center gap-3 border-b-2 border-orange-500/10 pb-2">
                                    <BookOpen className="w-5 h-5 text-orange-500" />
                                    <h3 className="font-bold text-lg">LA Tools Observed</h3>
                                </div>
                                <div className="grid grid-cols-1 gap-3">
                                    {dynamicLaTools.map((tool) => {
                                        const id = `la-tool-${tool.replace(/\s+/g, '-').toLowerCase()}`;
                                        const isChecked = formData.learningAreaTools?.includes(tool);
                                        return (
                                            <div
                                                key={tool}
                                                className={cn(
                                                    "flex items-center space-x-3 p-3 rounded-xl border transition-all select-none",
                                                    isChecked ? "bg-orange-500/5 border-orange-500 shadow-sm" : "hover:bg-muted/50 border-muted-foreground/10",
                                                    readOnly && "cursor-default"
                                                )}
                                            >
                                                <Checkbox
                                                    id={id}
                                                    checked={isChecked}
                                                    onCheckedChange={(checked) => !readOnly && setMultiSelect("learningAreaTools", tool, !!checked)}
                                                    disabled={readOnly}
                                                />
                                                <Label htmlFor={id} className={cn("font-medium text-sm flex-1", !readOnly && "cursor-pointer")}>{tool}</Label>
                                            </div>
                                        );
                                    })}
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Step 5: Feedback & Action Steps */}
                {step === 5 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <Card className="  shadow-xl">
                            <CardHeader className="bg-primary/5 rounded-t-xl py-6">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary">
                                        <MessageSquare className="w-6 h-6" />
                                    </div>
                                    <div>
                                        <CardTitle className="text-xl">Feedback & Action Steps</CardTitle>
                                        <CardDescription>Synthesizing the observation into growth points</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-8 space-y-10">
                                <div className="space-y-6">
                                    <Label className="text-base font-bold">Have you met and discussed the observation with the teacher? *</Label>
                                    <RadioGroup
                                        value={formData.discussionMet ? "Yes" : "No"}
                                        onValueChange={(val) => !readOnly && updateField("discussionMet", val === "Yes")}
                                        className="flex gap-8"
                                    >
                                        <div className={cn("flex items-center space-x-2 border p-4 rounded-xl transition-colors", readOnly ? "cursor-default" : "hover:bg-muted/50 cursor-pointer")}>
                                            <RadioGroupItem value="Yes" id="disc-yes" disabled={readOnly} />
                                            <Label htmlFor="disc-yes" className={cn("font-bold text-lg", !readOnly && "cursor-pointer")}>Yes</Label>
                                        </div>
                                        <div className={cn("flex items-center space-x-2 border p-4 rounded-xl transition-colors", readOnly ? "cursor-default" : "hover:bg-muted/50 cursor-pointer")}>
                                            <RadioGroupItem value="No" id="disc-no" disabled={readOnly} />
                                            <Label htmlFor="disc-no" className={cn("font-bold text-lg", !readOnly && "cursor-pointer")}>No</Label>
                                        </div>
                                    </RadioGroup>
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground flex items-center gap-2">
                                        <Star className="w-4 h-4 text-primary" /> Teacher Strengths
                                    </Label>
                                    <Textarea
                                        placeholder="What went exceptionally well?"
                                        className="min-h-[120px] p-4 text-base rounded-2xl border-muted-foreground/10"
                                        value={formData.strengths}
                                        onChange={(e) => updateField("strengths", e.target.value)}
                                        readOnly={readOnly}
                                    />
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground flex items-center gap-2">
                                        <Target className="w-4 h-4 text-primary" /> Areas of Growth
                                    </Label>
                                    <Textarea
                                        placeholder="What are the specific areas for improvement?"
                                        className="min-h-[120px] p-4 text-base rounded-2xl border-muted-foreground/10"
                                        value={formData.areasOfGrowth}
                                        onChange={(e) => updateField("areasOfGrowth", e.target.value)}
                                        readOnly={readOnly}
                                    />
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground flex items-center gap-2">
                                        <MessageSquare className="w-4 h-4 text-primary" /> Observer's Feedback
                                    </Label>
                                    <Textarea
                                        placeholder="Consolidated feedback for the teacher..."
                                        className="min-h-[120px] p-4 text-base rounded-2xl border-muted-foreground/10"
                                        value={formData.feedback}
                                        onChange={(e) => updateField("feedback", e.target.value)}
                                        readOnly={readOnly}
                                    />
                                </div>

                                <div className="space-y-4">
                                    <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground flex items-center gap-2">
                                        <Settings className="w-4 h-4 text-primary" /> Action Steps
                                    </Label>
                                    <Textarea
                                        placeholder="Agreed upon immediate action items..."
                                        className="min-h-[120px] p-4 text-base rounded-2xl border-muted-foreground/10"
                                        value={formData.actionSteps}
                                        onChange={(e) => updateField("actionSteps", e.target.value)}
                                        readOnly={readOnly}
                                    />
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}

                {/* Step 6: Meta Tags */}
                {step === 6 && (
                    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        <Card className="  shadow-xl bg-background overflow-hidden">
                            <CardHeader className="bg-primary/5 border-b py-8">
                                <div className="flex items-center gap-4">
                                    <div className="w-12 h-12 rounded-2xl bg-primary/10 flex items-center justify-center text-primary">
                                        <Tag className="w-6 h-6" />
                                    </div>
                                    <div>
                                        <CardTitle className="text-2xl font-bold">Meta Tags – Areas for Improvement</CardTitle>
                                        <CardDescription className="text-base">Select the key tags that best reflect the feedback and action steps.</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-10 space-y-10">
                                <div className="p-6 bg-emerald-50 rounded-2xl border border-emerald-200 flex items-start gap-4 mb-4 shadow-sm">
                                    <Sparkles className="w-6 h-6 text-emerald-600 mt-1" />
                                    <div>
                                        <p className="font-bold text-emerald-800">Insight Engine Integration</p>
                                        <p className="text-sm text-emerald-700/80">These tags power the AI analytics engine to identify recurring growth areas across teams and campuses.</p>
                                    </div>
                                </div>

                                <MultiSelectSection title="Meta Tags for Feedback & Coaching" items={META_TAGS} field="metaTags" formData={formData} setMultiSelect={setMultiSelect} readOnly={readOnly} />

                                <div className="pt-10 border-t flex flex-col items-center justify-center text-center space-y-6">
                                    <div className="w-20 h-20 rounded-full bg-success/10 flex items-center justify-center">
                                        <CheckCircle2 className="w-10 h-10 text-success" />
                                    </div>
                                    <div>
                                        <h3 className="text-2xl font-bold">Ready to Submit</h3>
                                        <p className="text-muted-foreground max-w-md">Every single detail matters for the educator's growth journey. Thank you for your thorough documentation.</p>
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </div>
                )}

                {/* Sticky Bottom Actions */}
                <div className="fixed bottom-0 left-0 right-0 bg-background/80 backdrop-blur-lg border-t py-4 z-30 px-6">
                    <div className="max-w-5xl mx-auto flex justify-between items-center">
                        <Button
                            type="button"
                            variant="ghost"
                            onClick={onCancel}
                            className="gap-2 font-bold px-6 border border-muted-foreground/20"
                        >
                            <ChevronLeft className="w-4 h-4" /> {readOnly ? "Close" : "Cancel"}
                        </Button>

                        <div className="flex gap-4">
                            {step > 1 && (
                                <Button
                                    type="button"
                                    variant="outline"
                                    onClick={handleBack}
                                    className="gap-2 font-bold px-6"
                                >
                                    <ChevronLeft className="w-4 h-4" /> Back
                                </Button>
                            )}

                            {step < 6 ? (
                                <Button
                                    type="button"
                                    onClick={handleNext}
                                    className="gap-2 font-bold px-8 bg-primary hover:bg-primary/90 text-white"
                                >
                                    Next <ChevronRight className="w-4 h-4" />
                                </Button>
                            ) : readOnly ? (
                                <Button
                                    type="button"
                                    onClick={onCancel}
                                    className="gap-2 font-bold px-10 bg-primary hover:bg-primary/90 text-white shadow-lg shadow-primary/20"
                                >
                                    <CheckCircle2 className="w-4 h-4" /> Back to Growth
                                </Button>
                            ) : (
                                <Button
                                    type="submit"
                                    className="gap-2 font-bold px-10 bg-primary hover:bg-primary/90 text-white shadow-lg shadow-primary/20"
                                >
                                    <Save className="w-4 h-4" /> {initialData.id ? "Update Observation" : "Submit Observation"}
                                </Button>
                            )}
                        </div>
                    </div>
                </div>
            </form>
        </div>
    );
}

const MultiSelectSection = ({ title, items, field, formData, setMultiSelect, readOnly }: any) => (
    <Card className="shadow-xl">
        <CardHeader className="bg-primary/5 py-4">
            <CardTitle className="text-lg">{title}</CardTitle>
        </CardHeader>
        <CardContent className="p-6">
            <div className="flex flex-wrap gap-3">
                {items.map((item: string) => {
                    const id = `meta-${item.replace(/\s+/g, '-').toLowerCase()}`;
                    const isChecked = formData[field]?.includes(item);
                    return (
                        <div
                            key={item}
                            className={cn(
                                "flex items-center gap-3 p-3 rounded-xl border-2 transition-all group",
                                isChecked
                                    ? "border-primary bg-primary/5 text-primary"
                                    : "border-muted-foreground/10 hover:border-primary/40",
                                readOnly ? "cursor-default" : "cursor-pointer"
                            )}
                        >
                            <Checkbox
                                id={id}
                                checked={isChecked}
                                onCheckedChange={(checked) => !readOnly && setMultiSelect(field, item, !!checked)}
                                disabled={readOnly}
                                className={cn(isChecked ? "border-primary bg-primary" : "border-muted-foreground/30")}
                            />
                            <Label htmlFor={id} className={cn("font-semibold text-sm cursor-pointer")}>{item}</Label>
                        </div>
                    );
                })}
            </div>
        </CardContent>
    </Card>
);

const DomainSection = ({ domain, idx, readOnly, updateIndicatorRating, updateDomainEvidence, formData }: any) => (
    <Card key={domain.id} className="shadow-xl overflow-hidden">
        <CardHeader className="bg-primary/5 py-6">
            <div className="flex justify-between items-start">
                <div className="flex items-center gap-4">
                    <div className="w-10 h-10 rounded-xl bg-primary/10 flex items-center justify-center font-bold text-primary">
                        {idx + 1}
                    </div>
                    <div>
                        <CardTitle className="text-xl">{domain.title}</CardTitle>
                        <CardDescription className="font-bold text-primary capitalize text-xs tracking-widest">{domain.subtitle}</CardDescription>
                    </div>
                </div>
            </div>
        </CardHeader>
        <CardContent className="p-8 space-y-10">
            {domain.indicators.map((indicator: string, iIdx: number) => (
                <div key={indicator} className="space-y-4">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                        <Label className="text-base font-bold flex-1 leading-tight">
                            <span className="text-primary/40 mr-2">3.{domain.id}.{iIdx + 1}</span>
                            {indicator}
                        </Label>
                        <div className="flex flex-wrap gap-2">
                            {RATING_SCALE.map(rating => (
                                <button
                                    key={rating}
                                    type="button"
                                    disabled={readOnly}
                                    onClick={() => updateIndicatorRating(domain.id, indicator, rating)}
                                    className={cn(
                                        "px-3 py-1.5 rounded-lg text-xs font-bold transition-all border",
                                        formData.domains?.find((d: any) => d.domainId === domain.id)?.indicators.find((i: any) => i.name === indicator)?.rating === rating
                                            ? "bg-primary text-white border-primary shadow-lg shadow-primary/20 scale-105"
                                            : "bg-background text-muted-foreground border-muted-foreground/10 hover:border-primary/40 hover:bg-primary/5",
                                        readOnly && "cursor-default scale-100 opacity-80"
                                    )}
                                >
                                    {rating}
                                </button>
                            ))}
                        </div>
                    </div>
                    <div className="h-px bg-muted-foreground/5" />
                </div>
            ))}

            <div className="space-y-3 pt-4">
                <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Share evidences for your rating ({domain.id}) *</Label>
                <Textarea
                    placeholder="Provide specific evidence observed mapping to the indicators above..."
                    className="min-h-[100px] bg-muted/20 border-muted-foreground/10 p-4 focus:ring-4 focus:ring-primary/10 rounded-xl transition-all"
                    value={formData.domains?.find((d: any) => d.domainId === domain.id)?.evidence || ""}
                    onChange={(e) => updateDomainEvidence(domain.id, e.target.value)}
                    readOnly={readOnly}
                />
            </div>
        </CardContent>
    </Card>
);

import React, { useState, useEffect } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from "@/components/ui/dialog";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Badge } from "@/components/ui/badge";
import { Checkbox } from "@/components/ui/checkbox";
import { ScrollArea } from "@/components/ui/scroll-area";
import { assessmentService } from "@/services/assessmentService";
import { userService, User } from "@/services/userService";
import { CAMPUS_OPTIONS } from "@/lib/constants";
import { toast } from "sonner";
import { X, Users, School, Shield, User as UserIcon, Loader2 } from 'lucide-react';

interface AssessmentAssignmentModalProps {
    assessmentId: string;
    assessmentTitle: string;
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
}

type AssignType = 'ROLE' | 'CAMPUS' | 'USER';

const CAMPUSES = CAMPUS_OPTIONS;

const ROLES = [
    { label: "Teachers", value: "TEACHER" },
    { label: "School Leaders", value: "SCHOOL_LEADER" },
    { label: "Admins", value: "ADMIN" }
];

export const AssessmentAssignmentModal: React.FC<AssessmentAssignmentModalProps> = ({
    assessmentId,
    assessmentTitle,
    isOpen,
    onClose,
    onSuccess
}) => {
    const [assignTo, setAssignTo] = useState<AssignType>('ROLE');
    const [selectedTargets, setSelectedTargets] = useState<string[]>([]);
    const [users, setUsers] = useState<User[]>([]);
    const [isLoadingUsers, setIsLoadingUsers] = useState(false);
    const [isSubmitting, setIsSubmitting] = useState(false);

    useEffect(() => {
        if (isOpen && assignTo === 'USER' && users.length === 0) {
            loadUsers();
        }
    }, [isOpen, assignTo]);

    const loadUsers = async () => {
        setIsLoadingUsers(true);
        try {
            const data = await userService.getAllUsers();
            setUsers(data);
        } catch (error) {
            toast.error("Failed to load users");
        } finally {
            setIsLoadingUsers(false);
        }
    };

    const toggleTarget = (targetId: string) => {
        setSelectedTargets(prev =>
            prev.includes(targetId)
                ? prev.filter(id => id !== targetId)
                : [...prev, targetId]
        );
    };

    const handleAssign = async () => {
        if (selectedTargets.length === 0) {
            return toast.error("Please select at least one target");
        }

        setIsSubmitting(true);
        try {
            await assessmentService.assignAssessment(assessmentId, selectedTargets, assignTo);
            toast.success(`Assessment assigned successfully!`);
            onSuccess();
        } catch (error) {
            toast.error("Failed to assign assessment");
        } finally {
            setIsSubmitting(false);
        }
    };

    return (
        <Dialog open={isOpen} onOpenChange={onClose}>
            <DialogContent className="sm:max-w-[500px] rounded-3xl">
                <DialogHeader>
                    <DialogTitle className="text-2xl font-bold flex items-center gap-2">
                        <Users className="w-6 h-6 text-primary" />
                        Assign Assessment
                    </DialogTitle>
                    <DialogDescription>
                        Assign <span className="font-semibold text-zinc-900">"{assessmentTitle}"</span> to specific groups or users.
                    </DialogDescription>
                </DialogHeader>

                <div className="space-y-6 py-4">
                    <div className="space-y-2">
                        <Label>Assign To Type</Label>
                        <Select value={assignTo} onValueChange={(val: AssignType) => {
                            setAssignTo(val);
                            setSelectedTargets([]);
                        }}>
                            <SelectTrigger className="rounded-xl h-11">
                                <SelectValue />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="ROLE">Specific Roles</SelectItem>
                                <SelectItem value="CAMPUS">Specific Campuses</SelectItem>
                                <SelectItem value="USER">Specific Individual Users</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    <div className="space-y-3">
                        <Label className="flex justify-between items-center">
                            <span>Select Targets</span>
                            <span className="text-xs text-zinc-500 font-normal">{selectedTargets.length} selected</span>
                        </Label>

                        <ScrollArea className="h-[250px] w-full rounded-xl border p-4 bg-zinc-50/50">
                            {assignTo === 'ROLE' && (
                                <div className="space-y-3">
                                    {ROLES.map(role => (
                                        <div key={role.value} className="flex items-center space-x-3 p-2 hover:bg-white rounded-lg transition-colors cursor-pointer" onClick={() => toggleTarget(role.value)}>
                                            <Checkbox id={`role-${role.value}`} checked={selectedTargets.includes(role.value)} />
                                            <label className="text-sm font-medium leading-none cursor-pointer flex items-center gap-2">
                                                <Shield className="w-4 h-4 text-zinc-400" />
                                                {role.label}
                                            </label>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {assignTo === 'CAMPUS' && (
                                <div className="space-y-3">
                                    {CAMPUSES.map(campus => (
                                        <div key={campus} className="flex items-center space-x-3 p-2 hover:bg-white rounded-lg transition-colors cursor-pointer" onClick={() => toggleTarget(campus)}>
                                            <Checkbox id={`campus-${campus}`} checked={selectedTargets.includes(campus)} />
                                            <label className="text-sm font-medium leading-none cursor-pointer flex items-center gap-2">
                                                <School className="w-4 h-4 text-zinc-400" />
                                                {campus}
                                            </label>
                                        </div>
                                    ))}
                                </div>
                            )}

                            {assignTo === 'USER' && (
                                <div className="space-y-3">
                                    {isLoadingUsers ? (
                                        <div className="flex items-center justify-center h-full py-10">
                                            <Loader2 className="w-6 h-6 animate-spin text-primary" />
                                        </div>
                                    ) : (
                                        users.map(user => (
                                            <div key={user.id} className="flex items-center space-x-3 p-2 hover:bg-white rounded-lg transition-colors cursor-pointer" onClick={() => toggleTarget(user.id)}>
                                                <Checkbox id={`user-${user.id}`} checked={selectedTargets.includes(user.id)} />
                                                <div className="flex flex-col">
                                                    <label className="text-sm font-medium leading-none cursor-pointer flex items-center gap-2">
                                                        <UserIcon className="w-4 h-4 text-zinc-400" />
                                                        {user.fullName}
                                                    </label>
                                                    <span className="text-[10px] text-zinc-500 ml-6">{user.email} • {user.role}</span>
                                                </div>
                                            </div>
                                        ))
                                    )}
                                </div>
                            )}
                        </ScrollArea>
                    </div>

                    {selectedTargets.length > 0 && (
                        <div className="flex flex-wrap gap-2">
                            {selectedTargets.map(target => (
                                <Badge key={target} variant="secondary" className="gap-1 px-2 py-1 rounded-lg bg-primary/10 text-primary border-none">
                                    {assignTo === 'USER' ? users.find(u => u.id === target)?.fullName : target}
                                    <X className="w-3 h-3 cursor-pointer" onClick={() => toggleTarget(target)} />
                                </Badge>
                            ))}
                        </div>
                    )}
                </div>

                <DialogFooter className="gap-2 sm:gap-0">
                    <Button variant="ghost" onClick={onClose} disabled={isSubmitting}>Cancel</Button>
                    <Button onClick={handleAssign} disabled={isSubmitting || selectedTargets.length === 0} className="px-8 rounded-xl">
                        {isSubmitting && <Loader2 className="w-4 h-4 mr-2 animate-spin" />}
                        Confirm Assignment
                    </Button>
                </DialogFooter>
            </DialogContent>
        </Dialog>
    );
};

import React, { useEffect, useState, useRef } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardFooter } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Progress } from "@/components/ui/progress";
import { assessmentService, Assessment, AssessmentAttempt } from "@/services/assessmentService";
import { useParams, useNavigate } from 'react-router-dom';
import { Timer, Send, ChevronLeft, ChevronRight, AlertTriangle } from 'lucide-react';
import { toast } from "sonner";

export const AssessmentAttemptView: React.FC = () => {
    const { assessmentId } = useParams<{ assessmentId: string }>();
    const navigate = useNavigate();

    const [assessment, setAssessment] = useState<Assessment | null>(null);
    const [attempt, setAttempt] = useState<AssessmentAttempt | null>(null);
    const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0);
    const [answers, setAnswers] = useState<Record<string, any>>({});
    const [loading, setLoading] = useState(true);
    const [timeLeft, setTimeLeft] = useState<number | null>(null);
    const timerRef = useRef<NodeJS.Timeout | null>(null);

    useEffect(() => {
        if (assessmentId) startAssessment(assessmentId);
        return () => {
            if (timerRef.current) clearInterval(timerRef.current);
        };
    }, [assessmentId]);

    const startAssessment = async (id: string) => {
        try {
            const newAttempt = await assessmentService.startAttempt(id);
            setAttempt(newAttempt);

            // Get assessment details (could be part of attempt response or separate call)
            // For now, assuming we need to fetch assignments to find this one or directly fetch by ID
            const data = await assessmentService.getMyAssignments();
            const found = data.assignments.find((a: any) => a.assessment.id === id)?.assessment;
            setAssessment(found);

            if (found.isTimed && found.timeLimitMinutes) {
                setTimeLeft(found.timeLimitMinutes * 60);
            }

            if (newAttempt.answers) {
                setAnswers(JSON.parse(newAttempt.answers));
            }
        } catch (error: any) {
            toast.error(error.response?.data?.message || "Failed to start assessment");
            navigate('/teacher/courses/assessments');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (timeLeft !== null && timeLeft > 0) {
            timerRef.current = setInterval(() => {
                setTimeLeft(prev => (prev !== null ? prev - 1 : null));
            }, 1000);
        } else if (timeLeft === 0) {
            handleSubmit();
        }
        return () => { if (timerRef.current) clearInterval(timerRef.current); };
    }, [timeLeft]);

    const handleAnswerChange = (questionId: string, value: any) => {
        setAnswers(prev => {
            const newAnswers = { ...prev, [questionId]: value };
            // Auto-save progress every answer
            if (attempt) assessmentService.saveProgress(attempt.id, newAnswers);
            return newAnswers;
        });
    };

    const handleSubmit = async () => {
        if (!attempt) return;
        try {
            await assessmentService.submitAttempt(attempt.id, answers);
            toast.success("Assessment submitted successfully!");
            navigate('/teacher/courses/assessments');
        } catch (error) {
            toast.error("Failed to submit assessment");
        }
    };

    const formatTime = (seconds: number) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    if (loading || !assessment || !attempt) return <div className="p-8 text-center text-zinc-500">Initializing environment...</div>;

    const questions = assessment.questions || [];
    const currentQuestion = questions[currentQuestionIndex];
    const progress = ((currentQuestionIndex + 1) / questions.length) * 100;

    return (
        <div className="max-w-4xl mx-auto space-y-8 p-4 md:p-0">
            {/* Header / Timer */}
            <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-zinc-900 text-white p-6 rounded-2xl shadow-xl">
                <div>
                    <h2 className="text-2xl font-bold">{assessment.title}</h2>
                    <p className="text-zinc-400 text-sm">Question {currentQuestionIndex + 1} of {questions.length}</p>
                </div>

                {timeLeft !== null && (
                    <div className={`flex items-center gap-3 px-6 py-3 rounded-xl border-2 ${timeLeft < 60 ? 'border-red-500 bg-red-500/10 text-red-500 animate-pulse' : 'border-primary/20 bg-primary/10 text-primary'}`}>
                        <Timer className="w-5 h-5" />
                        <span className="text-2xl font-mono font-bold">{formatTime(timeLeft)}</span>
                    </div>
                )}
            </div>

            <Progress value={progress} className="h-2" />

            {/* Question Card */}
            <Card className="  shadow-2xl min-h-[400px] flex flex-col">
                <CardHeader>
                    <CardTitle className="text-xl leading-relaxed">
                        {currentQuestionIndex + 1}. {currentQuestion.prompt}
                    </CardTitle>
                </CardHeader>
                <CardContent className="flex-1">
                    {currentQuestion.type === 'MULTI_SELECT' ? (
                        <div className="space-y-4">
                            {(Array.isArray(currentQuestion.options) ? currentQuestion.options : JSON.parse((currentQuestion.options as any) || '[]')).map((option: string, idx: number) => {
                                let selected: string[] = [];
                                try {
                                    selected = answers[currentQuestion.id] || [];
                                    if (typeof selected === 'string') selected = JSON.parse(selected);
                                    if (!Array.isArray(selected)) selected = [];
                                } catch {
                                    selected = [];
                                }

                                return (
                                    <div key={idx} className="flex items-center space-x-3 p-4 rounded-xl border-2 hover:border-primary/50 hover:bg-primary/5 transition-all cursor-pointer has-[:checked]:border-primary has-[:checked]:bg-primary/5">
                                        <input
                                            type="checkbox"
                                            id={`q-${currentQuestion.id}-opt-${idx}`}
                                            checked={selected.includes(option)}
                                            onChange={(e) => {
                                                const next = e.target.checked
                                                    ? [...selected, option]
                                                    : selected.filter(o => o !== option);
                                                handleAnswerChange(currentQuestion.id, next);
                                            }}
                                            className="w-5 h-5 accent-primary cursor-pointer"
                                        />
                                        <Label htmlFor={`q-${currentQuestion.id}-opt-${idx}`} className="flex-1 cursor-pointer font-medium leading-none">
                                            {option}
                                        </Label>
                                    </div>
                                );
                            })}
                        </div>
                    ) : currentQuestion.type === 'MCQ' ? (
                        <RadioGroup
                            value={answers[currentQuestion.id]}
                            onValueChange={(val) => handleAnswerChange(currentQuestion.id, val)}
                            className="space-y-4"
                        >
                            {(Array.isArray(currentQuestion.options) ? currentQuestion.options : JSON.parse((currentQuestion.options as any) || '[]')).map((option: string, idx: number) => (
                                <div key={idx} className="flex items-center space-x-3 p-4 rounded-xl border-2 hover:border-primary/50 hover:bg-primary/5 transition-all cursor-pointer has-[:checked]:border-primary has-[:checked]:bg-primary/5">
                                    <RadioGroupItem value={option} id={`q-${currentQuestion.id}-opt-${idx}`} />
                                    <Label htmlFor={`q-${currentQuestion.id}-opt-${idx}`} className="flex-1 cursor-pointer font-medium leading-none">
                                        {option}
                                    </Label>
                                </div>
                            ))}
                        </RadioGroup>
                    ) : (
                        <Textarea
                            placeholder="Type your answer here..."
                            className="min-h-[200px] text-lg rounded-xl"
                            value={answers[currentQuestion.id] || ''}
                            onChange={(e) => handleAnswerChange(currentQuestion.id, e.target.value)}
                        />
                    )}
                </CardContent>
                <CardFooter className="flex justify-between p-6 bg-zinc-50 border-t rounded-b-2xl">
                    <Button
                        variant="outline"
                        disabled={currentQuestionIndex === 0}
                        onClick={() => setCurrentQuestionIndex(prev => prev - 1)}
                        className="gap-2"
                    >
                        <ChevronLeft className="w-4 h-4" /> Previous
                    </Button>

                    {currentQuestionIndex === questions.length - 1 ? (
                        <Button onClick={handleSubmit} className="gap-2 px-8 bg-emerald-600 hover:bg-emerald-700">
                            Submit Assessment <Send className="w-4 h-4" />
                        </Button>
                    ) : (
                        <Button
                            onClick={() => setCurrentQuestionIndex(prev => prev + 1)}
                            className="gap-2"
                        >
                            Next <ChevronRight className="w-4 h-4" />
                        </Button>
                    )}
                </CardFooter>
            </Card>

            <div className="flex justify-center gap-2 flex-wrap">
                {questions.map((_, idx) => (
                    <button
                        key={idx}
                        onClick={() => setCurrentQuestionIndex(idx)}
                        className={`w-10 h-10 rounded-lg font-bold text-sm transition-all ${currentQuestionIndex === idx
                            ? 'bg-primary text-white scale-110 shadow-lg'
                            : answers[questions[idx].id]
                                ? 'bg-emerald-100 text-emerald-700 hover:bg-emerald-200'
                                : 'bg-zinc-100 text-zinc-500 hover:bg-zinc-200'
                            }`}
                    >
                        {idx + 1}
                    </button>
                ))}
            </div>
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Dialog, DialogContent, DialogHeader, DialogTitle } from "@/components/ui/dialog";
import { Search, MapPin, CheckCircle2, XCircle, TrendingUp, Users, ArrowRight, Clock } from 'lucide-react';
import { cn } from "@/lib/utils";
import { useAuth } from '@/hooks/useAuth';
import { CAMPUS_OPTIONS } from '@/lib/constants';

interface EnhancedAnalyticsViewProps {
    data: {
        attempts: any[];
        assignments: any[];
        users: any[];
    };
}

export const EnhancedAnalyticsView: React.FC<EnhancedAnalyticsViewProps> = ({ data }) => {
    const { user } = useAuth();
    const [searchQuery, setSearchQuery] = useState("");
    const [selectedCampus, setSelectedCampus] = useState<string | null>(null);

    const isNetworkLevel = user?.role === 'ADMIN' || user?.role === 'SUPERADMIN' || user?.role === 'MANAGEMENT';

    const campusMetrics = useMemo(() => {
        // Use standard CAMPUS_OPTIONS as the base list
        const uniqueCampuses = CAMPUS_OPTIONS;

        return uniqueCampuses.map(campus => {
            const campusUsers = data.users.filter(u => u.campusId === campus);
            // Even if no users, we might still want to show the campus in the list if the user expects it
            // but the original logic filtered out empty campuses. 
            // I'll keep them but show empty metrics if the user wants to see "all" campuses.
            // If the user said "campus options are not reflected here", they probably want to see the new ones.

            const campusAttempts = data.attempts.filter(a => a.user?.campusId === campus);

            // Post-Orientation Avg
            const postOrientationScores = campusAttempts
                .filter(a => a.assessment?.type === 'POST_ORIENTATION' && a.status === 'SUBMITTED' && a.score !== null)
                .map(a => a.score);
            const postOrientationAvg = postOrientationScores.length > 0
                ? postOrientationScores.reduce((a, b) => a + b, 0) / postOrientationScores.length
                : null;

            // Academic Preparedness Avg
            const preparednessScores = campusAttempts
                .filter(a => a.assessment?.type === 'PREPAREDNESS' && a.status === 'SUBMITTED' && a.score !== null)
                .map(a => a.score);
            const preparednessAvg = preparednessScores.length > 0
                ? preparednessScores.reduce((a, b) => a + b, 0) / preparednessScores.length
                : null;

            // Academic Orientation Avg
            const academicOrientationScores = campusAttempts
                .filter(a => a.assessment?.type === 'ACADEMIC_ORIENTATION' && a.status === 'SUBMITTED' && a.score !== null)
                .map(a => a.score);
            const academicOrientationAvg = academicOrientationScores.length > 0
                ? academicOrientationScores.reduce((a, b) => a + b, 0) / academicOrientationScores.length
                : null;

            // Other Assessments Avg
            const otherScores = campusAttempts
                .filter(a => !['POST_ORIENTATION', 'PREPAREDNESS', 'ACADEMIC_ORIENTATION'].includes(a.assessment?.type) && a.status === 'SUBMITTED' && a.score !== null)
                .map(a => a.score);
            const otherAvg = otherScores.length > 0
                ? otherScores.reduce((acc, b) => acc + b, 0) / otherScores.length
                : null;

            // Completion Rate Calculation
            let totalExpected = 0;
            let totalCompleted = 0;

            const relevantAssignments = data.assignments;

            campusUsers.forEach(u => {
                const assignedAssessments = Array.from(new Set(relevantAssignments
                    .filter(asm => asm.assignedToId === u.id || asm.assignedToRole === u.role || asm.assignedToCampusId === u.campusId)
                    .map(asm => asm.assessmentId)));

                assignedAssessments.forEach(asmId => {
                    totalExpected++;
                    const hasCompleted = data.attempts.some(att =>
                        att.assessmentId === asmId &&
                        att.userId === u.id &&
                        att.status === 'SUBMITTED'
                    );
                    if (hasCompleted) totalCompleted++;
                });
            });

            const completionRate = totalExpected > 0 ? (totalCompleted / totalExpected) * 100 : 0;

            return {
                id: campus,
                name: campus,
                totalUsers: campusUsers.length,
                postOrientationAvg,
                preparednessAvg,
                academicOrientationAvg,
                otherAvg,
                completionRate,
                totalExpected,
                totalCompleted
            };
        }).filter(Boolean) as any[];
    }, [data]);

    const filteredCampuses = campusMetrics.filter(c =>
        c.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    const renderTeacherDetails = (campusId: string) => {
        const campusUsers = data.users.filter(u => u.campusId === campusId);

        return (
            <div className="space-y-4">
                <Table>
                    <TableHeader>
                        <TableRow className="hover:bg-transparent border-zinc-100">
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px] w-[60px]">S.No.</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Teacher</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Post-Orientation</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Academic Orientation</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Preparedness</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Others Avg</TableHead>
                            <TableHead className="text-zinc-500 font-bold capitalize text-[10px]">Total Completion</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {campusUsers.length === 0 ? (
                            <TableRow>
                                <TableCell colSpan={7} className="text-center py-12 text-zinc-400">No teachers found for this campus.</TableCell>
                            </TableRow>
                        ) : campusUsers.map((u, index) => {
                            const userAttempts = data.attempts.filter(a => a.userId === u.id);

                            const poAttempt = userAttempts.find(a => a.assessment?.type === 'POST_ORIENTATION' && a.status === 'SUBMITTED');
                            const aoAttempt = userAttempts.find(a => a.assessment?.type === 'ACADEMIC_ORIENTATION' && a.status === 'SUBMITTED');
                            const prAttempt = userAttempts.find(a => a.assessment?.type === 'PREPAREDNESS' && a.status === 'SUBMITTED');

                            const otherAttempts = userAttempts.filter(a => !['POST_ORIENTATION', 'PREPAREDNESS', 'ACADEMIC_ORIENTATION'].includes(a.assessment?.type) && a.status === 'SUBMITTED');
                            const otherAvg = otherAttempts.length > 0
                                ? otherAttempts.reduce((acc, a) => acc + (a.score || 0), 0) / otherAttempts.length
                                : null;

                            const assignedAssessments = Array.from(new Set(data.assignments
                                .filter(asm => asm.assignedToId === u.id || asm.assignedToRole === u.role || asm.assignedToCampusId === u.campusId)
                                .map(asm => asm.assessmentId)));

                            let completedCount = 0;
                            assignedAssessments.forEach(asmId => {
                                const attempt = data.attempts.find(att =>
                                    att.assessmentId === asmId &&
                                    att.userId === u.id &&
                                    att.status === 'SUBMITTED'
                                );
                                if (attempt) completedCount++;
                            });

                            const allCompleted = assignedAssessments.length > 0 && completedCount === assignedAssessments.length;

                            return (
                                <TableRow key={u.id} className="group hover:bg-zinc-50/50 border-zinc-50 transition-colors">
                                    <TableCell className="font-medium text-slate-500">{index + 1}</TableCell>
                                    <TableCell>
                                        <div className="flex flex-col">
                                            <span className="font-bold text-sm text-zinc-700">{u.fullName}</span>
                                            <span className="text-[10px] text-zinc-400">{u.email}</span>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        {poAttempt ? (
                                            <Badge variant="secondary" className="bg-emerald-50 text-emerald-700 border-emerald-100 font-bold">
                                                {Math.round(poAttempt.score)}%
                                            </Badge>
                                        ) : (
                                            <Badge variant="outline" className="text-zinc-300 border-dashed bg-transparent border-zinc-200 capitalize text-[9px] font-bold">Pending</Badge>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        {aoAttempt ? (
                                            <Badge variant="secondary" className="bg-purple-50 text-purple-700 border-purple-100 font-bold">
                                                {Math.round(aoAttempt.score)}%
                                            </Badge>
                                        ) : (
                                            <Badge variant="outline" className="text-zinc-300 border-dashed bg-transparent border-zinc-200 capitalize text-[9px] font-bold">Pending</Badge>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        {prAttempt ? (
                                            <Badge variant="secondary" className="bg-blue-50 text-blue-700 border-blue-100 font-bold">
                                                {Math.round(prAttempt.score)}%
                                            </Badge>
                                        ) : (
                                            <Badge variant="outline" className="text-zinc-300 border-dashed bg-transparent border-zinc-200 capitalize text-[9px] font-bold">Pending</Badge>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        {otherAvg !== null ? (
                                            <Badge variant="secondary" className="bg-zinc-50 text-zinc-700 border-zinc-100 font-bold">
                                                {Math.round(otherAvg)}%
                                            </Badge>
                                        ) : (
                                            <span className="text-zinc-200 font-medium italic text-xs">--</span>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex items-center gap-3">
                                            <div className="flex flex-col gap-1 flex-1 min-w-[80px]">
                                                <div className="w-full h-1.5 bg-zinc-100 rounded-full overflow-hidden">
                                                    <div
                                                        className={cn("h-full transition-all duration-500", allCompleted ? "bg-emerald-500" : "bg-primary")}
                                                        style={{ width: `${assignedAssessments.length > 0 ? (completedCount / assignedAssessments.length) * 100 : 0}%` }}
                                                    />
                                                </div>
                                                <span className="text-[9px] text-zinc-400 font-bold capitalize">
                                                    {completedCount}/{assignedAssessments.length} Completed
                                                </span>
                                            </div>
                                            {allCompleted ? (
                                                <CheckCircle2 className="w-4 h-4 text-emerald-500" />
                                            ) : (
                                                <Clock className="w-4 h-4 text-amber-500" />
                                            )}
                                        </div>
                                    </TableCell>
                                </TableRow>
                            );
                        })}
                    </TableBody>
                </Table>
            </div>
        );
    };

    if (!isNetworkLevel) {
        const myCampusMetric = campusMetrics.find(m => m.name === user?.campusId);

        return (
            <div className="space-y-6">
                <div className="flex flex-col gap-1">
                    <h2 className="text-2xl font-bold text-zinc-900">{user?.campusId} Analytics</h2>
                    <p className="text-sm text-zinc-500 font-medium">Monitoring teacher performance and assessment completion for your campus</p>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    <Card className="  shadow-xl shadow-emerald-500/5 bg-emerald-50/30">
                        <CardContent className="pt-6">
                            <TrendingUp className="w-5 h-5 text-emerald-500 mb-2" />
                            <p className="text-xs font-bold text-emerald-600/60 capitalize tracking-wider">Post-Orientation Avg</p>
                            <h3 className="text-3xl font-black text-emerald-700 mt-1">
                                {myCampusMetric && myCampusMetric.postOrientationAvg !== null
                                    ? `${Math.round(myCampusMetric.postOrientationAvg)}%`
                                    : '--'}
                            </h3>
                        </CardContent>
                    </Card>

                    <Card className="  shadow-xl shadow-purple-500/5 bg-purple-50/30">
                        <CardContent className="pt-6">
                            <TrendingUp className="w-5 h-5 text-purple-500 mb-2" />
                            <p className="text-xs font-bold text-purple-600/60 capitalize tracking-wider">Academic Orientation Avg</p>
                            <h3 className="text-3xl font-black text-purple-700 mt-1">
                                {myCampusMetric && myCampusMetric.academicOrientationAvg !== null
                                    ? `${Math.round(myCampusMetric.academicOrientationAvg)}%`
                                    : '--'}
                            </h3>
                        </CardContent>
                    </Card>

                    <Card className="  shadow-xl shadow-blue-500/5 bg-blue-50/30">
                        <CardContent className="pt-6">
                            <TrendingUp className="w-5 h-5 text-blue-500 mb-2" />
                            <p className="text-xs font-bold text-blue-600/60 capitalize tracking-wider">Preparedness Avg</p>
                            <h3 className="text-3xl font-black text-blue-700 mt-1">
                                {myCampusMetric && myCampusMetric.preparednessAvg !== null
                                    ? `${Math.round(myCampusMetric.preparednessAvg)}%`
                                    : '--'}
                            </h3>
                        </CardContent>
                    </Card>

                    <Card className="  shadow-xl shadow-zinc-500/5 bg-zinc-50">
                        <CardContent className="pt-6">
                            <Users className="w-5 h-5 text-zinc-500 mb-2" />
                            <p className="text-xs font-bold text-zinc-400 capitalize tracking-wider">Total Teachers</p>
                            <h3 className="text-3xl font-black text-zinc-800 mt-1">{myCampusMetric?.totalUsers || 0}</h3>
                        </CardContent>
                    </Card>

                    <Card className="  shadow-xl shadow-primary/5 bg-primary/5">
                        <CardContent className="pt-6">
                            <CheckCircle2 className="w-5 h-5 text-primary mb-2" />
                            <p className="text-xs font-bold text-primary/60 capitalize tracking-wider">Campus Completion</p>
                            <h3 className="text-3xl font-black text-primary mt-1">
                                {myCampusMetric ? `${Math.round(myCampusMetric.completionRate)}%` : '0%'}
                            </h3>
                        </CardContent>
                    </Card>
                </div>

                <Card className="  shadow-2xl shadow-zinc-200/50 rounded-3xl overflow-hidden ring-1 ring-zinc-100">
                    <CardHeader className="border-b border-zinc-50 bg-zinc-50/20 py-6">
                        <div className="flex items-center justify-between">
                            <CardTitle className="text-lg font-bold flex items-center gap-2 text-zinc-800">
                                <Users className="w-5 h-5 text-primary" />
                                Teacher Performance & Completion
                            </CardTitle>
                        </div>
                    </CardHeader>
                    <div className="p-0">
                        {renderTeacherDetails(user?.campusId as string)}
                    </div>
                </Card>
            </div>
        );
    }

    const networkPostOrientationAvg = useMemo(() => {
        const valid = campusMetrics.filter(c => c.postOrientationAvg !== null);
        return valid.length ? valid.reduce((acc, c) => acc + c.postOrientationAvg, 0) / valid.length : null;
    }, [campusMetrics]);

    const networkCompletionRate = useMemo(() => {
        const totalExpected = campusMetrics.reduce((acc, c) => acc + c.totalExpected, 0);
        const totalCompleted = campusMetrics.reduce((acc, c) => acc + c.totalCompleted, 0);
        return totalExpected > 0 ? (totalCompleted / totalExpected) * 100 : 0;
    }, [campusMetrics]);

    return (
        <div className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <Card className="shadow-2xl shadow-emerald-500/10 bg-gradient-to-br from-emerald-500 justify-between items-center text-white border-none rounded-3xl overflow-hidden relative">
                    <div className="absolute top-0 right-0 -translate-y-4 translate-x-4 w-24 h-24 bg-white/10 rounded-full blur-2xl" />
                    <CardContent className="p-6 relative z-10">
                        <TrendingUp className="w-6 h-6 text-emerald-100 mb-3" />
                        <p className="text-xs font-bold text-emerald-100 uppercase tracking-widest mb-1">Network Post Orientation</p>
                        <h3 className="text-4xl font-black">{networkPostOrientationAvg !== null ? `${Math.round(networkPostOrientationAvg)}%` : '--'}</h3>
                        <p className="text-[10px] text-emerald-200 mt-2 font-medium">Average across all campuses</p>
                    </CardContent>
                </Card>

                <Card className="shadow-xl bg-purple-50 rounded-3xl border-none">
                    <CardContent className="p-6">
                        <TrendingUp className="w-5 h-5 text-purple-500 mb-2" />
                        <p className="text-xs font-bold text-purple-600/60 uppercase tracking-widest mb-1">Academic Orientation</p>
                        <h3 className="text-3xl font-black text-purple-700">
                            {campusMetrics.filter(c => c.academicOrientationAvg !== null).length 
                                ? `${Math.round(campusMetrics.reduce((a, b) => a + (b.academicOrientationAvg || 0), 0) / campusMetrics.filter(c => c.academicOrientationAvg !== null).length)}%`
                                : '--'}
                        </h3>
                    </CardContent>
                </Card>

                <Card className="shadow-xl bg-blue-50 rounded-3xl border-none">
                    <CardContent className="p-6">
                        <TrendingUp className="w-5 h-5 text-blue-500 mb-2" />
                        <p className="text-xs font-bold text-blue-600/60 uppercase tracking-widest mb-1">Academic Preparedness</p>
                        <h3 className="text-3xl font-black text-blue-700">
                            {campusMetrics.filter(c => c.preparednessAvg !== null).length 
                                ? `${Math.round(campusMetrics.reduce((a, b) => a + (b.preparednessAvg || 0), 0) / campusMetrics.filter(c => c.preparednessAvg !== null).length)}%`
                                : '--'}
                        </h3>
                    </CardContent>
                </Card>

                <Card className="shadow-xl bg-zinc-900 text-white rounded-3xl border-none relative overflow-hidden">
                    <div className="absolute top-0 right-0 -translate-y-4 translate-x-4 w-24 h-24 bg-primary/20 rounded-full blur-2xl" />
                    <CardContent className="p-6 relative z-10">
                        <CheckCircle2 className="w-5 h-5 text-primary mb-2" />
                        <p className="text-xs font-bold text-zinc-400 uppercase tracking-widest mb-1">Global Completion</p>
                        <h3 className="text-3xl font-black">{Math.round(networkCompletionRate)}%</h3>
                    </CardContent>
                </Card>
            </div>

            <div className="flex flex-col md:flex-row gap-4 justify-between items-start md:items-center pt-4">
                <div className="relative w-full max-w-sm">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-zinc-400" />
                    <Input
                        placeholder="Search campus..."
                        className="pl-10 h-10 rounded-xl"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                </div>
                <div className="flex items-center gap-3">
                    <p className="text-[10px] font-bold text-zinc-400 bg-zinc-50 px-3 py-1 rounded-full capitalize tracking-tighter border border-zinc-100 italic">
                        Tip: Double-tap row for teacher details
                    </p>
                    <Badge variant="outline" className="px-3 py-1 bg-white shadow-sm border-zinc-100 text-zinc-600 font-medium rounded-lg">
                        Total Users: {data.users.length}
                    </Badge>
                </div>
            </div>

            <Card className="  shadow-xl rounded-3xl overflow-hidden ring-1 ring-zinc-100">
                <div className="overflow-x-auto">
                    <Table>
                        <TableHeader className="bg-zinc-50/50">
                            <TableRow>
                                <TableHead className="w-[60px] font-bold text-zinc-500 capitalize text-[10px] tracking-wider text-center">S.No.</TableHead>
                                <TableHead className="w-[200px] font-bold text-zinc-500 capitalize text-[10px] tracking-wider">Campus</TableHead>
                                <TableHead className="font-bold text-zinc-500 capitalize text-[10px] tracking-wider text-center">Post-Orientation Avg</TableHead>
                                <TableHead className="font-bold text-zinc-500 capitalize text-[10px] tracking-wider text-center">Acad. Orientation Avg</TableHead>
                                <TableHead className="font-bold text-zinc-500 capitalize text-[10px] tracking-wider text-center">Acad. Preparedness Avg</TableHead>
                                <TableHead className="font-bold text-zinc-500 capitalize text-[10px] tracking-wider text-center">Other Assessments Avg</TableHead>
                                <TableHead className="font-bold text-zinc-500 capitalize text-[10px] tracking-wider">Completion Rate</TableHead>
                                <TableHead className="w-[80px]"></TableHead>
                            </TableRow>
                        </TableHeader>
                        <TableBody>
                            {filteredCampuses.map((campus, index) => (
                                <TableRow
                                    key={campus.id}
                                    className="cursor-pointer hover:bg-zinc-50 transition-colors group select-none"
                                    onDoubleClick={() => setSelectedCampus(campus.id)}
                                >
                                    <TableCell className="font-medium text-slate-500 text-center">{index + 1}</TableCell>
                                    <TableCell className="font-bold py-4">
                                        <div className="flex items-center gap-2">
                                            <div className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center">
                                                <MapPin className="w-4 h-4 text-primary" />
                                            </div>
                                            {campus.name}
                                        </div>
                                    </TableCell>
                                    <TableCell className="text-center">
                                        {campus.postOrientationAvg !== null ? (
                                            <div className="flex flex-col items-center">
                                                <span className="text-lg font-bold text-emerald-600">{Math.round(campus.postOrientationAvg)}%</span>
                                                <span className="text-[10px] text-zinc-400">Average Score</span>
                                            </div>
                                        ) : (
                                            <span className="text-zinc-300">--</span>
                                        )}
                                    </TableCell>
                                    <TableCell className="text-center">
                                        {campus.academicOrientationAvg !== null ? (
                                            <div className="flex flex-col items-center">
                                                <span className="text-lg font-bold text-purple-600">{Math.round(campus.academicOrientationAvg)}%</span>
                                                <span className="text-[10px] text-zinc-400">Average Score</span>
                                            </div>
                                        ) : (
                                            <span className="text-zinc-300">--</span>
                                        )}
                                    </TableCell>
                                    <TableCell className="text-center">
                                        {campus.preparednessAvg !== null ? (
                                            <div className="flex flex-col items-center">
                                                <span className="text-lg font-bold text-blue-600">{Math.round(campus.preparednessAvg)}%</span>
                                                <span className="text-[10px] text-zinc-400">Average Score</span>
                                            </div>
                                        ) : (
                                            <span className="text-zinc-300">--</span>
                                        )}
                                    </TableCell>
                                    <TableCell className="text-center">
                                        {campus.otherAvg !== null ? (
                                            <div className="flex flex-col items-center">
                                                <span className="text-lg font-bold text-zinc-600">{Math.round(campus.otherAvg)}%</span>
                                                <span className="text-[10px] text-zinc-400">Average Score</span>
                                            </div>
                                        ) : (
                                            <span className="text-zinc-300">--</span>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        <div className="flex flex-col gap-1">
                                            <div className="flex justify-between items-center w-full">
                                                <span className="text-xs font-bold">{Math.round(campus.completionRate)}%</span>
                                                <span className="text-[10px] text-zinc-400">{campus.totalCompleted}/{campus.totalExpected}</span>
                                            </div>
                                            <div className="w-full h-2 bg-zinc-100 rounded-full overflow-hidden">
                                                <div
                                                    className="h-full bg-primary"
                                                    style={{ width: `${campus.completionRate}%` }}
                                                />
                                            </div>
                                        </div>
                                    </TableCell>
                                    <TableCell>
                                        <Button variant="ghost" size="icon" className="group-hover:translate-x-1 transition-transform">
                                            <ArrowRight className="w-4 h-4 text-zinc-400" />
                                        </Button>
                                    </TableCell>
                                </TableRow>
                            ))}
                        </TableBody>
                    </Table>
                </div>
            </Card>

            <Dialog open={!!selectedCampus} onOpenChange={() => setSelectedCampus(null)}>
                <DialogContent className="max-w-4xl p-0 overflow-hidden rounded-3xl   shadow-2xl">
                    <div className="bg-primary p-6 text-white">
                        <DialogHeader>
                            <div className="flex items-center gap-3">
                                <div className="p-2 bg-white/20 rounded-xl backdrop-blur-sm">
                                    <MapPin className="w-6 h-6" />
                                </div>
                                <div>
                                    <DialogTitle className="text-2xl font-bold">{selectedCampus} Details</DialogTitle>
                                    <p className="text-white/70 text-sm">Teacher-level performance and completion</p>
                                </div>
                            </div>
                        </DialogHeader>
                    </div>
                    <div className="p-6 max-h-[70vh] overflow-y-auto">
                        {renderTeacherDetails(selectedCampus as string)}
                    </div>
                </DialogContent>
            </Dialog>
        </div>
    );
};

import { useState, useEffect } from "react";
import {
    FileCheck,
    Eye,
    CheckCircle2,
    Download,
    ExternalLink,
    ChevronRight,
    Clock,
    ShieldCheck,
    AlertCircle
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { toast } from "sonner";
import { documentService, DocumentAcknowledgement } from "@/services/documentService";
import { PageHeader } from "@/components/layout/PageHeader";
import { cn } from "@/lib/utils";

export function AcknowledgementsView({ teacherId }: { teacherId: string }) {
    const [acknowledgements, setAcknowledgements] = useState<DocumentAcknowledgement[]>([]);
    const [selectedAck, setSelectedAck] = useState<DocumentAcknowledgement | null>(null);
    const [loading, setLoading] = useState(true);
    const [pdfUrl, setPdfUrl] = useState<string | null>(null);
    const [docContent, setDocContent] = useState<string | null>(null);

    useEffect(() => {
        if (teacherId) {
            fetchAcknowledgements();
        }
    }, [teacherId]);

    const fetchAcknowledgements = async () => {
        try {
            setLoading(true);
            const data = await documentService.getTeacherAcknowledgements(teacherId);
            setAcknowledgements(data);
        } catch (error) {
            console.error("Error fetching documents:", error);
            toast.error("Failed to load documents");
        } finally {
            setLoading(false);
        }
    };

    const handleSelectAck = async (ack: DocumentAcknowledgement) => {
        setSelectedAck(ack);
        if (ack.document) {
            try {
                // Use fileUrl instead of file_path
                const publicUrl = await documentService.getDocumentPublicUrl(ack.document.fileUrl);

                // Determine if we need an Office viewer based on extension
                const isWordDoc = ack.document.fileName.toLowerCase().endsWith('.doc') ||
                    ack.document.fileName.toLowerCase().endsWith('.docx');

                if (isWordDoc) {
                    try {
                        // For localhost/private files, external viewers won't work.
                        // We use mammoth to convert DOCX to HTML for preview
                        setPdfUrl(''); // clear PDF url
                        const response = await fetch(publicUrl);
                        const arrayBuffer = await response.arrayBuffer();
                        const mammoth = await import('mammoth');
                        const result = await mammoth.convertToHtml({ arrayBuffer });
                        setDocContent(result.value);
                    } catch (err) {
                        console.error("Error parsing Word document:", err);
                        setDocContent("<div class='p-8 text-center text-red-500'>Failed to load Word document preview. Please download the file instead.</div>");
                    }
                } else {
                    setDocContent(''); // clear text content
                    setPdfUrl(publicUrl);
                }

                if (ack.status === 'PENDING') {
                    await documentService.markAsViewed(ack.id);
                    // Update local state
                    setAcknowledgements(prev => prev.map(a =>
                        a.id === ack.id ? { ...a, status: 'VIEWED' as const, viewedAt: new Date().toISOString() } : a
                    ));
                }
            } catch (error) {
                console.error("Error getting PDF URL:", error);
                toast.error("Could not load document preview");
            }
        }
    };

    const handleAcknowledge = async () => {
        if (!selectedAck || !selectedAck.document) return;

        try {
            // Use document.hash if available, or a computed one
            await documentService.acknowledgeDocument(selectedAck.id, selectedAck.document.hash || 'manual-hash');
            toast.success("Document acknowledged successfully");

            // Update local state
            setAcknowledgements(prev => prev.map(a =>
                a.id === selectedAck.id ? {
                    ...a,
                    status: 'ACKNOWLEDGED' as const,
                    acknowledgedAt: new Date().toISOString(),
                    documentHash: selectedAck.document?.hash
                } : a
            ));

            // Update selected ack to show success
            setSelectedAck(prev => prev ? {
                ...prev,
                status: 'ACKNOWLEDGED' as const,
                acknowledgedAt: new Date().toISOString()
            } : null);

        } catch (error) {
            console.error("Error acknowledging document:", error);
            toast.error("Failed to acknowledge document");
        }
    };

    const getStatusBadge = (status: string) => {
        const baseClass = "px-3 py-1 rounded-full font-black text-[10px] tracking-widest uppercase border-none text-white shadow-sm";
        switch (status) {
            case 'PENDING': return <Badge className={cn(baseClass, "bg-amber-500")}>Pending</Badge>;
            case 'VIEWED': return <Badge className={cn(baseClass, "bg-blue-600")}>Viewed</Badge>;
            case 'ACKNOWLEDGED': return <Badge className={cn(baseClass, "bg-emerald-600")}>Acknowledged</Badge>;
            case 'SIGNED': return <Badge className={cn(baseClass, "bg-indigo-600")}>Signed</Badge>;
            default: return <Badge className={cn(baseClass, "bg-slate-400")}>{status}</Badge>;
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center h-64">
                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            <PageHeader
                title="Document Acknowledgements"
                subtitle="Review and sign important school documents and policies"
            />

            <div className="grid lg:grid-cols-12 gap-6 h-[calc(100vh-250px)]">
                {/* Left: Document List */}
                <Card className="lg:col-span-4 flex flex-col overflow-hidden">
                    <CardHeader className="pb-3">
                        <CardTitle className="text-lg">My Documents</CardTitle>
                        <CardDescription>{acknowledgements.length} documents assigned to you</CardDescription>
                    </CardHeader>
                    <CardContent className="flex-1 p-0 overflow-hidden">
                        <ScrollArea className="h-full">
                            <div className="divide-y">
                                {acknowledgements.length === 0 ? (
                                    <div className="p-8 text-center text-muted-foreground">
                                        <FileCheck className="w-12 h-12 mx-auto mb-4 opacity-20" />
                                        <p>No documents found</p>
                                    </div>
                                ) : (
                                    acknowledgements.map((ack) => (
                                        <button
                                            key={ack.id}
                                            onClick={() => handleSelectAck(ack)}
                                            className={cn(
                                                "w-full text-left p-4 transition-colors hover:bg-muted/50 flex items-center gap-4",
                                                selectedAck?.id === ack.id && "bg-muted border-l-4 border-primary"
                                            )}
                                        >
                                            <div className={cn(
                                                "w-10 h-10 rounded-full flex items-center justify-center shrink-0",
                                                ack.status === 'ACKNOWLEDGED' ? "bg-green-100 text-green-600" : "bg-primary/10 text-primary"
                                            )}>
                                                <FileCheck className="w-5 h-5" />
                                            </div>
                                            <div className="flex-1 min-w-0">
                                                <div className="font-medium truncate">{ack.document?.title}</div>
                                                <div className="flex items-center gap-2 mt-1">
                                                    {getStatusBadge(ack.status)}
                                                    <span className="text-xs text-muted-foreground">
                                                        {new Date(ack.createdAt).toLocaleDateString()}
                                                    </span>
                                                </div>
                                            </div>
                                            <ChevronRight className="w-4 h-4 text-muted-foreground" />
                                        </button>
                                    ))
                                )}
                            </div>
                        </ScrollArea>
                    </CardContent>
                </Card>

                {/* Right: Document Preview & Actions */}
                <Card className="lg:col-span-8 flex flex-col overflow-hidden">
                    {!selectedAck ? (
                        <div className="flex-1 flex flex-col items-center justify-center p-12 text-center text-muted-foreground">
                            <Eye className="w-16 h-16 mb-4 opacity-10" />
                            <h3 className="text-lg font-medium">Select a document to preview</h3>
                            <p className="max-w-xs mx-auto mt-2">
                                Choose a document from the list on the left to view its contents and provide acknowledgement.
                            </p>
                        </div>
                    ) : (
                        <>
                            <CardHeader className="flex flex-row items-center justify-between pb-3">
                                <div>
                                    <CardTitle className="text-xl flex items-center gap-2">
                                        {selectedAck.document?.title}
                                        {selectedAck.status === 'ACKNOWLEDGED' && (
                                            <CheckCircle2 className="w-5 h-5 text-green-500" />
                                        )}
                                    </CardTitle>
                                    <CardDescription>
                                        Assigned on {new Date(selectedAck.createdAt).toLocaleDateString()}
                                    </CardDescription>
                                </div>
                                <div className="flex gap-2">
                                    {!docContent && pdfUrl && (
                                        <Button variant="outline" size="sm" onClick={() => window.open(pdfUrl, '_blank')}>
                                            <ExternalLink className="w-4 h-4 mr-2" />
                                            Open in New Tab
                                        </Button>
                                    )}
                                    {selectedAck.document?.fileUrl && (
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            onClick={async () => {
                                                const url = await documentService.getDocumentPublicUrl(selectedAck.document!.fileUrl);
                                                const a = document.createElement('a');
                                                a.href = url;
                                                a.download = selectedAck.document!.title;
                                                document.body.appendChild(a);
                                                a.click();
                                                document.body.removeChild(a);
                                            }}
                                        >
                                            <Download className="w-4 h-4 mr-2" />
                                            Download
                                        </Button>
                                    )}
                                </div>
                            </CardHeader>
                            <CardContent className="flex-1 flex flex-col gap-4 p-0 overflow-hidden">
                                <div className="flex-1 bg-muted relative rounded-md mx-6 border overflow-hidden">
                                    {docContent ? (
                                        <ScrollArea className="w-full h-full bg-white p-8">
                                            <div
                                                className="prose max-w-none docx-preview"
                                                dangerouslySetInnerHTML={{ __html: docContent }}
                                            />
                                        </ScrollArea>
                                    ) : pdfUrl ? (
                                        <iframe
                                            src={pdfUrl}
                                            className="w-full h-full border-none"
                                            title="Document Preview"
                                        />
                                    ) : (
                                        <div className="absolute inset-0 flex flex-col items-center justify-center p-8 text-center bg-white">
                                            <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary mb-4"></div>
                                            <p>Loading document preview...</p>
                                        </div>
                                    )}
                                </div>

                                <div className="p-6 bg-background border-t">
                                    {selectedAck.status === 'ACKNOWLEDGED' ? (
                                        <div className="flex items-center gap-4 p-4 rounded-lg bg-green-50 border border-green-100">
                                            <ShieldCheck className="w-8 h-8 text-green-600" />
                                            <div>
                                                <div className="font-semibold text-green-900">Document Acknowledged</div>
                                                <div className="text-sm text-green-700">
                                                    Acknowledged on {selectedAck.acknowledgedAt ? new Date(selectedAck.acknowledgedAt).toLocaleString() : 'N/A'} from IP {selectedAck.ipAddress || 'unknown'}
                                                </div>
                                                <div className="text-[10px] text-green-600 font-mono mt-1 opacity-60">
                                                    Digital Hash: {selectedAck.documentHash}
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <div className="flex flex-col gap-4">
                                            <div className="flex items-start gap-3 p-4 rounded-lg bg-blue-50 border border-blue-100 text-blue-800 text-sm">
                                                <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
                                                <p>
                                                    By clicking "Acknowledge", you confirm that you have read and understood the contents of this document.
                                                    Your IP address and a timestamp will be recorded for compliance purposes.
                                                </p>
                                            </div>
                                            <div className="flex justify-end gap-3">
                                                <Button variant="ghost" onClick={() => setSelectedAck(null)}>Cancel</Button>
                                                <Button
                                                    onClick={handleAcknowledge}
                                                    className="bg-indigo-600 hover:bg-indigo-700 text-white shadow-md"
                                                >
                                                    <FileCheck className="w-4 h-4 mr-2" />
                                                    Acknowledge Document
                                                </Button>
                                            </div>
                                        </div>
                                    )}
                                </div>
                            </CardContent>
                        </>
                    )}
                </Card>
            </div>
        </div>
    );
}

import React from "react";
import { User } from "@/services/userService";
import { Card, CardContent } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Search, User as UserIcon, Filter } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";

interface TeacherSelectionProps {
    teachers: User[];
    onSelect: (teacher: User) => void;
}

import { useSearchParams } from "react-router-dom";

const TeacherSelection: React.FC<TeacherSelectionProps> = ({ teachers, onSelect }) => {
    const [searchParams, setSearchParams] = useSearchParams();
    const [searchTerm, setSearchTerm] = React.useState(searchParams.get("q") || "");
    const [academicFilter, setAcademicFilter] = React.useState(searchParams.get("academics") || "all");

    // Sync state to URL
    React.useEffect(() => {
        const params = new URLSearchParams(searchParams);
        if (searchTerm) params.set("q", searchTerm);
        else params.delete("q");

        if (academicFilter !== "all") params.set("academics", academicFilter);
        else params.delete("academics");

        setSearchParams(params, { replace: true });
    }, [searchTerm, academicFilter]);

    const filteredTeachers = teachers.filter(t => {
        const matchesSearch = t.fullName.toLowerCase().includes(searchTerm.toLowerCase()) ||
            t.department?.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesAcademic = academicFilter === "all" || t.academics === academicFilter;
        return matchesSearch && matchesAcademic;
    });

    return (
        <div className="space-y-6">
            <div className="flex flex-col sm:flex-row gap-3">
                <div className="relative flex-1">
                    <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                    <Input
                        className="pl-10 h-10"
                        placeholder="Search teachers by name or department..."
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                    />
                </div>
                <div className="w-full sm:w-48">
                    <Select value={academicFilter} onValueChange={setAcademicFilter}>
                        <SelectTrigger className="h-10">
                            <Filter className="w-4 h-4 mr-2 text-muted-foreground" />
                            <SelectValue placeholder="All Teachers" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="all">All Teachers</SelectItem>
                            <SelectItem value="CORE">Core Teachers</SelectItem>
                            <SelectItem value="NON_CORE">Non-Core Teachers</SelectItem>
                        </SelectContent>
                    </Select>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {filteredTeachers.map((teacher) => (
                    <Card
                        key={teacher.id}
                        className="hover:border-primary cursor-pointer transition-colors shadow-sm group"
                        onClick={() => onSelect(teacher)}
                    >
                        <CardContent className="p-4 flex items-center gap-4">
                            <div className="p-2 rounded-full bg-muted group-hover:bg-primary/10 transition-colors">
                                <UserIcon className="w-5 h-5 text-muted-foreground group-hover:text-primary transition-colors" />
                            </div>
                            <div className="flex-1 min-w-0">
                                <h4 className="font-semibold truncate">{teacher.fullName}</h4>
                                <p className="text-xs text-muted-foreground truncate">{teacher.department}</p>
                            </div>
                            <Badge variant={teacher.academics === 'CORE' ? 'default' : 'secondary'} className="text-[10px] whitespace-nowrap">
                                {teacher.academics === 'CORE' ? 'Core' : 'Non-Core'}
                            </Badge>
                        </CardContent>
                    </Card>
                ))}
            </div>

            {filteredTeachers.length === 0 && (
                <div className="text-center py-12 border-2 border-dashed rounded-xl">
                    <p className="text-muted-foreground">No teachers found matching your search.</p>
                </div>
            )}
        </div>
    );
};

export default TeacherSelection;

import { useState, useEffect } from "react";
import { NavLink, useLocation } from "react-router-dom";
import { cn } from "@/lib/utils";
import { useIsMobile } from "@/hooks/use-mobile";
import {
  SquaresFour,
  ChartLineUp,
  UsersThree,
  GraduationCap,
  Gear,
  SignOut,
  CaretLeft,
  Student,
  X,
  Buildings,
  Heartbeat,
  Bell,
  ShieldCheck,
  MagnifyingGlass,
  ClipboardText,
  CalendarBlank,
  ChartBar,
  Lightning,
  BookOpen,
  Clock,
  Target,
} from "@phosphor-icons/react";
import { Role, RoleBadge } from "../RoleBadge";
import { Button } from "../ui/button";
import { useAccessControl } from "@/hooks/useAccessControl";
import { SidebarAccordionItem, SidebarModule } from "./SidebarAccordionItem";
import { Input } from "../ui/input";

interface DashboardSidebarProps {
  role: Role;
  userName: string;
  collapsed: boolean;
  onToggle: () => void;
  searchQuery: string;
  setSearchQuery: (query: string) => void;
  isHoverMode?: boolean;
}

export function DashboardSidebar({
  role,
  userName,
  collapsed,
  onToggle,
  searchQuery,
  setSearchQuery,
  isHoverMode = false
}: DashboardSidebarProps) {
  const { isModuleEnabled } = useAccessControl();
  const location = useLocation();
  const isMobile = useIsMobile();
  const [unreadAnnouncements, setUnreadAnnouncements] = useState(0);
  const [openModule, setOpenModule] = useState<string | null>("Dashboard");

  useEffect(() => {
    const fetchUnread = async () => {
      try {
        const { announcementService } = await import("@/services/announcementService");
        const announcements = await announcementService.getAnnouncements();
        setUnreadAnnouncements(announcements.filter(a => !a.isAcknowledged).length);
      } catch (e) {
        // Silently fail if not logged in or error
      }
    };
    fetchUnread();
  }, [location.pathname]);

  // Role-based navigation configuration (Unified into a single 'Leader' style view)
  const getNavByRole = (role: string): SidebarModule[] => {
    const r = role.toLowerCase();

    if (r === "teacher") {
      return [
        {
          title: "Dashboard",
          icon: SquaresFour,
          subModules: [
            { title: "Overview", path: "/teacher" },
            { title: "Progress Dashboard", path: "/okr" },
            { title: "My Portfolio", path: "/portfolio" },
          ],
        },
        {
          title: "Observation",
          icon: ChartLineUp,
          subModules: [
            { title: "Observations", path: "/teacher/observations" },
            { title: "Goals", path: "/teacher/goals" },
          ],
        },
        {
          title: "Courses",
          icon: GraduationCap,
          subModules: [
            { title: "Course Catalogue", path: "/teacher/courses" },
            { title: "Assessments", path: "/teacher/courses/assessments" },
            { title: "Learning Festival", path: "/teacher/festival" },
            { title: "MOOC Evidence", path: "/teacher/mooc" },
          ],
        },
        {
          title: "Training",
          icon: Clock,
          subModules: [
            { title: "Training Calendar", path: "/teacher/calendar" },
            { title: "Training Hours", path: "/teacher/hours" },
          ],
        },
        {
          title: "Engagement",
          icon: Bell,
          subModules: [
            { title: "Meetings", path: "/teacher/meetings" },
            { title: "Survey", path: "/teacher/survey" },
            { title: "Announcements", path: "/announcements", badge: unreadAnnouncements },
          ],
        },
        {
          title: "Records",
          icon: ClipboardText,
          subModules: [{ title: "Attendance", path: "/teacher/attendance" }],
        },
        {
          title: "Profile",
          icon: UsersThree,
          subModules: [{ title: "My Profile", path: "/teacher/profile" }],
        },
      ];
    }

    if (r === "school_leader" || r === "leader") {
      return [
        {
          title: "Dashboard",
          icon: SquaresFour,
          subModules: [
            { title: "Overview", path: "/leader" },
            { title: "Performance", path: "/leader/performance" },
            { title: "Progress Dashboard", path: "/okr" },
            { title: "Portfolio", path: "/portfolio" },
          ],
        },
        {
          title: "Observation & Performance",
          icon: ChartLineUp,
          subModules: [
            { title: "Observations", path: "/leader/growth" },
            { title: "Goals", path: "/leader/goals" },
          ],
        },
        {
          title: "Team Management",
          icon: UsersThree,
          subModules: [
            { title: "Team Overview", path: "/leader/team" },
            { title: "User Management", path: "/leader/users" },
          ],
        },
        {
          title: "Courses",
          icon: GraduationCap,
          subModules: [
            { title: "Course Catalogue", path: "/leader/courses" },
            { title: "Assessments", path: "/leader/courses/assessments" },
            { title: "Learning Festival", path: "/leader/festival" },
            { title: "MOOC Evidence", path: "/leader/mooc" },
          ],
        },
        {
          title: "Training",
          icon: Clock,
          subModules: [
            { title: "TD Participation", path: "/leader/participation" },
            { title: "Learning Insights", path: "/leader/insights" },
            { title: "Training Calendar", path: "/leader/calendar" },
          ],
        },
        {
          title: "Operations",
          icon: Gear,
          subModules: [
            { title: "Attendance Register", path: "/leader/attendance" },
            { title: "Meetings", path: "/leader/meetings" },
            { title: "Reports", path: "/leader/reports" },
            { title: "Survey", path: "/leader/survey" },
            { title: "Announcements", path: "/announcements", badge: unreadAnnouncements },
            { title: "Form Templates", path: "/leader/forms" },
            { title: "Settings", path: "/leader/settings" },
          ],
        },
      ];
    }

    if (r === "admin" || r === "superadmin") {
      const isAdmin = r === "admin";
      const baseNav: SidebarModule[] = [
        {
          title: "Dashboard",
          icon: SquaresFour,
          subModules: [
            { title: "Overview", path: "/admin" },
            { title: "Progress Dashboard", path: "/okr" },
            { title: "Portfolio", path: "/portfolio" },
          ],
        },
        {
          title: "Observation & Goals",
          icon: ChartLineUp,
          subModules: [
            { title: "Observations", path: "/admin/growth-analytics" },
            { title: "Goals", path: "/admin/goals" },
          ],
        },
      ];

      if (r === "superadmin") {
        baseNav.push({
          title: "User & Configuration",
          icon: ShieldCheck,
          subModules: [
            { title: "User Management", path: "/admin/users" },
            { title: "Settings", path: "/admin/settings" },
            { title: "SuperAdmin Console", path: "/admin/superadmin" },
            { title: "Form Templates", path: "/admin/forms" },
          ],
        });
      } else {
        baseNav.push({
          title: "User & Forms",
          icon: UsersThree,
          subModules: [
            { title: "User Management", path: "/admin/users" },
            { title: "Form Templates", path: "/admin/forms" },
          ],
        });
      }

      baseNav.push(
        {
          title: "Courses",
          icon: GraduationCap,
          subModules: [
            { title: "Course Catalogue", path: "/admin/courses" },
            { title: "Assessments", path: "/admin/courses/assessments" },
            { title: "Learning Festival", path: "/admin/festival" },
            { title: "MOOC Evidence", path: "/admin/mooc" },
          ],
        },
        {
          title: "Training",
          icon: Clock,
          subModules: [
            { title: "Training Calendar", path: "/admin/calendar" },
            { title: "Training Hours", path: "/admin/hours" },
          ],
        },
        {
          title: "Operations",
          icon: Gear,
          subModules: [
            { title: "Attendance Register", path: "/admin/attendance" },
            { title: "Meetings", path: "/admin/meetings" },
            { title: "Reports", path: "/admin/reports" },
            { title: "Survey", path: "/admin/survey" },
            { title: "Announcements", path: "/announcements", badge: unreadAnnouncements },
          ],
        }
      );

      return baseNav;
    }

    if (r === "management") {
      return [
        {
          title: "Dashboard",
          icon: SquaresFour,
          subModules: [
            { title: "Overview", path: "/management/overview" },
          ],
        },
        {
          title: "Observation & Goals",
          icon: ChartLineUp,
          subModules: [
            { title: "Observations", path: "/management/growth-analytics" },
            { title: "Goals", path: "/management/goals" },
            { title: "Progress Dashboard", path: "/okr" },
            { title: "Staff Portfolios", path: "/portfolio" },
          ],
        },
        {
          title: "Performance Analytics",
          icon: Heartbeat,
          subModules: [
            { title: "PDI Health Index", path: "/management/pdi-health" },
            { title: "Campus Performance", path: "/management/campus-performance" },
            { title: "Academic TD Impact", path: "/management/pd-impact" },
            { title: "Training Hours", path: "/management/hours" },
          ],
        },
        {
          title: "Courses & Assessments",
          icon: GraduationCap,
          subModules: [
            { title: "Assessments", path: "/management/courses/assessments" },
          ],
        },
        {
          title: "Training",
          icon: Clock,
          subModules: [

            { title: "Training Analytics", path: "/management/training-analytics" },
            { title: "Attendance Logs", path: "/management/attendance" },
          ],
        },
        {
          title: "Operations",
          icon: Gear,
          subModules: [
            { title: "Meetings", path: "/management/meetings" },
            { title: "Survey", path: "/management/survey" },
            { title: "Announcements", path: "/announcements", badge: unreadAnnouncements },
          ],
        },
      ];
    }

    return [];
  };

  const fullNav = getNavByRole(role);

  // Filter modules and sub-modules based on access control and search
  const filteredNav = fullNav
    .map((module) => {
      if (module.path) {
        // Direct link module
        const isEnabled = isModuleEnabled(module.path, role);
        const matchesSearch =
          module.title.toLowerCase().includes(searchQuery.toLowerCase());

        return isEnabled && matchesSearch ? module : null;
      }

      // Accordion module
      const filteredSubModules = module.subModules?.filter(
        (sub) =>
          isModuleEnabled(sub.path, role) &&
          (sub.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
            module.title.toLowerCase().includes(searchQuery.toLowerCase()))
      );

      if (filteredSubModules && filteredSubModules.length > 0) {
        return { ...module, subModules: filteredSubModules };
      }
      return null;
    })
    .filter((module): module is SidebarModule => module !== null);

  // Determine initial open module based on location
  useEffect(() => {
    const activeModule = fullNav.find((m) =>
      m.subModules.some((s) => {
        const rootPaths = ["/teacher", "/leader", "/admin", "/management"];
        return location.pathname === s.path || (!rootPaths.includes(s.path) && location.pathname.startsWith(s.path));
      })
    );
    if (activeModule) {
      setOpenModule(activeModule.title);
    }
  }, [location.pathname]);

  return (
    <aside
      className={cn(
        "h-screen bg-sidebar shadow-xl print:hidden flex flex-col overflow-hidden",
        isHoverMode
          ? "w-full"
          : cn(
            "fixed left-0 top-0 z-[60] transition-all duration-300 ease-out",
            collapsed
              ? isMobile
                ? "-translate-x-full w-64"
                : "w-16 translate-x-0"
              : "translate-x-0 w-64"
          )
      )}
    >
      {/* Header */}
      <div className="flex items-center justify-between p-4 border-b border-sidebar-border h-16 shrink-0 relative">
        {/* Collapsed: just the icon, centered */}
        <div
          className={cn(
            "absolute left-1/2 -translate-x-1/2 transition-all duration-200",
            collapsed && !isMobile ? "opacity-100 scale-100" : "opacity-0 scale-75 pointer-events-none"
          )}
        >
          <div className="bg-sidebar-primary p-2 rounded-lg">
            <Student className="w-5 h-5 text-sidebar-primary-foreground" weight="fill" />
          </div>
        </div>

        {/* Expanded: logo + platform name */}
        <div
          className={cn(
            "flex items-center gap-2 min-w-0 flex-1 pr-2 transition-all duration-200",
            collapsed && !isMobile
              ? "opacity-0 translate-x-[-8px] pointer-events-none"
              : "opacity-100 translate-x-0 delay-[120ms]"
          )}
        >
          <div className="p-2 rounded-lg bg-sidebar-primary shrink-0">
            <Student className="w-5 h-5 text-sidebar-primary-foreground" weight="fill" />
          </div>
          <span className="font-semibold text-sidebar-foreground truncate text-sm whitespace-nowrap">
            <span className="text-[#EA104A]">Teacher</span> Platform
          </span>
        </div>

        {/* Collapse toggle – only in non-hover mode */}
        {!isHoverMode && (
          <Button
            variant="ghost"
            size="icon"
            onClick={onToggle}
            className={cn(
              "text-sidebar-foreground hover:bg-sidebar-accent shrink-0",
              collapsed && !isMobile && "absolute -right-3 top-20 bg-sidebar border border-sidebar-border rounded-full shadow-md z-50 h-6 w-6"
            )}
          >
            {isMobile ? (
              <X className="w-5 h-5" />
            ) : (
              <CaretLeft className={cn("w-4 h-4 transition-transform duration-300", collapsed && "rotate-180")} weight="bold" />
            )}
          </Button>
        )}
      </div>

      {/* User Info – fades in after expansion */}
      <div
        className={cn(
          "border-b border-sidebar-border overflow-hidden transition-all duration-300",
          collapsed && !isMobile || searchQuery
            ? "max-h-0 opacity-0 py-0"
            : "max-h-24 opacity-100 p-4 delay-[140ms]"
        )}
      >
        <p className="font-medium text-sidebar-foreground truncate text-sm">{userName}</p>
        <div className="mt-2">
          <RoleBadge role={role} />
        </div>
      </div>

      {/* Navigation */}
      <nav className="flex-1 overflow-y-auto p-3 space-y-2 scrollbar-hide">
        {filteredNav.map((module) => (
          <SidebarAccordionItem
            key={module.title}
            module={module}
            isOpen={openModule === module.title}
            onToggle={() => setOpenModule(openModule === module.title ? null : module.title)}
            collapsed={collapsed && !isMobile}
            role={role}
          />
        ))}
      </nav>

      {/* Footer */}
      <div className="p-3 border-t border-sidebar-border shrink-0">
        <NavLink
          to="/"
          className={cn(
            "flex items-center gap-3 px-3 py-2.5 rounded-lg transition-colors group overflow-hidden",
            "text-sidebar-foreground hover:bg-destructive hover:text-destructive-foreground"
          )}
        >
          <SignOut className="w-5 h-5 shrink-0 group-hover:rotate-180 transition-transform duration-500" weight="bold" />
          <span
            className={cn(
              "text-sm font-medium whitespace-nowrap transition-all duration-200",
              collapsed && !isMobile
                ? "opacity-0 -translate-x-2 w-0"
                : "opacity-100 translate-x-0 delay-[130ms]"
            )}
          >
            Sign Out
          </span>
        </NavLink>
      </div>
    </aside>
  );
}

import React, { useState, useEffect } from 'react';
import { Bell, Check, Trash2, Info, AlertTriangle, CheckCircle2, XCircle, BellOff } from 'lucide-react';
import {
    Popover,
    PopoverContent,
    PopoverTrigger,
} from "@/components/ui/popover";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { ScrollArea } from "@/components/ui/scroll-area";
import { Separator } from "@/components/ui/separator";
import { notificationService, Notification } from '@/services/notificationService';
import { getSocket } from '@/lib/socket';
import { formatDistanceToNow } from 'date-fns';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';

import { useAuth } from '@/hooks/useAuth';

export const NotificationBell: React.FC = () => {
    const { user } = useAuth();
    const [notifications, setNotifications] = useState<Notification[]>([]);
    const [unreadCount, setUnreadCount] = useState(0);
    const [isOpen, setIsOpen] = useState(false);

    useEffect(() => {
        if (!user) return;

        fetchNotifications();

        // Socket listener for new notifications
        const socket = getSocket();

        // Join user-specific room for targeted notifications
        socket.emit('join_room', `user:${user.id}`);
        console.log(`NotificationBell: Joining room user:${user.id}`);

        socket.on('notification:new', (newNotification: Notification) => {
            setNotifications(prev => [newNotification, ...prev]);
            setUnreadCount(prev => prev + 1);
            toast.info(`${newNotification.title}: ${newNotification.message.substring(0, 50)}${newNotification.message.length > 50 ? '...' : ''}`, {
                action: {
                    label: 'View',
                    onClick: () => {
                        // Handle view logic if needed
                    }
                }
            });
        });

        return () => {
            socket.off('notification:new');
            socket.emit('leave_room', `user:${user.id}`);
        };
    }, [user?.id]);

    const fetchNotifications = async () => {
        try {
            const data = await notificationService.getNotifications();
            setNotifications(data);
            setUnreadCount(data.filter(n => !n.isRead).length);
        } catch (error) {
            console.error('Failed to fetch notifications', error);
        }
    };

    const handleMarkAsRead = async (id: string) => {
        try {
            await notificationService.markAsRead(id);
            setNotifications(prev => prev.map(n => n.id === id ? { ...n, isRead: true } : n));
            setUnreadCount(prev => Math.max(0, prev - 1));
        } catch (error) {
            toast.error('Failed to mark as read');
        }
    };

    const handleMarkAllAsRead = async () => {
        try {
            await notificationService.markAllAsRead();
            setNotifications(prev => prev.map(n => ({ ...n, isRead: true })));
            setUnreadCount(0);
            toast.success('All notifications marked as read');
        } catch (error) {
            toast.error('Failed to mark all as read');
        }
    };

    const handleDelete = async (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        try {
            await notificationService.deleteNotification(id);
            const deletedNotification = notifications.find(n => n.id === id);
            setNotifications(prev => prev.filter(n => n.id !== id));
            if (deletedNotification && !deletedNotification.isRead) {
                setUnreadCount(prev => Math.max(0, prev - 1));
            }
        } catch (error) {
            toast.error('Failed to delete notification');
        }
    };

    const getIcon = (type: string) => {
        switch (type) {
            case 'SUCCESS': return <CheckCircle2 className="w-4 h-4 text-green-500" />;
            case 'WARNING': return <AlertTriangle className="w-4 h-4 text-yellow-500" />;
            case 'ERROR': return <XCircle className="w-4 h-4 text-red-500" />;
            default: return <Info className="w-4 h-4 text-blue-500" />;
        }
    };

    return (
        <Popover open={isOpen} onOpenChange={setIsOpen}>
            <PopoverTrigger asChild>
                <Button variant="ghost" size="icon" className="relative hover:bg-primary/5">
                    <Bell className="w-5 h-5 text-gray-500" />
                    {unreadCount > 0 && (
                        <Badge variant="destructive" className="absolute -top-1 -right-1 px-1.5 py-0.5 text-[10px] min-w-[1.2rem] flex justify-center items-center h-4 bg-red-500 border-2 border-white">
                            {unreadCount > 9 ? '9+' : unreadCount}
                        </Badge>
                    )}
                </Button>
            </PopoverTrigger>
            <PopoverContent className="w-80 p-0 mr-4 mt-2" align="end">
                <div className="flex items-center justify-between p-4 border-b">
                    <h4 className="font-bold text-sm text-gray-900">Notifications</h4>
                    {unreadCount > 0 && (
                        <Button
                            variant="ghost"
                            size="sm"
                            onClick={handleMarkAllAsRead}
                            className="text-[10px] h-7 px-2 font-bold text-primary capitalize tracking-wider hover:bg-primary/5"
                        >
                            Mark all read
                        </Button>
                    )}
                </div>
                <ScrollArea className="h-[350px]">
                    {notifications.length === 0 ? (
                        <div className="flex flex-col items-center justify-center p-8 text-center space-y-3">
                            <div className="w-12 h-12 bg-gray-50 rounded-full flex items-center justify-center">
                                <BellOff className="w-6 h-6 text-gray-300" />
                            </div>
                            <div>
                                <p className="text-sm font-bold text-gray-900">All caught up!</p>
                                <p className="text-xs text-gray-400 mt-1">No notifications to show right now.</p>
                            </div>
                        </div>
                    ) : (
                        <div className="flex flex-col">
                            {notifications.map((notification) => (
                                <div
                                    key={notification.id}
                                    onClick={() => !notification.isRead && handleMarkAsRead(notification.id)}
                                    className={cn(
                                        "group flex items-start gap-3 p-4 hover:bg-gray-50/50 cursor-pointer transition-colors relative border-b last:border-0",
                                        !notification.isRead && "bg-blue-50/30"
                                    )}
                                >
                                    <div className="mt-0.5">
                                        {getIcon(notification.type)}
                                    </div>
                                    <div className="flex-1 min-w-0 pr-6">
                                        <div className="flex items-center justify-between gap-2">
                                            <p className={cn("text-sm font-bold truncate", !notification.isRead ? "text-gray-900" : "text-gray-600")}>
                                                {notification.title}
                                            </p>
                                            {!notification.isRead && (
                                                <div className="w-2 h-2 bg-blue-500 rounded-full shrink-0" />
                                            )}
                                        </div>
                                        <p className="text-xs text-gray-500 mt-1 line-clamp-2 leading-relaxed">
                                            {notification.message}
                                        </p>
                                        <p className="text-[10px] text-gray-400 mt-2 font-medium">
                                            {formatDistanceToNow(new Date(notification.createdAt), { addSuffix: true })}
                                        </p>
                                    </div>
                                    <Button
                                        variant="ghost"
                                        size="icon"
                                        onClick={(e) => handleDelete(e, notification.id)}
                                        className="absolute right-2 top-4 opacity-0 group-hover:opacity-100 h-8 w-8 text-gray-400 hover:text-red-500 transition-opacity"
                                    >
                                        <Trash2 className="w-3.5 h-3.5" />
                                    </Button>
                                </div>
                            ))}
                        </div>
                    )}
                </ScrollArea>
                <div className="p-2 border-t text-center">
                    <Button variant="ghost" className="w-full text-[10px] font-bold text-gray-500 capitalize tracking-widest h-8">
                        View All History
                    </Button>
                </div>
            </PopoverContent>
        </Popover>
    );
};

import React, { useEffect, useState } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import { Loader2, Download, Filter, Eye } from 'lucide-react';
import { surveyService, Survey, SurveyAnalytics, SurveyAnswer } from '@/services/surveyService';
import { toast } from 'sonner';
import { SurveyManagementView } from './SurveyManagementView';
import { useAuth } from '@/hooks/useAuth';
import { 
    Table, TableBody, TableCell, TableHead, TableHeader, TableRow 
} from '@/components/ui/table';
import { Badge } from '@/components/ui/badge';
import { format } from 'date-fns';

interface SurveyAnalyticsDashboardProps {
    survey: Survey;
    onRefreshSurvey?: () => void;
}

export const SurveyAnalyticsDashboard = ({ survey, onRefreshSurvey }: SurveyAnalyticsDashboardProps) => {
    const { user } = useAuth();
    const [analytics, setAnalytics] = useState<SurveyAnalytics | null>(null);
    const [rawResponses, setRawResponses] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedCampus, setSelectedCampus] = useState<string>('All');

    useEffect(() => {
        fetchAnalytics();
    }, [survey.id]);

    const fetchAnalytics = async () => {
        try {
            setLoading(true);
            const [data, rawData] = await Promise.all([
                surveyService.getAnalytics(survey.id),
                surveyService.getRawResponses(survey.id)
            ]);
            setAnalytics(data);
            setRawResponses(rawData || []);
        } catch (err) {
            console.error(err);
            toast.error('Failed to load analytics');
        } finally {
            setLoading(false);
        }
    };

    if (loading) return <div className="flex justify-center p-12"><Loader2 className="h-8 w-8 animate-spin" /></div>;
    if (!analytics) return <div>No data available</div>;

    // Transform data for charts
    const completionData = analytics.completionStats.filter(s => selectedCampus === 'All' || s.campus === selectedCampus);

    // Find the leadership support score question (Q11 or similar)
    const leadershipQuestion = analytics.questionStats.find(q => 
        q.question.toLowerCase().includes('leadership') || 
        q.question.toLowerCase().includes('support') || 
        q.question.toLowerCase().includes('observation feedback')
    ) || analytics.questionStats[0]; // Fallback to first available numeric question if not found

    // Refresh function for the management view
    const handleSurveyUpdate = () => {
        fetchAnalytics(); // Re-fetch data which includes questions
        if (onRefreshSurvey) onRefreshSurvey(); // Notify parent to refresh survey meta-data
    };

    const handleExport = async () => {
        try {
            toast.info('Generating CSV...');
            const blob = await surveyService.exportResults(survey.id);
            const url = window.URL.createObjectURL(new Blob([blob]));
            const link = document.createElement('a');
            link.href = url;
            link.setAttribute('download', `survey_results_${survey.id}.csv`);
            document.body.appendChild(link);
            link.click();
            link.parentNode?.removeChild(link);
            toast.success('Download started');
        } catch (error) {
            console.error(error);
            toast.error('Failed to export CSV');
        }
    };

    const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884d8'];

    return (
        <div className="space-y-6">
            <div className="flex justify-between items-center bg-card p-4 rounded-lg border shadow-sm">
                <div className="flex items-center gap-4">
                    <div>
                        <div className="flex items-center gap-3">
                            <h2 className="text-xl font-bold">Survey: {survey.title}</h2>
                            <span className={`px-2 py-0.5 rounded-full text-[10px] font-bold capitalize tracking-wider ${survey.isActive ? "bg-emerald-100 text-emerald-700 border border-emerald-200" : "bg-slate-100 text-slate-600 border border-slate-200"
                                }`}>
                                {survey.isActive ? "Active" : "Closed"}
                            </span>
                        </div>
                        <p className="text-sm text-muted-foreground">{survey.academicYear} Term {survey.term}</p>
                    </div>
                </div>
                <div className="flex gap-2">
                    <Select value={selectedCampus} onValueChange={setSelectedCampus}>
                        <SelectTrigger className="w-[180px]">
                            <Filter className="w-4 h-4 mr-2" />
                            <SelectValue placeholder="Filter Campus" />
                        </SelectTrigger>
                        <SelectContent>
                            <SelectItem value="All">All Campuses</SelectItem>
                            {analytics.completionStats.map(s => (
                                <SelectItem key={s.campus} value={s.campus}>{s.campus}</SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    {['ADMIN', 'SUPERADMIN'].includes(user?.role || '') && (
                        <>
                            <Button
                                variant={survey.isActive ? "outline" : "default"}
                                className={survey.isActive ? "text-red-600 border-red-200 hover:bg-red-50 font-bold" : "bg-emerald-600 hover:bg-emerald-700 text-white font-bold"}
                                onClick={async () => {
                                    const action = survey.isActive ? 'Deactivate' : 'Activate';
                                    if (confirm(`${action} this survey? All active teachers will be notified automatically.`)) {
                                        try {
                                            await surveyService.updateSurvey(survey.id, { isActive: !survey.isActive });
                                            toast.success(`Survey ${!survey.isActive ? 'activated' : 'closed'} & teachers notified!`);
                                            handleSurveyUpdate();
                                        } catch (error) {
                                            toast.error(`Failed to ${action.toLowerCase()} survey`);
                                        }
                                    }
                                }}
                            >
                                {survey.isActive ? "Close & Notify" : "Activate & Notify"}
                            </Button>
                        </>
                    )}

                    <Button variant="outline" onClick={handleExport}>
                        <Download className="w-4 h-4 mr-2" /> Export CSV
                    </Button>
                </div>
            </div>

            <Tabs defaultValue="analytics" className="w-full">
                <TabsList className="mb-4">
                    <TabsTrigger value="analytics">Analytics Dashboard</TabsTrigger>
                    <TabsTrigger value="responses">Raw Responses</TabsTrigger>
                    {['ADMIN', 'SUPERADMIN'].includes(user?.role || '') && (
                        <TabsTrigger value="questions">Manage Questions</TabsTrigger>
                    )}
                </TabsList>

                <TabsContent value="analytics" className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                        {/* Completion Rate Chart */}
                        <Card>
                            <CardHeader>
                                <CardTitle>Survey Completion Rate</CardTitle>
                                <CardDescription>Percentage of teachers who completed the survey</CardDescription>
                            </CardHeader>
                            <CardContent className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={completionData}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="campus" />
                                        <YAxis domain={[0, 100]} />
                                        <Tooltip />
                                        <Bar dataKey="rate" name="Completion %" fill="#8884d8">
                                            {completionData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                                            ))}
                                        </Bar>
                                    </BarChart>
                                </ResponsiveContainer>
                            </CardContent>
                        </Card>

                        {/* Leadership Support Score */}
                        <Card>
                            <CardHeader>
                                <CardTitle>Campus Leadership Support Score</CardTitle>
                                <CardDescription>Avg. rating indicating School Leadership Support (1-5)</CardDescription>
                            </CardHeader>
                            <CardContent className="h-[300px]">
                                {leadershipQuestion ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={leadershipQuestion.data.filter(d => selectedCampus === 'All' || d.campus === selectedCampus)}>
                                            <CartesianGrid strokeDasharray="3 3" />
                                            <XAxis dataKey="campus" />
                                            <YAxis domain={[0, 5]} />
                                            <Tooltip />
                                            <Bar dataKey="avg" name="Avg Score" fill="#82ca9d" />
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="flex items-center justify-center h-full text-muted-foreground">
                                        Metric not found
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    </div>

                    {/* All Metrics Table */}
                    <Card>
                        <CardHeader>
                            <CardTitle>Detailed Metrics by Question</CardTitle>
                        </CardHeader>
                        <CardContent>
                            <div className="space-y-6">
                                {analytics.questionStats.map((q, i) => (
                                    <div key={i} className="space-y-2">
                                        <h4 className="font-semibold text-sm">{q.question}</h4>
                                        <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 gap-4">
                                            {q.data.filter(d => selectedCampus === 'All' || d.campus === selectedCampus).map(d => (
                                                <div key={d.campus} className="bg-secondary/20 p-2 rounded text-xs">
                                                    <span className="font-medium">{d.campus}:</span> {d.avg.toFixed(1)}
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </CardContent>
                    </Card>
                </TabsContent>

                <TabsContent value="responses" className="space-y-6">
                    <Card>
                        <CardHeader>
                            <CardTitle>Survey Submissions</CardTitle>
                            <CardDescription>View all raw survey responses submitted across campuses.</CardDescription>
                        </CardHeader>
                        <CardContent className="overflow-x-auto">
                            <Table className="min-w-max">
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>Teacher</TableHead>
                                        <TableHead>Campus</TableHead>
                                        <TableHead>Date</TableHead>
                                        {survey.questions.map(q => (
                                            <TableHead key={q.id} className="max-w-[200px] truncate" title={q.questionText}>
                                                {q.questionText}
                                            </TableHead>
                                        ))}
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {rawResponses.filter(r => selectedCampus === 'All' || r.user?.campusId === selectedCampus).map(response => (
                                        <TableRow key={response.id}>
                                            <TableCell>
                                                {survey.isAnonymous ? (
                                                    <Badge variant="outline">Anonymous</Badge>
                                                ) : (
                                                    <div className="flex flex-col">
                                                        <span className="font-medium">{response.user?.fullName}</span>
                                                        <span className="text-xs text-muted-foreground">{response.user?.email}</span>
                                                    </div>
                                                )}
                                            </TableCell>
                                            <TableCell>{response.user?.campusId || 'Unassigned'}</TableCell>
                                            <TableCell>{response.submittedAt ? format(new Date(response.submittedAt), 'PPp') : ''}</TableCell>
                                            {survey.questions.map(q => {
                                                const ans = response.answers?.find((a: any) => a.question?.questionText === q.questionText);
                                                let ansText = "-";
                                                if (ans) {
                                                    ansText = ans.answerNumeric ? String(ans.answerNumeric) : (ans.answerText || ans.answerJson || "-");
                                                }
                                                return (
                                                    <TableCell key={q.id} className="max-w-[200px] truncate" title={ansText}>
                                                        {ansText}
                                                    </TableCell>
                                                );
                                            })}
                                        </TableRow>
                                    ))}
                                    {rawResponses.length === 0 && (
                                        <TableRow>
                                            <TableCell colSpan={survey.questions.length + 3} className="text-center py-8 text-muted-foreground">
                                                No responses retrieved yet.
                                            </TableCell>
                                        </TableRow>
                                    )}
                                </TableBody>
                            </Table>
                        </CardContent>
                    </Card>
                </TabsContent>

                {['ADMIN', 'SUPERADMIN'].includes(user?.role || '') && (
                    <TabsContent value="questions">
                        {/* Lazy load or just render */}
                        <SurveyManagementView survey={survey} onUpdate={handleSurveyUpdate} />
                    </TabsContent>
                )}
            </Tabs>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { ScrollToTop } from '@/components/ui/ScrollToTop';
import { useForm, FormProvider, useFormContext } from 'react-hook-form';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Label } from '@/components/ui/label';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';
import { Checkbox } from '@/components/ui/checkbox';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { toast } from 'sonner';
import { Loader2, ChevronRight, ChevronLeft, CheckCircle } from 'lucide-react';
import { surveyService, Survey, SurveyQuestion } from '@/services/surveyService';

interface SurveyWizardProps {
    survey: Survey;
    initialAnswers?: any[];
    onComplete: () => void;
}

const QuestionRenderer = ({ question }: { question: SurveyQuestion }) => {
    const { register, setValue, watch, formState: { errors } } = useFormContext();
    const answerKey = `answers.${question.id}`;
    const error = errors.answers?.[question.id];

    let options: any = null;
    try {
        options = question.options ? JSON.parse(question.options) : null;
    } catch (e) {
        console.error("Error parsing options", e);
    }

    const currentVal = watch(answerKey);

    // Common wrapper for error message
    const ErrorMsg = () => error ? <p className="text-red-500 text-sm mt-1">This field is required</p> : null;

    switch (question.questionType) {
        case 'short_text':
            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <Input
                        {...register(answerKey, { required: question.isRequired })}
                        placeholder="Your answer"
                    />
                    <ErrorMsg />
                </div>
            );
        case 'long_text':
            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <Textarea
                        {...register(answerKey, { required: question.isRequired })}
                        placeholder="Your answer"
                        className="min-h-[100px]"
                    />
                    <ErrorMsg />
                </div>
            );
        case 'multiple_choice':
            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <RadioGroup
                        onValueChange={(val) => setValue(answerKey, val, { shouldValidate: true })}
                        defaultValue={currentVal}
                    >
                        {Array.isArray(options) && options.map((opt: string) => (
                            <div key={opt} className="flex items-center space-x-2">
                                <RadioGroupItem value={opt} id={`${question.id}-${opt}`} />
                                <Label htmlFor={`${question.id}-${opt}`}>{opt}</Label>
                            </div>
                        ))}
                    </RadioGroup>
                    {/* Hidden input for validation */}
                    <input
                        type="hidden"
                        {...register(answerKey, { required: question.isRequired })}
                    />
                    <ErrorMsg />
                </div>
            );
        case 'multi_select':
            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <div className="grid grid-cols-1 gap-2">
                        {Array.isArray(options) && options.map((opt: string) => (
                            <div key={opt} className="flex items-center space-x-2">
                                <Checkbox
                                    id={`${question.id}-${opt}`}
                                    checked={Array.isArray(currentVal) && currentVal.includes(opt)}
                                    onCheckedChange={(checked) => {
                                        const current = Array.isArray(currentVal) ? currentVal : [];
                                        if (checked) {
                                            setValue(answerKey, [...current, opt], { shouldValidate: true });
                                        } else {
                                            setValue(answerKey, current.filter((v: string) => v !== opt), { shouldValidate: true });
                                        }
                                    }}
                                />
                                <Label htmlFor={`${question.id}-${opt}`}>{opt}</Label>
                            </div>
                        ))}
                    </div>
                    <input
                        type="hidden"
                        {...register(answerKey, { required: question.isRequired, validate: v => !question.isRequired || (v && v.length > 0) })}
                    />
                    <ErrorMsg />
                </div>
            );
        case 'rating_scale': {
            const min = options?.min || 1;
            const max = options?.max || 5;
            const range = Array.from({ length: max - min + 1 }, (_, i) => i + min);

            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <div className="flex items-center gap-4">
                        {options?.lowLabel && <span className="text-sm text-muted-foreground">{options.lowLabel}</span>}
                        <div className="flex gap-2">
                            {range.map((val) => (
                                <Button
                                    key={val}
                                    type="button"
                                    variant={currentVal == val ? "default" : "outline"}
                                    className="w-10 h-10 rounded-full p-0"
                                    onClick={() => setValue(answerKey, val, { shouldValidate: true })}
                                >
                                    {val}
                                </Button>
                            ))}
                        </div>
                        {options?.highLabel && <span className="text-sm text-muted-foreground">{options.highLabel}</span>}
                    </div>
                    <input
                        type="hidden"
                        {...register(answerKey, { required: question.isRequired })}
                    />
                    <ErrorMsg />
                </div>
            );
        }
        case 'yes_no':
            return (
                <div className="space-y-2 mb-6">
                    <Label>{question.questionText} {question.isRequired && <span className="text-red-500">*</span>}</Label>
                    <RadioGroup
                        onValueChange={(val) => setValue(answerKey, val, { shouldValidate: true })}
                        defaultValue={currentVal}
                        className="flex gap-4"
                    >
                        <div className="flex items-center space-x-2">
                            <RadioGroupItem value="Yes" id={`${question.id}-yes`} />
                            <Label htmlFor={`${question.id}-yes`}>Yes</Label>
                        </div>
                        <div className="flex items-center space-x-2">
                            <RadioGroupItem value="No" id={`${question.id}-no`} />
                            <Label htmlFor={`${question.id}-no`}>No</Label>
                        </div>
                    </RadioGroup>
                    <input
                        type="hidden"
                        {...register(answerKey, { required: question.isRequired })}
                    />
                    <ErrorMsg />
                </div>
            );

        default:
            return null;
    }
};

export const SurveyWizard = ({ survey, initialAnswers, onComplete }: SurveyWizardProps) => {
    const [currentPage, setCurrentPage] = useState(1);
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [isSaving, setIsSaving] = useState(false);
    const [lastSaved, setLastSaved] = useState<Date | null>(null);

    // Group questions by page
    const questionsByPage = survey.questions.reduce((acc, q) => {
        if (!acc[q.pageNumber]) acc[q.pageNumber] = [];
        acc[q.pageNumber].push(q);
        return acc;
    }, {} as Record<number, SurveyQuestion[]>);

    const totalPages = Object.keys(questionsByPage).length;

    const methods = useForm({
        defaultValues: {
            answers: initialAnswers?.reduce((acc, ans) => {
                // Convert backend answer format to form format
                if (ans.answerNumeric !== null && ans.answerNumeric !== undefined) acc[ans.questionId] = ans.answerNumeric;
                else if (ans.answerJson) {
                    try {
                        acc[ans.questionId] = JSON.parse(ans.answerJson);
                    } catch (e) {
                        acc[ans.questionId] = ans.answerJson;
                    }
                }
                else acc[ans.questionId] = ans.answerText || "";
                return acc;
            }, {}) || {}
        }
    });

    const { handleSubmit, trigger, getValues, watch, formState: { isDirty } } = methods;
    const allAnswers = watch("answers");

    // Initialize to the last progress page if there are answers
    useEffect(() => {
        if (initialAnswers && initialAnswers.length > 0) {
            // Find the highest page number that has an answer
            const answeredQuestionIds = initialAnswers.map(a => a.questionId);
            let maxPage = 1;

            survey.questions.forEach(q => {
                if (answeredQuestionIds.includes(q.id)) {
                    maxPage = Math.max(maxPage, q.pageNumber);
                }
            });

            // If the last page is completed, we might want to stay there or stay on step 1 if editing?
            // Actually, stay on step 1 is safer, or jump to the first incomplete page.
            // Let's just default to the "furthest" reached page or step 1.
            setCurrentPage(maxPage);
        }
    }, [survey.id]); // Only run on survey change/mount

    const formatAnswers = (answersData: any) => {
        return Object.keys(answersData).map(qId => {
            const val = answersData[qId];
            const q = survey.questions.find(q => q.id === qId);
            if (!q || val === undefined || val === null || val === "") return null;

            const ansObj: any = { questionId: qId };
            if (q.questionType === 'rating_scale') {
                ansObj.answerNumeric = Number(val);
            } else if (q.questionType === 'multi_select') {
                ansObj.answerJson = JSON.stringify(val);
            } else {
                ansObj.answerText = String(val);
            }
            return ansObj;
        }).filter(Boolean);
    };

    const saveDraft = async () => {
        const values = getValues();
        const formattedAnswers = formatAnswers(values.answers);

        if (formattedAnswers.length === 0) return;

        setIsSaving(true);
        try {
            await surveyService.submitSurvey(survey.id, formattedAnswers, false);
            setLastSaved(new Date());
        } catch (err) {
            console.error("Auto-save failed", err);
        } finally {
            setIsSaving(false);
        }
    };

    // Auto-save logic (debounced)
    useEffect(() => {
        if (!isDirty) return;

        const timer = setTimeout(() => {
            saveDraft();
        }, 3000);

        return () => clearTimeout(timer);
    }, [allAnswers, isDirty]);

    const handleNext = async () => {
        // Validate current page fields
        const currentPageQuestions = questionsByPage[currentPage] || [];
        const fieldsToValidate = currentPageQuestions.map(q => `answers.${q.id}`);
        const isValid = await trigger(fieldsToValidate as any);

        if (isValid) {
            // Save progress when moving forward
            saveDraft();
            setCurrentPage(prev => Math.min(prev + 1, totalPages));
            window.scrollTo(0, 0);
        }
    };

    const handlePrev = () => {
        setCurrentPage(prev => Math.max(prev - 1, 1));
        window.scrollTo(0, 0);
    };

    const onSubmit = async (data: any) => {
        setIsSubmitting(true);
        try {
            const formattedAnswers = formatAnswers(data.answers);
            await surveyService.submitSurvey(survey.id, formattedAnswers, true);
            toast.success("Survey submitted successfully!");
            onComplete();
        } catch (err) {
            console.error(err);
            toast.error("Failed to submit survey");
        } finally {
            setIsSubmitting(false);
        }
    };

    const progress = (currentPage / totalPages) * 100;

    return (
        <div className="max-w-5xl mx-auto py-4 px-0">
            <div className="space-y-6">
                <div className="px-6 flex flex-col md:flex-row md:items-end justify-between gap-4">
                    <div className="flex-1">
                        <div className="flex justify-between items-center mb-4 max-w-sm">
                            <div className="text-sm text-muted-foreground">Step {currentPage} of {totalPages}</div>
                            <div className="w-1/2 h-2 bg-secondary rounded-full overflow-hidden">
                                <div className="h-full bg-primary transition-all duration-300" style={{ width: `${progress}%` }} />
                            </div>
                        </div>
                        <h1 className="text-3xl font-bold text-foreground mb-2">{survey.title}</h1>
                        <p className="text-muted-foreground">{survey.description}</p>
                    </div>

                    <div className="flex items-center gap-2 mb-2 text-xs font-medium text-muted-foreground bg-muted/30 px-3 py-1.5 rounded-full border border-muted-foreground/10 self-start md:self-auto">
                        {isSaving ? (
                            <div className="flex items-center gap-1.5">
                                <Loader2 className="h-3 w-3 animate-spin" />
                                <span>Saving draft...</span>
                            </div>
                        ) : lastSaved ? (
                            <div className="flex items-center gap-1.5 text-success">
                                <CheckCircle className="h-3 w-3" />
                                <span>Draft saved at {lastSaved.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
                            </div>
                        ) : (
                            <span>All changes auto-saved</span>
                        )}
                    </div>
                </div>
                <div className="bg-white/50 backdrop-blur-sm rounded-3xl p-6 md:p-10 border shadow-sm">
                    <FormProvider {...methods}>
                        <form onSubmit={handleSubmit(onSubmit)}>
                            <div className="mt-4">
                                {questionsByPage[currentPage]?.map(q => (
                                    <QuestionRenderer key={q.id} question={q} />
                                ))}
                            </div>

                            <div className="flex justify-between mt-8 pt-4 border-t">
                                <Button
                                    type="button"
                                    variant="outline"
                                    onClick={handlePrev}
                                    disabled={currentPage === 1 || isSubmitting}
                                >
                                    <ChevronLeft className="mr-2 h-4 w-4" /> Previous
                                </Button>

                                {currentPage < totalPages ? (
                                    <Button
                                        type="button"
                                        onClick={handleNext}
                                        disabled={isSubmitting}
                                    >
                                        Next <ChevronRight className="ml-2 h-4 w-4" />
                                    </Button>
                                ) : (
                                    <Button
                                        type="submit"
                                        disabled={isSubmitting}
                                    >
                                        {isSubmitting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                                        Submit Survey
                                    </Button>
                                )}
                            </div>
                        </form>
                    </FormProvider>
                </div>
            </div>
            <ScrollToTop />
        </div>
    );
};

