export function CreateMeetingForm() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [allUsers, setAllUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(false);
    const [fetching, setFetching] = useState(false);

    const [formData, setFormData] = useState({
        title: '',
        meetingType: '',
        description: '',
        meetingDate: '',
        startTime: '',
        endTime: '',
        mode: 'Online' as 'Online' | 'Offline',
        locationLink: '',
        attendees: [] as string[]
    });

    const { isSaving } = useAutoSave({
        data: formData,
        onSave: async () => {}, // LocalStorage only for now
        enabled: !!formData.title,
        localStorageKey: `pdi_meeting_draft_${id || 'new'}`
    });

    useEffect(() => {
        fetchUsers();
        if (id) {
            fetchMeetingDetails();
        }
    }, [id]);

    const fetchMeetingDetails = async () => {
        try {
            setFetching(true);
            const meeting = await meetingService.getMeetingById(id!);
            setFormData({
                title: meeting.title,
                meetingType: meeting.meetingType,
                description: meeting.description || '',
                meetingDate: format(new Date(meeting.meetingDate), 'yyyy-MM-dd'),
                startTime: meeting.startTime,
                endTime: meeting.endTime,
                mode: meeting.mode as any,
                locationLink: meeting.locationLink || '',
                attendees: meeting.attendees?.map((a: any) => a.userId) || []
            });
        } catch (error) {
            console.error('Failed to fetch meeting details', error);
            toast.error('Failed to load meeting details');
        } finally {
            setFetching(false);
        }
    };

    const fetchUsers = async () => {
        try {
            const users = await userService.getAllUsers();
            setAllUsers(users);
        } catch (error) {
            console.error('Failed to fetch users', error);
        }
    };

    const handleInviteToggle = (userId: string) => {
        setFormData(prev => ({
            ...prev,
            attendees: prev.attendees.includes(userId)
                ? prev.attendees.filter(id => id !== userId)
                : [...prev.attendees, userId]
        }));
    };

