import React, { useState, useEffect } from 'react';
import { learningFestivalService, LearningFestival, LearningFestivalApplication } from '@/services/learningFestivalService';
import { analyticsService } from '@/services/analyticsService';
import { useAuth } from '@/hooks/useAuth';

import { Role } from '@/components/RoleBadge';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { PageHeader } from '@/components/layout/PageHeader';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter, DialogDescription } from '@/components/ui/dialog';
import { Search, Filter, CheckCircle2, XCircle, Award, Target, FileText, Download, ArrowLeft, BookOpen, TrendingUp, UserCircle, Users } from 'lucide-react';
import { format } from 'date-fns';
import { toast } from 'sonner';
import { CreateFestivalModal } from './CreateFestivalModal';

export function FestivalManagementDashboard() {
    const { user } = useAuth();
    const role = user?.role || 'TEACHER';

    const [festivals, setFestivals] = useState<LearningFestival[]>([]);
    const [applications, setApplications] = useState<LearningFestivalApplication[]>([]);
    const [loading, setLoading] = useState(true);
    const [isCreateModalOpen, setIsCreateModalOpen] = useState(false);

    const [selectedFestival, setSelectedFestival] = useState<string>('all');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [searchQuery, setSearchQuery] = useState('');

    const [selectedApp, setSelectedApp] = useState<LearningFestivalApplication | null>(null);
    const [feedback, setFeedback] = useState('');

    const [activeTab, setActiveTab] = useState<'festival' | 'self-paced'>('festival');
    const [engagementSummary, setEngagementSummary] = useState<any>(null);
    const [teachersStats, setTeachersStats] = useState<any[]>([]);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLoading(true);
        try {
            const [fests, apps, engagementData] = await Promise.all([
                learningFestivalService.getFestivals(),
                learningFestivalService.getApplications(),
                analyticsService.getCampusEngagement()
            ]);
            setFestivals(fests);
            setApplications(apps);
            setEngagementSummary(engagementData.summary);
            setTeachersStats(engagementData.teachers);

            if (fests.length > 0 && selectedFestival === 'all') {
                setSelectedFestival(fests[0].id);
            }
        } catch (error) {
            console.error(error);
            toast.error("Failed to load festival data.");
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateStatus = async (status: string) => {
        if (!selectedApp) return;
        try {
            const updated = await learningFestivalService.updateApplicationStatus(selectedApp.id, {
                status,
                feedback
            });
            setApplications(prev => prev.map(a => a.id === updated.id ? updated : a));
            toast.success(`Application marked as ${status}`);
            setSelectedApp(null);
            setFeedback('');
        } catch (error) {
            console.error(error);
            toast.error("Failed to update status");
        }
    };

    const filteredApps = applications.filter(app => {
        const matchFest = selectedFestival === 'all' || app.festivalId === selectedFestival;
        const matchStatus = statusFilter === 'all' || app.status === statusFilter;
        const matchSearch = (app.user?.fullName || '').toLowerCase().includes(searchQuery.toLowerCase()) ||
            (app.user?.email || '').toLowerCase().includes(searchQuery.toLowerCase());
        return matchFest && matchStatus && matchSearch;
    });

    // Counts for stat cards
    const totalApps = filteredApps.length;
    const shortlistedCount = filteredApps.filter(a => a.status === 'Shortlisted').length;
    const confirmedCount = filteredApps.filter(a => a.status === 'Confirmed').length;

    // Check if user has permission to manage festival events globally
    const isAdminOrMgmt = ['ADMIN', 'SUPERADMIN', 'MANAGEMENT'].includes(role);

    // Group applications by campus
    const appsByCampus = filteredApps.reduce((acc, app) => {
        const campus = app.user?.campusId || 'Main Campus';
        if (!acc[campus]) {
            acc[campus] = { total: 0, shortlisted: 0 };
        }
        acc[campus].total += 1;
        if (app.status === 'Shortlisted' || app.status === 'Confirmed') {
            acc[campus].shortlisted += 1;
        }
        return acc;
    }, {} as Record<string, { total: number; shortlisted: number }>);

    // Self-paced learning filtering
    const [roleFilter, setRoleFilter] = useState('all');
    const filteredTeachers = (teachersStats || []).filter(t => {
        const matchSearch = t.name.toLowerCase().includes(searchQuery.toLowerCase()) || (t.email || '').toLowerCase().includes(searchQuery.toLowerCase());
        const matchRole = roleFilter === 'all' || t.role === roleFilter;
        return matchSearch && matchRole;
    }).sort((a, b) => b.engagementPercent - a.engagementPercent);

    const handleExportCSV = () => {
        if (filteredApps.length === 0) {
            toast.error("No applications to export.");
            return;
        }

        const headers = ['Applicant Name', 'Email', 'Campus', 'Festival', 'Strand', 'Status', 'Submitted At'];

        const csvRows = filteredApps.map(app => [
            `"${app.user?.fullName || ''}"`,
            `"${app.user?.email || ''}"`,
            `"${app.user?.campusId || ''}"`,
            `"${festivals.find(f => f.id === app.festivalId)?.name || app.festivalId}"`,
            `"${app.preferredStrand || ''}"`,
            `"${app.status || ''}"`,
            `"${app.appliedAt ? format(new Date(app.appliedAt), 'MMM dd, yyyy') : ''}"`
        ]);

        const csvContent = [headers.join(','), ...csvRows.map(row => row.join(','))].join('\n');

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.setAttribute('href', url);
        link.setAttribute('download', `learning_festival_applications_${format(new Date(), 'yyyy-MM-dd')}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        URL.revokeObjectURL(url);

        toast.success("Exported successfuly!");
    };

    return (
        <div className="space-y-6 animate-in fade-in duration-500">

            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <PageHeader
                    title="Learning Festival Tracker"
                    subtitle={isAdminOrMgmt ? "Strategic overview and application management across all campuses." : `Manage learning festival applications for ${user?.campusId || 'your campus'}.`}
                />

                <div className="flex gap-2">
                    <Button variant="outline" className="gap-2" onClick={handleExportCSV}>
                        <Download className="w-4 h-4" />
                        Export CSV
                    </Button>
                    {isAdminOrMgmt && (
                        <Button
                            className="bg-primary hover:bg-primary/90 gap-2"
                            onClick={() => setIsCreateModalOpen(true)}
                        >
                            <Award className="w-4 h-4" />
                            Create Festival
                        </Button>
                    )}
                </div>
            </div>

            {/* Navigation Tabs */}
            <div className="flex overflow-x-auto gap-2 p-1 bg-muted/50 rounded-lg w-fit">
                <Button
                    variant={activeTab === 'festival' ? 'default' : 'ghost'}
                    onClick={() => setActiveTab('festival')}
                    className="gap-2 rounded-md"
                >
                    <Award className="w-4 h-4" />
                    Learning Festival
                </Button>
                <Button
                    variant={activeTab === 'self-paced' ? 'default' : 'ghost'}
                    onClick={() => setActiveTab('self-paced')}
                    className="gap-2 rounded-md"
                >
                    <BookOpen className="w-4 h-4" />
                    Self-Paced Learning
                </Button>
            </div>

            {activeTab === 'festival' && (
                <>
                    {/* KPI Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <Card className="bg-gradient-to-br from-blue-50 to-white   shadow-sm">
                            <CardContent className="p-6">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <p className="text-sm font-bold text-gray-500 capitalize">Total Applications</p>
                                        <h3 className="text-3xl font-black text-blue-900 mt-2">{totalApps}</h3>
                                    </div>
                                    <div className="p-3 bg-blue-100/50 rounded-xl text-blue-600">
                                        <FileText className="w-6 h-6" />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="bg-gradient-to-br from-green-50 to-white   shadow-sm">
                            <CardContent className="p-6">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <p className="text-sm font-bold text-gray-500 capitalize">Shortlisted</p>
                                        <h3 className="text-3xl font-black text-green-700 mt-2">{shortlistedCount}</h3>
                                    </div>
                                    <div className="p-3 bg-green-100/50 rounded-xl text-green-600">
                                        <Target className="w-6 h-6" />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>

                        <Card className="bg-gradient-to-br from-emerald-50 to-white   shadow-sm">
                            <CardContent className="p-6">
                                <div className="flex justify-between items-start">
                                    <div>
                                        <p className="text-sm font-bold text-gray-500 capitalize">Confirmed Participants</p>
                                        <h3 className="text-3xl font-black text-emerald-800 mt-2">{confirmedCount}</h3>
                                    </div>
                                    <div className="p-3 bg-emerald-100/50 rounded-xl text-emerald-600">
                                        <CheckCircle2 className="w-6 h-6" />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Campus-wise Festival Analytics (For Admins/Mgmt) */}
                    {isAdminOrMgmt && Object.keys(appsByCampus).length > 0 && (
                        <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-4 gap-4 mt-8">
                            {Object.entries(appsByCampus).map(([campus, stats]) => (
                                <Card key={campus} className="shadow-sm border-gray-100 bg-white hover:border-blue-100 transition-colors">
                                    <CardHeader className="pb-2">
                                        <CardTitle className="text-sm font-bold text-gray-500 capitalize flex items-center gap-2">
                                            <Target className="w-4 h-4 text-blue-500" />
                                            {campus}
                                        </CardTitle>
                                    </CardHeader>
                                    <CardContent>
                                        <div className="space-y-3">
                                            <div className="flex justify-between items-center bg-blue-50/50 p-2 rounded-lg">
                                                <span className="text-xs font-medium text-gray-600">Total Apps Received</span>
                                                <span className="font-bold text-blue-700">{stats.total}</span>
                                            </div>
                                            <div className="flex justify-between items-center bg-green-50/50 p-2 rounded-lg">
                                                <span className="text-xs font-medium text-gray-600">Shortlisted Apps</span>
                                                <span className="font-bold text-green-700">{stats.shortlisted}</span>
                                            </div>
                                        </div>
                                    </CardContent>
                                </Card>
                            ))}
                        </div>
                    )}

                    {/* Filters */}
                    <div className="bg-white p-4 rounded-xl shadow-sm border flex flex-col md:flex-row gap-4 mt-6">
                        <div className="flex-1 relative">
                            <Search className="w-4 h-4 absolute left-3 top-3 text-gray-400" />
                            <Input
                                placeholder="Search by teacher name or email..."
                                className="pl-9 bg-gray-50 border-transparent focus-visible:ring-primary/20"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>

                        <Select value={selectedFestival} onValueChange={setSelectedFestival}>
                            <SelectTrigger className="w-full md:w-[250px] bg-white">
                                <SelectValue placeholder="Select Festival" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Festivals</SelectItem>
                                {festivals.map(f => (
                                    <SelectItem key={f.id} value={f.id}>{f.name}</SelectItem>
                                ))}
                            </SelectContent>
                        </Select>

                        <Select value={statusFilter} onValueChange={setStatusFilter}>
                            <SelectTrigger className="w-full md:w-[180px] bg-white">
                                <SelectValue placeholder="Filter by Status" />
                            </SelectTrigger>
                            <SelectContent>
                                <SelectItem value="all">All Statuses</SelectItem>
                                <SelectItem value="Submitted">Submitted</SelectItem>
                                <SelectItem value="Under Review">Under Review</SelectItem>
                                <SelectItem value="Shortlisted">Shortlisted</SelectItem>
                                <SelectItem value="Confirmed">Confirmed</SelectItem>
                                <SelectItem value="Rejected">Rejected</SelectItem>
                            </SelectContent>
                        </Select>
                    </div>

                    {/* Data Table */}
                    <Card className="shadow-sm border-gray-100">
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="bg-gray-50/80 text-gray-600 font-medium border-b border-gray-100">
                                    <tr>
                                        <th className="px-6 py-4">Applicant Profile</th>
                                        {isAdminOrMgmt && <th className="px-6 py-4">Campus</th>}
                                        <th className="px-6 py-4">Selected Strand</th>
                                        <th className="px-6 py-4">Applied Date</th>
                                        <th className="px-6 py-4">Status</th>
                                        <th className="px-6 py-4 text-right">Action</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-50">
                                    {loading ? (
                                        <tr>
                                            <td colSpan={6} className="text-center py-12 text-gray-400">Loading applications...</td>
                                        </tr>
                                    ) : filteredApps.length === 0 ? (
                                        <tr>
                                            <td colSpan={6} className="text-center py-12 text-gray-400">
                                                No applications match the given criteria.
                                            </td>
                                        </tr>
                                    ) : (
                                        filteredApps.map(app => (
                                            <tr key={app.id} className="hover:bg-gray-50/50 transition-colors">
                                                <td className="px-6 py-4">
                                                    <div className="font-bold text-gray-900">{app.user?.fullName}</div>
                                                    <div className="text-xs text-gray-500">{app.user?.email}</div>
                                                </td>
                                                {isAdminOrMgmt && (
                                                    <td className="px-6 py-4 text-gray-600 font-medium">
                                                        {app.user?.campusId || 'Main Campus'}
                                                    </td>
                                                )}
                                                <td className="px-6 py-4">
                                                    <Badge variant="outline" className="bg-blue-50 text-blue-700 border-blue-100">
                                                        {app.preferredStrand || 'N/A'}
                                                    </Badge>
                                                </td>
                                                <td className="px-6 py-4 text-gray-500">
                                                    {app.appliedAt ? format(new Date(app.appliedAt), 'MMM dd, yyyy') : 'N/A'}
                                                </td>
                                                <td className="px-6 py-4">
                                                    <Badge variant={
                                                        app.status === 'Shortlisted' ? 'default' :
                                                            app.status === 'Confirmed' ? 'default' :
                                                                app.status === 'Rejected' ? 'destructive' :
                                                                    app.status === 'Under Review' ? 'secondary' : 'outline'
                                                    } className={
                                                        app.status === 'Confirmed' ? 'bg-emerald-600' :
                                                            app.status === 'Shortlisted' ? 'bg-green-600' : ''
                                                    }>
                                                        {app.status}
                                                    </Badge>
                                                </td>
                                                <td className="px-6 py-4 text-right">
                                                    <Button variant="ghost" size="sm" onClick={() => setSelectedApp(app)}>
                                                        Review
                                                    </Button>
                                                </td>
                                            </tr>
                                        ))
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </Card>

                    {/* Review Dialog */}
                    {selectedApp && (
                        <Dialog open={!!selectedApp} onOpenChange={(open) => !open && setSelectedApp(null)}>
                            <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
                                <DialogHeader>
                                    <DialogTitle>Review Application</DialogTitle>
                                    <DialogDescription>
                                        Applicant: <strong>{selectedApp.user?.fullName}</strong> ({selectedApp.user?.campusId})
                                    </DialogDescription>
                                </DialogHeader>

                                <div className="space-y-6 py-4">
                                    <div className="space-y-2">
                                        <p className="text-sm font-bold text-gray-500 capitalize">Preferred Strand</p>
                                        <p className="font-medium text-gray-900">{selectedApp.preferredStrand || 'None Selected'}</p>
                                    </div>
                                    <div className="space-y-2">
                                        <p className="text-sm font-bold text-gray-500 capitalize">Statement of Purpose</p>
                                        <div className="p-4 bg-gray-50 rounded-xl text-gray-800 text-sm leading-relaxed border">
                                            {selectedApp.statementOfPurpose}
                                        </div>
                                    </div>
                                    {selectedApp.relevantExperience && (
                                        <div className="space-y-2">
                                            <p className="text-sm font-bold text-gray-500 capitalize">Relevant Experience</p>
                                            <div className="p-4 bg-gray-50 rounded-xl text-gray-800 text-sm leading-relaxed border">
                                                {selectedApp.relevantExperience}
                                            </div>
                                        </div>
                                    )}

                                    <div className="space-y-3 pt-4 border-t">
                                        <label className="text-sm font-bold text-gray-900">Reviewer Feedback (Optional)</label>
                                        <Textarea
                                            placeholder="Add notes for the teacher or internal review..."
                                            value={feedback}
                                            onChange={(e) => setFeedback(e.target.value)}
                                            rows={3}
                                        />
                                    </div>
                                </div>

                                <DialogFooter className="flex-col sm:flex-row gap-2 mt-4">
                                    <Button variant="outline" className="sm:mr-auto" onClick={() => setSelectedApp(null)}>
                                        Cancel
                                    </Button>
                                    <Button variant="destructive" onClick={() => handleUpdateStatus('Rejected')}>
                                        <XCircle className="w-4 h-4 mr-2" />
                                        Reject
                                    </Button>
                                    {(role === 'ADMIN' || role === 'SUPERADMIN' || role === 'MANAGEMENT') && selectedApp.status === 'Shortlisted' ? (
                                        <Button className="bg-emerald-600 hover:bg-emerald-700" onClick={() => handleUpdateStatus('Confirmed')}>
                                            <CheckCircle2 className="w-4 h-4 mr-2" />
                                            Confirm Selection
                                        </Button>
                                    ) : (
                                        <Button className="bg-primary hover:bg-primary/90" onClick={() => handleUpdateStatus('Shortlisted')}>
                                            <CheckCircle2 className="w-4 h-4 mr-2" />
                                            Shortlist
                                        </Button>
                                    )}
                                </DialogFooter>
                            </DialogContent>
                        </Dialog>
                    )}
                </>
            )}

            {activeTab === 'self-paced' && (
                <div className="space-y-6">
                    {/* Engagement Overview KPI Cards */}
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                        <Card className="bg-gradient-to-br from-indigo-50 to-white   shadow-sm">
                            <CardHeader className="pb-2">
                                <CardTitle className="text-sm font-semibold text-gray-500 capitalize">System Avg Engagement</CardTitle>
                            </CardHeader>
                            <CardContent>
                                <div className="text-3xl font-black text-indigo-700">
                                    {engagementSummary?.campusAverageEngagement || 0}%
                                </div>
                                <p className="text-sm text-gray-500 mt-1">Average course completion rate</p>
                            </CardContent>
                        </Card>

                        <Card className="bg-gradient-to-br from-blue-50 to-white   shadow-sm">
                            <CardHeader className="pb-2">
                                <CardTitle className="text-sm font-semibold text-gray-500 capitalize">Enrolled Teachers</CardTitle>
                            </CardHeader>
                            <CardContent>
                                <div className="text-3xl font-black text-blue-700">
                                    {engagementSummary?.totalTeachersEnrolled || 0}
                                </div>
                                <p className="text-sm text-gray-500 mt-1">Teachers tracking self-paced goals</p>
                            </CardContent>
                        </Card>

                        <Card className="bg-gradient-to-br from-green-50 to-white   shadow-sm">
                            <CardHeader className="pb-2">
                                <CardTitle className="text-sm font-semibold text-gray-500 capitalize">Active Participants</CardTitle>
                            </CardHeader>
                            <CardContent>
                                <div className="text-3xl font-black text-green-700">
                                    {engagementSummary?.totalTeachersActive || 0}
                                </div>
                                <p className="text-sm text-gray-500 mt-1">Recently active on platform</p>
                            </CardContent>
                        </Card>
                    </div>

                    {/* Filters for Self-Paced */}
                    <div className="bg-white p-4 rounded-xl shadow-sm border flex flex-col md:flex-row gap-4">
                        <div className="flex-1 relative">
                            <Search className="w-4 h-4 absolute left-3 top-3 text-gray-400" />
                            <Input
                                placeholder="Search teachers..."
                                className="pl-9 bg-gray-50/50"
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                            />
                        </div>
                        <div className="flex gap-2">
                            <div className="relative">
                                <Filter className="w-4 h-4 absolute left-3 top-3 text-gray-400" />
                                <select
                                    className="pl-9 h-10 w-[180px] rounded-md border border-input bg-white px-3 py-2 text-sm ring-offset-background focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
                                    value={roleFilter}
                                    onChange={(e) => setRoleFilter(e.target.value)}
                                >
                                    <option value="all">All Roles</option>
                                    <option value="Primary Teacher">Primary</option>
                                    <option value="Middle School Teacher">Middle School</option>
                                    <option value="Senior School Teacher">Senior School</option>
                                </select>
                            </div>
                        </div>
                    </div>

                    {/* Teachers Engagement Table */}
                    <Card className="  shadow-sm overflow-hidden">
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="bg-gray-50/80 text-gray-500 capitalize text-xs font-semibold border-b">
                                    <tr>
                                        <th className="px-6 py-4">Teacher Profile</th>
                                        {isAdminOrMgmt && <th className="px-6 py-4">Campus</th>}
                                        <th className="px-6 py-4">Courses Enrolled</th>
                                        <th className="px-6 py-4">Completed</th>
                                        <th className="px-6 py-4">Engagement %</th>
                                        <th className="px-6 py-4 text-right">Activity</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-gray-100">
                                    {filteredTeachers.map((teacher: any) => (
                                        <tr key={teacher.id} className="hover:bg-gray-50 transition-colors">
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-10 h-10 rounded-full bg-indigo-100 flex items-center justify-center text-indigo-700 font-bold border border-indigo-200">
                                                        {teacher.name.charAt(0)}
                                                    </div>
                                                    <div>
                                                        <p className="font-semibold text-gray-900">{teacher.name}</p>
                                                        <p className="text-xs text-gray-500 flex items-center gap-1">
                                                            <UserCircle className="w-3 h-3" />
                                                            {teacher.role || 'Teacher'}
                                                        </p>
                                                    </div>
                                                </div>
                                            </td>
                                            {isAdminOrMgmt && (
                                                <td className="px-6 py-4 text-gray-600 font-medium">
                                                    {teacher.campus || 'N/A'}
                                                </td>
                                            )}
                                            <td className="px-6 py-4 text-gray-600 font-mono">
                                                {teacher.coursesEnrolled}
                                            </td>
                                            <td className="px-6 py-4 text-gray-600 font-mono">
                                                {teacher.coursesCompleted}
                                            </td>
                                            <td className="px-6 py-4">
                                                <div className="flex items-center gap-3">
                                                    <div className="w-full bg-gray-100 rounded-full h-2 max-w-[100px]">
                                                        <div
                                                            className={`h-2 rounded-full ${teacher.engagementPercent >= 75 ? 'bg-green-500' :
                                                                teacher.engagementPercent >= 40 ? 'bg-yellow-500' : 'bg-red-500'
                                                                }`}
                                                            style={{ width: `${Math.min(teacher.engagementPercent, 100)}%` }}
                                                        ></div>
                                                    </div>
                                                    <span className="font-bold text-gray-700 font-mono">{teacher.engagementPercent}%</span>
                                                </div>
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <Badge variant={teacher.isActive ? 'default' : 'secondary'} className={teacher.isActive ? 'bg-emerald-100 text-emerald-800' : ''}>
                                                    {teacher.isActive ? 'Active' : 'Inactive'}
                                                </Badge>
                                            </td>
                                        </tr>
                                    ))}
                                    {filteredTeachers.length === 0 && (
                                        <tr>
                                            <td colSpan={isAdminOrMgmt ? 6 : 5} className="px-6 py-12 text-center text-gray-500">
                                                <div className="flex flex-col items-center justify-center gap-3">
                                                    <BookOpen className="w-12 h-12 text-gray-300" />
                                                    <p className="text-lg font-medium">No engagement data found</p>
                                                    <p className="text-sm">Adjust your filters to see more results.</p>
                                                </div>
                                            </td>
                                        </tr>
                                    )}
                                </tbody>
                            </table>
                        </div>
                    </Card>
                </div>
            )}

            <CreateFestivalModal
                isOpen={isCreateModalOpen}
                onOpenChange={setIsCreateModalOpen}
                onSuccess={fetchData}
            />
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
    ChevronLeft,
    Calendar,
    Clock,
    MapPin,
    Video,
    Users,
    FileText,
    CheckCircle2,
    Link as LinkIcon,
    User,
    Info,
    History,
    ArrowLeft,
    Share2,
    PenTool,
    PlusCircle,
    Play,
    FileCheck,
    Target,
    ClipboardList,
    Download,
    Paperclip
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { PageHeader } from '@/components/layout/PageHeader';
import { meetingService, Meeting } from '@/services/meetingService';
import { useAuth } from '@/hooks/useAuth';
import { format } from 'date-fns';
import { Role } from '@/components/RoleBadge';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';

export function MeetingDetailsView() {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const { user } = useAuth();
    const [meeting, setMeeting] = useState<Meeting | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        if (id) {
            fetchMeetingDetails();
        }
    }, [id]);

    const fetchMeetingDetails = async () => {
        try {
            setLoading(true);
            const data = await meetingService.getMeetingById(id!);
            setMeeting(data);
        } catch (error) {
            console.error('Failed to fetch meeting details', error);
            toast.error('Failed to load meeting details');
        } finally {
            setLoading(false);
        }
    };

    const handleUpdateStatus = async (status: string) => {
        try {
            // Check if meetingService has updateStatus, else fallback to completeMeeting if status is COMPLETED
            if (status === "Completed") {
                await meetingService.completeMeeting(id!);
            }
            toast.success(`Meeting status updated to ${status}`);
            fetchMeetingDetails();
        } catch (error) {
            console.error('Failed to update status', error);
            toast.error('Failed to update meeting status');
        }
    };

    const getStatusBadge = (status: string) => {
        const baseClass = "px-3 py-1 rounded-full font-black text-[10px] tracking-widest uppercase border-none text-white shadow-sm";
        switch (status) {
            case 'Completed':
                return <Badge className={cn(baseClass, "bg-slate-600")}>Completed</Badge>;
            case 'Ongoing':
                return <Badge className={cn(baseClass, "bg-emerald-600")}>Ongoing</Badge>;
            case 'Scheduled':
                return <Badge className={cn(baseClass, "bg-blue-600")}>Scheduled</Badge>;
            case 'Draft':
                return <Badge className={cn(baseClass, "bg-amber-500")}>Draft</Badge>;
            default:
                return <Badge className={cn(baseClass, "bg-slate-400")}>{status}</Badge>;
        }
    };

    if (loading) {
        return (
            <div className="flex items-center justify-center min-h-[60vh]">
                <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
            </div>
        );
    }

    if (!meeting) {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center">
                <History className="w-16 h-16 text-gray-300 mb-4" />
                <h2 className="text-2xl font-bold text-gray-900">Meeting Not Found</h2>
                <p className="text-gray-500 mt-2">The meeting you are looking for does not exist or has been removed.</p>
                <Button onClick={() => navigate('/meetings')} className="mt-6">
                    Back to Meetings
                </Button>
            </div>
        );
    }

    const isCreator = meeting.createdById === user?.id;
    const isAdmin = user?.role === 'ADMIN' || user?.role === 'SUPERADMIN';
    const canManage = isCreator || isAdmin;

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex flex-col gap-1">
                    <h1 className="text-3xl font-bold tracking-tight">{meeting.title}</h1>
                    <div className="flex flex-wrap items-center gap-3 text-sm text-muted-foreground">
                        <span className="flex items-center gap-1.5 bg-muted/50 px-2 py-1 rounded">
                            <Calendar className="w-4 h-4" />
                            {meeting.meetingDate ? format(new Date(meeting.meetingDate), 'EEEE, MMMM do, yyyy') : (meeting as any).date}
                        </span>
                        <span className="flex items-center gap-1.5 bg-muted/50 px-2 py-1 rounded">
                            <Clock className="w-4 h-4" />
                            {meeting.startTime} - {meeting.endTime}
                        </span>
                        <span className="flex items-center gap-1.5 bg-muted/50 px-2 py-1 rounded">
                            <MapPin className="w-4 h-4" />
                            {meeting.locationLink || (meeting.mode === 'Online' ? 'Online' : 'Main Office')}
                        </span>
                        {getStatusBadge(meeting.status)}
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    <Button variant="outline" size="sm" onClick={() => navigate(-1)} className="gap-2">
                        <ArrowLeft className="w-4 h-4" />
                        Back
                    </Button>
                    <div className="flex items-center gap-2">
                        <Button variant="outline" size="sm" className="gap-2" onClick={() => {
                            navigator.clipboard.writeText(window.location.href);
                            toast.success("Meeting link copied to clipboard!");
                        }}>
                            <Share2 className="w-4 h-4" />
                            Share Link
                        </Button>
                        {isCreator && (
                            <Button size="sm" onClick={() => navigate(`/meetings/edit/${meeting.id}`)} className="gap-2">
                                <PenTool className="w-4 h-4" />
                                Edit Meeting
                            </Button>
                        )}
                    </div>
                </div>
            </div>

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                {/* Main Content */}
                <div className="lg:col-span-2 space-y-8">
                    {/* Meeting Content */}
                    <Card className="border-none shadow-xl shadow-slate-200/50">
                        <CardHeader className="border-b bg-slate-50/50">
                            <CardTitle className="text-xl">Agenda & Description</CardTitle>
                        </CardHeader>
                        <CardContent className="p-6">
                            <div className="prose prose-slate max-w-none">
                                <p className="text-slate-600 leading-relaxed whitespace-pre-wrap">
                                    {meeting.description || "No description provided."}
                                </p>
                            </div>
                        </CardContent>
                    </Card>

                    {/* MoM Section */}
                    {meeting.status === "Completed" && (
                        <Card className="border-none shadow-xl shadow-slate-200/50 overflow-hidden">
                            <CardHeader className="border-b bg-emerald-50/50 flex flex-row items-center justify-between space-y-0">
                                <div className="flex flex-col gap-1">
                                    <CardTitle className="text-xl text-emerald-900 flex items-center gap-2">
                                        Minutes of Meeting (MoM)
                                        {(user?.role === 'MANAGEMENT' || canManage) && (
                                            <Button variant="outline" size="sm" className="ml-4 h-7 text-xs bg-white text-emerald-700 hover:bg-emerald-50 hover:text-emerald-800 border-emerald-200 shadow-sm" onClick={() => {
                                                const momText = `MoM: ${meeting.title}\n\nSummary:\n${(meeting as any).mom.summary}\n\nMeeting Link: ${window.location.href}`;
                                                navigator.clipboard.writeText(momText);
                                                toast.success("MoM copied to clipboard for sharing!");
                                            }}>
                                                <Share2 className="w-3 h-3 mr-1" /> Share MoM
                                            </Button>
                                        )}
                                    </CardTitle>
                                    <CardDescription>Official record of decisions and updates from this meeting</CardDescription>
                                </div>
                                <FileCheck className="w-6 h-6 text-emerald-600" />
                            </CardHeader>
                            <CardContent className="p-6">
                                {(meeting as any).mom ? (
                                    <div className="space-y-6">
                                        <div className="bg-white rounded-xl p-5 border border-emerald-100/50 shadow-sm">
                                            <h4 className="font-bold text-emerald-900 mb-3 flex items-center gap-2">
                                                <History className="w-4 h-4" />
                                                Meeting Summary
                                            </h4>
                                            <p className="text-emerald-800/80 leading-relaxed whitespace-pre-wrap">
                                                {(meeting as any).mom.summary}
                                            </p>
                                        </div>

                                        <div className="grid gap-6 sm:grid-cols-2">
                                            <div className="bg-slate-50 rounded-xl p-5 border border-slate-100 shadow-sm">
                                                <h4 className="font-bold text-slate-900 mb-3 flex items-center gap-2">
                                                    <Target className="w-4 h-4 text-primary" />
                                                    Key Decisions
                                                </h4>
                                                <ul className="space-y-2">
                                                    {(meeting as any).mom.decisions.map((decision: string, i: number) => (
                                                        <li key={i} className="flex gap-2 text-sm text-slate-600">
                                                            <span className="w-1.5 h-1.5 rounded-full bg-primary mt-1.5 shrink-0" />
                                                            {decision}
                                                        </li>
                                                    ))}
                                                </ul>
                                            </div>

                                            <div className="bg-slate-50 rounded-xl p-5 border border-slate-100 shadow-sm">
                                                <h4 className="font-bold text-slate-900 mb-3 flex items-center gap-2">
                                                    <ClipboardList className="w-4 h-4 text-indigo-600" />
                                                    Action Items
                                                </h4>
                                                <ul className="space-y-3">
                                                    {(meeting as any).mom.actionItems.map((item: any, i: number) => (
                                                        <li key={i} className="bg-white p-3 rounded-lg border border-slate-100 shadow-sm">
                                                            <p className="text-sm font-medium text-slate-900 mb-1">{item.task}</p>
                                                            <div className="flex items-center justify-between text-[11px]">
                                                                <span className="text-slate-500 font-medium">{item.assignee}</span>
                                                                <span className="bg-slate-100 px-2 py-0.5 rounded-full text-slate-600">
                                                                    {item.dueDate}
                                                                </span>
                                                            </div>
                                                        </li>
                                                    ))}
                                                </ul>
                                            </div>
                                        </div>
                                    </div>
                                ) : (
                                    <div className="flex flex-col items-center justify-center py-12 text-center">
                                        <div className="w-16 h-16 rounded-full bg-slate-50 flex items-center justify-center border border-slate-100 mb-4 shadow-sm">
                                            <FileText className="w-8 h-8 text-slate-300" />
                                        </div>
                                        <p className="text-slate-500 font-medium">MoM hasn't been added for this meeting yet.</p>
                                        {isCreator && (
                                            <Button
                                                variant="outline"
                                                className="mt-4 gap-2 rounded-xl"
                                                onClick={() => navigate(`/meetings/${meeting.id}/mom`)}
                                            >
                                                <PlusCircle className="w-4 h-4" />
                                                Create MoM
                                            </Button>
                                        )}
                                    </div>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {!(meeting as any).mom && meeting.status !== "Completed" && (
                        <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-6 flex items-start gap-4">
                            <div className="p-2 bg-indigo-100 rounded-lg shrink-0">
                                <FileCheck className="w-5 h-5 text-indigo-600" />
                            </div>
                            <div>
                                <h4 className="font-bold text-indigo-900 mb-1">Upcoming Meeting</h4>
                                <p className="text-sm text-indigo-700 leading-relaxed">
                                    MoM can be generated once the meeting is completed. Use this page to track the agenda and attendees in the meantime.
                                </p>
                            </div>
                        </div>
                    )}
                </div>

                {/* Sidebar */}
                <div className="space-y-6">
                    {/* Interaction Buttons */}
                    {isCreator && meeting.status !== "Completed" && (
                        <Card className="border-none shadow-xl shadow-indigo-500/10 bg-indigo-600 text-white overflow-hidden group">
                            <CardHeader className="pb-2">
                                <CardTitle className="text-lg">Lead Meeting</CardTitle>
                                <CardDescription className="text-indigo-100">Quick actions for the meeting lead</CardDescription>
                            </CardHeader>
                            <CardContent className="space-y-3 pt-4">
                                <Button
                                    className="w-full bg-white text-indigo-600 hover:bg-white/90 gap-2 font-bold h-11 rounded-xl"
                                    onClick={() => navigate(`/meetings/${meeting.id}/mom`)}
                                >
                                    <PlusCircle className="w-4 h-4" />
                                    Generate MoM
                                </Button>
                                <Button
                                    variant="outline"
                                    className="w-full border-white/20 hover:bg-white/10 text-white gap-2 h-11 rounded-xl"
                                    onClick={() => handleUpdateStatus("Completed")}
                                >
                                    <CheckCircle2 className="w-4 h-4" />
                                    Mark as Completed
                                </Button>
                                {meeting.status === 'Scheduled' && (
                                    <Button
                                        variant="outline"
                                        className="w-full border-white/20 hover:bg-white/10 text-white gap-2 h-11 rounded-xl"
                                        onClick={() => handleUpdateStatus("IN_PROGRESS")}
                                    >
                                        <Play className="w-4 h-4" />
                                        Start Meeting
                                    </Button>
                                )}
                            </CardContent>
                        </Card>
                    )}

                    {/* Attendees */}
                    <Card className="border-none shadow-xl shadow-slate-200/50">
                        <CardHeader className="border-b bg-slate-50/50 flex flex-row items-center justify-between pb-4">
                            <div className="flex items-center gap-2">
                                <Users className="w-5 h-5 text-primary" />
                                <CardTitle className="text-lg">Attendees</CardTitle>
                            </div>
                            <Badge variant="secondary" className="bg-slate-100 text-slate-600 font-bold border-none">
                                {meeting.attendees?.length || 0}
                            </Badge>
                        </CardHeader>
                        <CardContent className="p-0">
                            <ScrollArea className="h-[400px]">
                                <div className="divide-y divide-slate-100">
                                    {(meeting.attendees || []).map((attendee: any, i: number) => (
                                        <div key={i} className="p-4 flex items-center justify-between hover:bg-slate-50/50 transition-colors">
                                            <div className="flex items-center gap-3 min-w-0">
                                                <div className="w-9 h-9 rounded-full bg-primary/10 flex items-center justify-center text-primary font-bold text-xs shrink-0">
                                                    {attendee.fullName ? attendee.fullName.split(' ').map((n: any) => n[0]).join('') : attendee.user?.fullName?.split(' ').map((n: any) => n[0]).join('') || "A"}
                                                </div>
                                                <div className="min-w-0">
                                                    <p className="text-sm font-bold text-slate-900 truncate">{attendee.fullName || attendee.user?.fullName || attendee.email}</p>
                                                    <p className="text-[11px] text-slate-500 font-medium truncate">{attendee.role || attendee.user?.role}</p>
                                                </div>
                                            </div>
                                            <div className="flex items-center gap-2">
                                                <Badge className={cn(
                                                    "px-2 py-0.5 rounded-full font-black text-[8px] tracking-widest uppercase border-none text-white shadow-sm",
                                                    attendee.status === "PRESENT" ? "bg-emerald-600" : "bg-amber-500"
                                                )}>
                                                    {attendee.status || "INVITED"}
                                                </Badge>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </ScrollArea>
                        </CardContent>
                    </Card>

                    {/* Resources */}
                    <Card className="border-none shadow-xl shadow-slate-200/50">
                        <CardHeader className="border-b bg-slate-50/50">
                            <div className="flex items-center gap-2">
                                <FileText className="w-5 h-4 text-primary" />
                                <CardTitle className="text-lg">Resources</CardTitle>
                            </div>
                        </CardHeader>
                        <CardContent className="p-6">
                            {((meeting as any).attachments && (meeting as any).attachments.length > 0) ? (
                                <div className="space-y-3">
                                    {(meeting as any).attachments.map((file: any, i: number) => (
                                        <div key={i} className="flex items-center justify-between p-3 rounded-xl border border-slate-100 group hover:border-primary/30 transition-all bg-slate-50/30">
                                            <div className="flex items-center gap-3 min-w-0">
                                                <div className="p-2 rounded-lg bg-white shadow-sm">
                                                    <Paperclip className="w-4 h-4 text-slate-400 group-hover:text-primary transition-colors" />
                                                </div>
                                                <span className="text-sm font-medium text-slate-700 truncate">{file.name || file.fileName}</span>
                                            </div>
                                            <Button variant="ghost" size="icon" className="h-8 w-8 rounded-lg hover:bg-white hover:text-primary shadow-none">
                                                <Download className="w-4 h-4" />
                                            </Button>
                                        </div>
                                    ))}
                                </div>
                            ) : (
                                <div className="text-center py-6">
                                    <p className="text-sm text-slate-400 italic">No resources attached.</p>
                                </div>
                            )}
                        </CardContent>
                    </Card>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useAutoSave } from '@/hooks/useAutoSave';
import { useParams, useNavigate } from 'react-router-dom';
import {
    FileText,
    Save,
    Send,
    Plus,
    Trash2,
    ChevronLeft,
    Users,
    CheckCircle2,
    MessageSquare,
    Paperclip,
    AlertCircle,
    Info,
    Calendar,
    Clock,
    MapPin,
    Share2,
    Lock,
    Eye,
    CheckSquare,
    Video,
    History as HistoryIcon,
    Cloud
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { PageHeader } from '@/components/layout/PageHeader';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Badge } from '@/components/ui/badge';
import { Checkbox } from '@/components/ui/checkbox';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
