                                        </Dialog>
                                    </span>
                                    <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            className="h-7 text-xs gap-1 bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100 hover:text-amber-800"
                                            onClick={() => navigate(`/leader/life-skills-obs/new?teacherId=${obs.teacherId}&id=${obs.id}&mode=view`)}
                                        >
                                            <Eye className="w-3 h-3" /> VIEW
                                        </Button>
                                    </span>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>
                {filtered.length > 0 && (
                    <p className="text-xs text-muted-foreground text-right mt-2">{filtered.length} observation{filtered.length !== 1 ? "s" : ""} found</p>
                )}
            </div>
        </GrowthLayout>

    );
};

