// ─── Component ─────────────────────────────────────────────────────────────

const MatrixTable = ({
    rows, field, label, form, setMatrix, set, DARK, ACCENT, readOnly
}: {
    rows: string[];
    field: "sectionAResponses" | "sectionBResponses" | "sectionCResponses";
    label: string;
    form: any;
    setMatrix: any;
    set: any;
    DARK: string;
    ACCENT: string;
