);

const CheckboxGroup = ({
    items, field, label, form, toggleList, readOnly
}: {
    items: string[];
    field: "cultureTools" | "routinesObserved" | "instructionalTools" | "metaTags";
    label: string;
    form: any;
    toggleList: any;
    readOnly?: boolean;
}) => (
    <div className="space-y-3">
        <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">{label}</Label>
        <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
            {items.map(item => {
                const checked = (form[field] as string[]).includes(item);
                return (
                    <div
                        key={item}
                        className={cn("flex items-center gap-2 p-2 rounded-lg border transition-all text-sm", checked ? "border-amber-300 bg-amber-50" : "border-slate-200 hover:bg-slate-50", readOnly ? "cursor-default" : "cursor-pointer")}
                        onClick={() => !readOnly && toggleList(field, item)}
                    >
                        <Checkbox checked={checked} onCheckedChange={() => !readOnly && toggleList(field, item)} disabled={readOnly} />
                        <span className="leading-tight">{item}</span>
                    </div>
                );
            })}
        </div>
    </div>
);

const LifeSkillsObsPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const isViewMode = searchParams.get("mode") === "view";
    const [step, setStep] = useState(1);
    const [fetching, setFetching] = useState(false);
    const TOTAL_STEPS = 4;

    const ACCENT = "#B69D74";
    const DARK = "#1F2839";

    const initMatrix = (rows: string[]): Record<string, MatrixVal> =>
        Object.fromEntries(rows.map(r => [r, ""]));

    const [form, setForm] = useState({
        // Page 1
        teacherId: searchParams.get("teacherId") || "",
        observerEmail: user?.email || "",
        teacherName: searchParams.get("teacherName") || "",
        teacherEmail: searchParams.get("teacherEmail") || "",
        observerName: user?.fullName || "",
        observerRole: "",
        observerRoleOther: "",
        observationDate: new Date().toISOString().split("T")[0],
        // Page 2
        block: "",
        grade: "",
        section: "",
        // Page 3 – matrices
        sectionAResponses: initMatrix(SECTION_A_ROWS),
        sectionAEvidence: "",
        sectionBResponses: initMatrix(SECTION_B_ROWS),
        sectionBEvidence: "",
        sectionCResponses: initMatrix(SECTION_C_ROWS),
        sectionCEvidence: "",
        overallRating: "",
        cultureTools: [] as string[],
        routinesObserved: [] as string[],
        instructionalTools: [] as string[],
        // Page 4
        discussedWithTeacher: "",
        feedback: "",
        teacherReflection: "",
        actionStep: "",
        metaTags: [] as string[],
        moduleType: "LIFE_SKILLS",
        academicYear: "AY 25-26",
    });

    const set = (key: string, val: any) => setForm(p => ({ ...p, [key]: val }));

    useEffect(() => {
        const obsId = searchParams.get("id");
        if (obsId) {
            const fetchObs = async () => {
                try {
                    setFetching(true);
                    const res = await api.get(`/growth/observations/${obsId}`);
                    const obs = res.data?.data?.observation;
                    if (obs) {
                        const payload = typeof obs.formPayload === 'string' ? JSON.parse(obs.formPayload) : obs.formPayload;
                        const data = payload || obs;

                        // Helper to merge legacy detailedReflection if it exists
                        const getSecData = (currentResponses: any, sectionRows: string[]) => {
                            const result = { ...currentResponses };
                            if (data.detailedReflection) {
                                sectionRows.forEach(row => {
                                    if (data.detailedReflection[row]) {
                                        result[row] = data.detailedReflection[row];
                                    }
                                });
                            }
                            return result;
                        };

                        setForm(p => ({
                            ...p,
                            ...(payload || obs),
                            teacherId: obs.teacherId,
                            teacherName: obs.teacher?.fullName || payload?.teacherName || obs.teacherName || "",
                            teacherEmail: obs.teacher?.email || payload?.teacherEmail || obs.teacherEmail || "",
                            observationDate: obs.observationDate ? new Date(obs.observationDate).toISOString().split("T")[0] : p.observationDate,
                            sectionAResponses: getSecData(data.sectionAResponses || p.sectionAResponses, SECTION_A_ROWS),
                            sectionBResponses: getSecData(data.sectionBResponses || p.sectionBResponses, SECTION_B_ROWS),
                            sectionCResponses: getSecData(data.sectionCResponses || p.sectionCResponses, SECTION_C_ROWS),
                            overallRating: obs.overallRating ? (Object.keys(ratingMapping).find(k => ratingMapping[k] === obs.overallRating) || payload?.overallRating || obs.overallRating) : (payload?.overallRating || obs.overallRating),
                            discussedWithTeacher: (payload?.discussedWithTeacher || obs.discussionMet) ? (payload?.discussedWithTeacher === true || payload?.discussedWithTeacher === 'Yes' || obs.discussionMet === true ? "Yes" : "No") : ""
                        }));
                    }
                } catch (e) {
                    toast.error("Failed to load observation data");
                } finally {
                    setFetching(false);
                }
            };
            fetchObs();
        }
    }, [searchParams]);

    const ratingMapping: Record<string, number> = {
        "1": 1, // Basic
        "2": 2, // Developing
        "3": 3, // Effective
        "4": 4  // Highly Effective
    };

    const setMatrix = (field: "sectionAResponses" | "sectionBResponses" | "sectionCResponses", row: string, val: MatrixVal) =>
        setForm(p => ({ ...p, [field]: { ...(p[field] as any), [row]: val } }));

    const toggleList = (field: "cultureTools" | "routinesObserved" | "instructionalTools" | "metaTags", item: string) =>
        setForm(p => {
            const arr = p[field] as string[];
            return { ...p, [field]: arr.includes(item) ? arr.filter(x => x !== item) : [...arr, item] };
        });

    const validateStep = () => {
        if (step === 1) {
            if (!form.teacherId) {
                toast.error("Teacher ID is missing. Please select a teacher again."); return false;
            }
            if (!form.teacherName.trim() || !form.teacherEmail.trim() || !form.observerName.trim() || !form.observerRole) {
                toast.error("Please fill in all required fields"); return false;
            }
        }
        if (step === 2) {
            if (!form.block || !form.grade || !form.section.trim()) {
                toast.error("Please fill in all classroom details"); return false;
            }
        }
        if (step === 3) {
            const matrices = [
                { m: form.sectionAResponses, rows: SECTION_A_ROWS, label: "Section A" },
                { m: form.sectionBResponses, rows: SECTION_B_ROWS, label: "Section B" },
                { m: form.sectionCResponses, rows: SECTION_C_ROWS, label: "Section C" },
            ];
            for (const { m, rows, label } of matrices) {
                if (rows.some(r => !m[r])) { toast.error(`Please complete all rows in ${label}`); return false; }
            }
            if (!form.sectionAEvidence.trim() || !form.sectionBEvidence.trim() || !form.sectionCEvidence.trim()) {
                toast.error("Please provide evidence for all sections"); return false;
            }
            if (!form.overallRating) { toast.error("Please select an overall rating"); return false; }
        }
        if (step === 4) {
            if (!form.discussedWithTeacher || !form.feedback.trim() || !form.teacherReflection.trim() || !form.actionStep.trim()) {
                toast.error("Please complete all feedback fields"); return false;
            }
            if (form.metaTags.length === 0) { toast.error("Please select at least one meta tag"); return false; }
        }
        return true;
    };

    const handleNext = () => { if (validateStep()) { setStep(p => p + 1); window.scrollTo(0, 0); } };
    const handleBack = () => { setStep(p => p - 1); window.scrollTo(0, 0); };

    const handleSubmit = async () => {
        if (!validateStep()) return;
        const obsId = searchParams.get("id");

        const numericRating = ratingMapping[form.overallRating] || 0;

        try {
            const payload = {
                ...form,
                discussedWithTeacher: form.discussedWithTeacher === "Yes",
                overallRating: numericRating,
                formPayload: { ...form },
                status: "SUBMITTED"
            };

            if (obsId) {
                await api.patch(`/growth/observations/${obsId}`, payload);
                toast.success("Observation updated successfully!");
            } else {
                await api.post("/growth/observations", payload);
                toast.success("Life Skills Observation saved successfully!");
            }
            navigate(`/leader/growth/${form.teacherId}`);
        } catch (err) {
            console.error(err);
            toast.error("Failed to save observation");
        }
    };

    if (isViewMode && !fetching) {
        const reportData = {
            ...form,
            campus: (user as any)?.campus || (user as any)?.campusId || "N/A",
            strengths: form.feedback,
            areasOfGrowth: form.actionStep
        };

        return (

            <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
                <div className="pt-8 px-4">
                    <ObservationReport data={reportData} onBack={() => navigate(`/leader/growth/${form.teacherId}`)} />
                </div>
            </GrowthLayout>

        );
    }

    return (

        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div style={{ background: "#F5F5EF", minHeight: "100vh", paddingBottom: 60 }}>
                {fetching && (
                    <div className="fixed inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                        <div className="flex flex-col items-center gap-3">
                            <div className="w-10 h-10 border-4 border-amber-500 border-t-transparent rounded-full animate-spin" />
                            <p className="font-bold text-amber-900">Loading observation data...</p>
                        </div>
                    </div>
                )}
                {/* Top bar */}
                <div className="sticky top-0 z-20 border-b mb-6 px-4 pt-4 pb-4" style={{ background: "#F5F5EF" }}>
                    <div className="flex items-center justify-between mb-3">
                        <div className="flex items-center gap-3">
                            <div>
                                <h1 className="text-xl font-bold" style={{ color: DARK }}>AY 25-26 Life Skills Observation_Master</h1>
                                <p className="text-xs text-muted-foreground">Step {step} of {TOTAL_STEPS}</p>
                            </div>
                        </div>
                        <div className="flex gap-1.5">
                            {Array.from({ length: TOTAL_STEPS }).map((_, i) => (
                                <div key={i} className={cn("h-1.5 rounded-full transition-all duration-500", i < step ? "w-10" : "w-6", i < step ? "opacity-100" : "opacity-30")} style={{ background: ACCENT }} />
                            ))}
                        </div>
                    </div>
                </div>

                <div className="max-w-4xl mx-auto px-4 space-y-6">

                    {/* ── PAGE 1: Observer Details ─── */}
                    {step === 1 && (
                        <Card className="  shadow-lg animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <CardHeader className="rounded-t-xl pb-4" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><Users className="w-5 h-5 text-white" /></div>
                                    <div>
                                        <CardTitle className="text-white">Observer Details</CardTitle>
                                        <CardDescription className="text-white/70">Page 1 of 4</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-6 space-y-5">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer Email (Auto-captured)</Label>
                                    <Input value={form.observerEmail} readOnly className="bg-slate-50 text-muted-foreground" />
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wide text-muted-foreground">Name of Teacher *</Label>
                                        <Input value={form.teacherName} onChange={e => set("teacherName", e.target.value)} placeholder="Full name" readOnly={isViewMode || !!searchParams.get("teacherName")} className={cn((isViewMode || !!searchParams.get("teacherName")) && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wide text-muted-foreground">Teacher Email ID *</Label>
                                        <Input type="email" value={form.teacherEmail} onChange={e => set("teacherEmail", e.target.value)} placeholder="teacher@ekya.in" readOnly={isViewMode || !!searchParams.get("teacherEmail")} className={cn((isViewMode || !!searchParams.get("teacherEmail")) && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer's Name *</Label>
                                        <Input value={form.observerName} onChange={e => set("observerName", e.target.value)} readOnly={isViewMode} className={cn(isViewMode && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Date of Observation *</Label>
                                        <Input type="date" value={form.observationDate} onChange={e => set("observationDate", e.target.value)} readOnly={isViewMode} className={cn(isViewMode && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                </div>
                                <div className="space-y-3">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer's Role *</Label>
                                    <RadioGroup value={form.observerRole} onValueChange={v => !isViewMode && set("observerRole", v)} disabled={isViewMode} className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                        {["Academic Coordinator", "CCA Coordinator", "Head of School", "ELC Team Member", "PDI Team Member", "Other"].map(r => (
                                            <div key={r} className={cn("flex items-center gap-2 border p-3 rounded-xl transition-all", isViewMode ? "cursor-default" : "hover:bg-muted/50 cursor-pointer")}>
                                                <RadioGroupItem value={r} id={`role-${r}`} disabled={isViewMode} />
                                                <Label htmlFor={`role-${r}`} className={cn("text-sm", !isViewMode && "cursor-pointer")}>{r}</Label>
                                            </div>
                                        ))}
                                    </RadioGroup>
                                    {form.observerRole === "Other" && (
                                        <Input placeholder="Specify role..." value={form.observerRoleOther} onChange={e => set("observerRoleOther", e.target.value)} readOnly={isViewMode} />
                                    )}
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* ── PAGE 2: Classroom Details ─── */}
                    {step === 2 && (
                        <Card className="  shadow-lg animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <CardHeader className="rounded-t-xl pb-4" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><BookOpen className="w-5 h-5 text-white" /></div>
                                    <div>
                                        <CardTitle className="text-white">Classroom Details</CardTitle>
                                        <CardDescription className="text-white/70">Page 2 of 4</CardDescription>
                                    </div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-6 space-y-6">
                                <div className="space-y-3">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Block *</Label>
                                    <div className="flex flex-wrap gap-3">
                                        {["Early Years", "Primary", "Middle", "Senior"].map(b => (
                                            <button key={b} type="button" onClick={() => !isViewMode && set("block", b)}
                                                disabled={isViewMode}
                                                className={cn("px-5 py-2.5 rounded-xl border-2 text-sm font-semibold transition-all", form.block === b ? "text-white border-transparent" : "border-slate-200 hover:border-amber-300", isViewMode && "cursor-default")}
                                                style={form.block === b ? { background: ACCENT } : {}}>
                                                {b}
                                            </button>
                                        ))}
                                    </div>
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Grade *</Label>
                                        <Select value={form.grade} onValueChange={v => set("grade", v)} disabled={isViewMode}>
                                            <SelectTrigger className={cn("h-11", isViewMode && "bg-slate-50 text-muted-foreground")}><SelectValue placeholder="Select grade" /></SelectTrigger>
                                            <SelectContent>{GRADES.map(g => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Section *</Label>
                                        <Input maxLength={5} placeholder="e.g. A, Emerald" value={form.section} onChange={e => set("section", e.target.value)} className="h-11" readOnly={isViewMode} />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* ── PAGE 3: Observation Matrix ─── */}
                    {step === 3 && (
                        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="p-5 rounded-2xl border" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><ClipboardCheck className="w-5 h-5 text-white" /></div>
                                    <div>
                                        <h2 className="text-lg font-bold text-white">Life Skills Observation Matrix</h2>
                                        <p className="text-white/60 text-sm">Page 3 of 4 — Rate each indicator</p>
                                    </div>
                                </div>
                            </div>

                            {/* Section A */}
                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#EEF2FF" }}>
                                    <h3 className="font-bold text-indigo-800">🟦 Section A – Curriculum and Instruction</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_A_ROWS} field="sectionAResponses" label="A" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            {/* Section B */}
                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#F0FDF4" }}>
                                    <h3 className="font-bold text-green-800">🟦 Section B – Culture and Environment</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_B_ROWS} field="sectionBResponses" label="B" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            {/* Section C */}
                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#FFF7ED" }}>
                                    <h3 className="font-bold text-orange-800">🟦 Section C – Life Skills Classroom Procedures</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_C_ROWS} field="sectionCResponses" label="C" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            {/* Overall Rating */}
                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#FDF4FF" }}>
                                    <h3 className="font-bold text-purple-800">Overall Rating *</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <RadioGroup value={form.overallRating} onValueChange={v => !isViewMode && set("overallRating", v)} disabled={isViewMode} className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                        {[["1", "Basic"], ["2", "Developing"], ["3", "Effective"], ["4", "Highly Effective"]].map(([val, label]) => (
                                            <div key={val} className={cn("flex flex-col items-center gap-1 p-4 border-2 rounded-2xl transition-all", form.overallRating === val ? "border-amber-400 bg-amber-50" : "border-slate-200 hover:border-amber-200", isViewMode ? "cursor-default" : "cursor-pointer")}>
                                                <RadioGroupItem value={val} id={`rating-${val}`} disabled={isViewMode} />
                                                <Label htmlFor={`rating-${val}`} className={cn("font-bold text-lg", !isViewMode && "cursor-pointer")}>{val}</Label>
                                                <span className="text-xs text-muted-foreground text-center">{label}</span>
                                            </div>
                                        ))}
                                    </RadioGroup>
                                </CardContent>
                            </Card>

                            {/* Multi-selects */}
                            <Card className="  shadow-md">
                                <CardContent className="p-5 space-y-8">
                                    <CheckboxGroup items={CULTURE_TOOLS} field="cultureTools" label="Culture Tools Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                    <CheckboxGroup items={ROUTINES} field="routinesObserved" label="Routines Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                    <CheckboxGroup items={INSTRUCTIONAL_TOOLS} field="instructionalTools" label="Instructional Tools Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* ── PAGE 4: Feedback ─── */}
                    {step === 4 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="p-5 rounded-2xl border" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><MessageSquare className="w-5 h-5 text-white" /></div>
                                    <div>
                                        <h2 className="text-lg font-bold text-white">Feedback Section</h2>
                                        <p className="text-white/60 text-sm">Page 4 of 4</p>
                                    </div>
                                </div>
                            </div>

                            <Card className="  shadow-md">
                                <CardContent className="p-6 space-y-5">
                                    <div className="space-y-3">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Have you met and discussed the observation? *</Label>
                                        <RadioGroup value={form.discussedWithTeacher} onValueChange={v => !isViewMode && set("discussedWithTeacher", v)} disabled={isViewMode} className="flex gap-6">
                                            {["Yes", "No"].map(v => (
                                                <div key={v} className={cn("flex items-center gap-2 border p-3 rounded-xl transition-all pr-6", isViewMode ? "cursor-default" : "cursor-pointer hover:bg-muted/50")}>
                                                    <RadioGroupItem value={v} id={`disc-${v}`} disabled={isViewMode} />
                                                    <Label htmlFor={`disc-${v}`} className={cn("font-semibold", !isViewMode && "cursor-pointer")}>{v}</Label>
                                                </div>
                                            ))}
                                        </RadioGroup>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Your Feedback to the Teacher *</Label>
                                        <Textarea className="min-h-[100px]" placeholder="Share your feedback..." value={form.feedback} onChange={e => set("feedback", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">One Reflection Shared by Teacher *</Label>
                                        <Textarea className="min-h-[90px]" placeholder="Teacher's reflection..." value={form.teacherReflection} onChange={e => set("teacherReflection", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Action Step *</Label>
                                        <Textarea className="min-h-[90px]" placeholder="Agreed action step..." value={form.actionStep} onChange={e => set("actionStep", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                </CardContent>
                            </Card>

                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: DARK }}>
                                    <h3 className="font-bold text-white">Meta Tags (select at least 1) *</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <CheckboxGroup items={META_TAGS} field="metaTags" label="" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Navigation Buttons */}
                    <div className="flex justify-between pt-4 pb-10">
                        {step > 1 ? (
                            <Button variant="outline" onClick={handleBack} className="gap-2">
                                <ChevronLeft className="w-4 h-4" /> Back
                            </Button>
                        ) : (
                            <Button variant="ghost" onClick={() => navigate("/leader/life-skills-obs")} className="gap-2">
                                <ChevronLeft className="w-4 h-4" /> Cancel
                            </Button>
                        )}
                        {step < TOTAL_STEPS ? (
                            <Button onClick={handleNext} className="gap-2" style={{ background: ACCENT, color: "white" }}>
                                Next <ChevronRight className="w-4 h-4" />
                            </Button>
                        ) : isViewMode ? (
                            <Button onClick={() => navigate(`/leader/growth/${form.teacherId}`)} className="gap-2 text-white" style={{ background: DARK }}>
                                <ChevronLeft className="w-4 h-4" /> Back to Growth
                            </Button>
                        ) : (
                            <Button onClick={handleSubmit} className="gap-2" style={{ background: DARK, color: "white" }}>
                                <Save className="w-4 h-4" /> {searchParams.get("id") ? "Update Observation" : "Submit Observation"}
                            </Button>
                        )}
                    </div>
                </div>
            </div>
        </GrowthLayout>

    );
};

export default LifeSkillsObsPage;

import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Activity, Plus, Search, Calendar, Star, Eye } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import { toast } from "sonner";
import { GrowthLayout } from "@/components/growth/GrowthLayout";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogTrigger } from "@/components/ui/dialog";
import { MessageSquare } from "lucide-react";

const RATING_COLORS: Record<number, string> = {
    1: "bg-red-100 text-red-700",
    2: "bg-yellow-100 text-yellow-700",
    3: "bg-blue-100 text-blue-700",
    4: "bg-green-100 text-green-700",
};
const RATING_LABELS: Record<number, string> = {
    1: "Basic", 2: "Developing", 3: "Effective", 4: "Highly Effective",
};

const PEObsDashboard: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const teacherId = searchParams.get("teacherId");
    const [observations, setObservations] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchText, setSearchText] = useState(searchParams.get("q") || "");
    const [blockFilter, setBlockFilter] = useState(searchParams.get("block") || "");
    const [gradeFilter, setGradeFilter] = useState(searchParams.get("grade") || "");
    const [ratingFilter, setRatingFilter] = useState(searchParams.get("rating") || "");

    useEffect(() => {
        const params = new URLSearchParams(searchParams);
        if (searchText) params.set("q", searchText); else params.delete("q");
        if (blockFilter) params.set("block", blockFilter); else params.delete("block");
        if (gradeFilter) params.set("grade", gradeFilter); else params.delete("grade");
        if (ratingFilter) params.set("rating", ratingFilter); else params.delete("rating");
        setSearchParams(params, { replace: true });
    }, [searchText, blockFilter, gradeFilter, ratingFilter]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                setLoading(true);
                const params: any = { moduleType: 'PHYSICAL_EDUCATION' };
                if (teacherId) params.teacherId = teacherId;
                const res = await api.get("/growth/observations", { params });

                const mappedObservations = (res.data?.data?.observations || []).map((obs: any) => {
                    let formPayload = obs.formPayload;
                    if (typeof formPayload === 'string') {
                        try { formPayload = JSON.parse(formPayload); } catch (e) { formPayload = {}; }
                    }
                    return {
                        id: obs.id,
                        teacherId: obs.teacherId,
                        observationDate: obs.observationDate,
                        teacherName: obs.teacher?.fullName || obs.teacherEmail || formPayload?.teacherName || "Unknown Teacher",
                        block: formPayload?.block || "",
                        grade: formPayload?.grade || "",
                        overallRating: obs.overallRating || formPayload?.overallRating || "",
                        observerName: obs.observer?.fullName || formPayload?.observer || formPayload?.observerName || "Unknown Observer",
                        hasReflection: obs.hasReflection || false,
                        teacherReflection: obs.teacherReflection || "",
                        detailedReflection: (() => {
                            if (!obs.detailedReflection) return null;
                            if (typeof obs.detailedReflection !== 'string') return obs.detailedReflection;
                            try { return JSON.parse(obs.detailedReflection); } catch (e) { return null; }
                        })()
                    };
                });

                setObservations(mappedObservations);
            } catch {
                toast.error("Failed to load PE observations");
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    if (!user) return null;

    const filtered = observations.filter(o => {
        const name = (o.teacherName || "").toLowerCase();
        return (
            (!searchText || name.includes(searchText.toLowerCase())) &&
            (!blockFilter || o.block === blockFilter) &&
            (!gradeFilter || o.grade === gradeFilter) &&
            (!ratingFilter || String(o.overallRating) === ratingFilter) &&
            (!teacherId || o.teacherId === teacherId)
        );
    });

    const teacherName = searchParams.get("teacherName");
    const teacherEmail = searchParams.get("teacherEmail");

    let newPath = "/leader/pe-obs/new";
    if (teacherId) {
        const params = new URLSearchParams();
        params.set("teacherId", teacherId);
        if (teacherName) params.set("teacherName", teacherName);
        if (teacherEmail) params.set("teacherEmail", teacherEmail);
        newPath += `?${params.toString()}`;
    }

    return (

        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div className="animate-in fade-in duration-500" style={{ background: "#F5F5EF", minHeight: "100vh", padding: "0 0 40px" }}>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                    <div className="flex items-center gap-3">
                        <div className="p-3 rounded-xl text-white" style={{ background: "#1F2839" }}>
                            <Activity className="w-6 h-6" />
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold" style={{ color: "#1F2839" }}>Physical Education Observation</h1>
                            <p className="text-sm text-muted-foreground">AY 25-26 Physical Education Observation_Master</p>
                        </div>
                    </div>
                    <Button onClick={() => navigate(newPath)} style={{ background: "#B69D74", color: "white" }} className="hover:opacity-90 flex items-center gap-2 font-semibold">
                        <Plus className="w-4 h-4" /> New Observation
                    </Button>
                </div>

                <Card className="mb-6   shadow-sm">
                    <CardContent className="pt-4">
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                <Input placeholder="Search teacher..." className="pl-9" value={searchText} onChange={e => setSearchText(e.target.value)} />
                            </div>
                            <Select value={blockFilter} onValueChange={v => setBlockFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Blocks" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Blocks</SelectItem>
                                    {["Early Years", "Primary", "Middle", "Senior"].map(b => <SelectItem key={b} value={b}>{b}</SelectItem>)}
                                </SelectContent>
                            </Select>
                            <Select value={gradeFilter} onValueChange={v => setGradeFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Grades" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Grades</SelectItem>
                                    {["Nursery", "LKG", "UKG", "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5", "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"].map(g => <SelectItem key={g} value={g}>{g}</SelectItem>)}
                                </SelectContent>
                            </Select>
                            <Select value={ratingFilter} onValueChange={v => setRatingFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Ratings" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Ratings</SelectItem>
                                    <SelectItem value="1">1 – Basic</SelectItem>
                                    <SelectItem value="2">2 – Developing</SelectItem>
                                    <SelectItem value="3">3 – Effective</SelectItem>
                                    <SelectItem value="4">4 – Highly Effective</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                <Card className="  shadow-sm overflow-hidden">
                    <CardHeader className="py-3 px-4 border-b" style={{ background: "#1F2839" }}>
                        <div className="grid grid-cols-11 gap-2 text-xs font-semibold text-white capitalize tracking-wider">
                            <span>Sr.</span>
                            <span>Date</span>
                            <span className="col-span-2">Teacher</span>
                            <span>Block</span>
                            <span>Grade</span>
                            <span>Rating</span>
                            <span className="col-span-2">Comments</span>
                            <span className="col-span-2 px-2">View Observation</span>
                        </div>
                    </CardHeader>
                    <CardContent className="p-0">
                        {loading ? (
                            <div className="flex items-center justify-center py-16 text-muted-foreground">Loading observations...</div>
                        ) : filtered.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-16 gap-3 text-muted-foreground">
                                <Activity className="w-12 h-12 opacity-20" />
                                <p className="font-medium">No PE observations yet</p>
                                <Button variant="outline" onClick={() => navigate(newPath)}><Plus className="w-4 h-4 mr-2" /> Start First Observation</Button>
                            </div>
                        ) : (
                            filtered.map((obs, idx) => (
                                <div key={obs.id} className={`grid grid-cols-11 gap-2 px-4 py-3 items-center hover:bg-amber-50 cursor-pointer border-b transition-colors text-sm ${idx % 2 === 0 ? "bg-white" : "bg-slate-50/50"}`}
                                    onClick={() => navigate(`/leader/pe-obs/new?teacherId=${obs.teacherId}&id=${obs.id}`)}>
                                    <span className="font-medium text-slate-500">{idx + 1}</span>
                                    <span className="text-muted-foreground flex items-center gap-1"><Calendar className="w-3 h-3" />{obs.observationDate ? new Date(obs.observationDate).toLocaleDateString() : "—"}</span>
                                    <span className="col-span-2 font-medium text-slate-800">{obs.teacherName}</span>
                                    <span>{obs.block || "—"}</span>
                                    <span>{obs.grade || "—"}</span>
                                    <span>
                                        {obs.overallRating ? (
                                            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${RATING_COLORS[obs.overallRating] || "bg-slate-100 text-slate-700"}`}>
                                                <Star className="w-3 h-3" />{RATING_LABELS[obs.overallRating] || obs.overallRating}
                                            </span>
                                        ) : "—"}
                                    </span>
                                    <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                        <Dialog>
                                            <DialogTrigger asChild>
                                                <Button variant="outline" size="sm" className="h-7 text-xs gap-1 bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100 hover:text-blue-800">
                                                    <MessageSquare className="w-3 h-3" /> View Comment
                                                </Button>
                                            </DialogTrigger>
                                            <DialogContent className="sm:max-w-[500px]">
                                                <DialogHeader>
                                                    <DialogTitle>Teacher Comment</DialogTitle>
                                                    <DialogDescription>
                                                        Insights and comments from the teacher.
                                                    </DialogDescription>
                                                </DialogHeader>
                                                <div className="space-y-4 py-4">
                                                    {obs.detailedReflection?.strengths && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Identified Strengths</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.strengths}</p>
                                                        </div>
                                                    )}
                                                    {obs.detailedReflection?.improvements && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Areas for Growth</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.improvements}</p>
                                                        </div>
                                                    )}
                                                    {obs.detailedReflection?.goal && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Action Goal</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.goal}</p>
                                                        </div>
                                                    )}
                                                    {obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">General Comments</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.teacherReflection}</p>
                                                        </div>
                                                    )}
                                                    {!obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                        <div className="text-center py-6 text-muted-foreground">
                                                            <MessageSquare className="w-8 h-8 mx-auto mb-2 opacity-20" />
                                                            <p className="text-sm">No comments provided by the teacher yet.</p>
                                                        </div>
                                                    )}
                                                </div>
                                            </DialogContent>
                                        </Dialog>
                                    </span>
                                    <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            className="h-7 text-xs gap-1 bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100 hover:text-amber-800"
                                            onClick={() => navigate(`/leader/pe-obs/new?teacherId=${obs.teacherId}&id=${obs.id}&mode=view`)}
                                        >
                                            <Eye className="w-3 h-3" /> VIEW
                                        </Button>
                                    </span>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>
                {filtered.length > 0 && <p className="text-xs text-muted-foreground text-right mt-2">{filtered.length} record{filtered.length !== 1 ? "s" : ""} found</p>}
            </div>
        </GrowthLayout>

    );
};

export default PEObsDashboard;

import React, { useState, useEffect } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/card";
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Checkbox } from "@/components/ui/checkbox";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Activity, ChevronLeft, ChevronRight, Save, Users, BookOpen, ClipboardCheck, MessageSquare } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import { toast } from "sonner";
import { cn } from "@/lib/utils";
import { GrowthLayout } from "@/components/growth/GrowthLayout";
import { ObservationReport } from "@/components/growth/ObservationReport";

const RATING_MAP: Record<string, number> = {
    'Highly Effective': 4,
    'Effective': 3,
    'Developing': 2,
    'Basic': 1,
    'Needs Improvement': 1,
    'Not Observed': 0
};

const GRADES = ["Nursery", "LKG", "UKG", "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5", "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"];

const SECTION_A_ROWS = [
    "Teacher states student learning objectives for class/sport",
    "Gives clear and straightforward directions",
    "Demonstrates relevant examples",
    "Provides practice time and assistance",
    "Offers skill correction and encouraging feedback",
    "States safety procedures and addresses unsafe practices immediately",
];

const SECTION_B_ROWS = [
    "Appropriate class pace & smooth transitions",
    "Maintains student engagement through voice & movement",
    "Students engaged ≥ 50% of class time",
    "Behavior monitored & corrected",
    "Students treated respectfully & fairly",
    "Equipment ready before class; excess stored safely",
    "Rules posted & expectations clear",
];

const SECTION_C_ROWS = [
    "Instant warm-up on entry",
    "Structured warm-up for moderate to vigorous activity",
    "Cool-down activity included",
    "Organized dismissal & wind-up routines",
];

const CULTURE_TOOLS = [
    "Academic Integrity Checklist", "Affirmations", "All Eyes on Me", "Brain Breaks", "Carousel",
    "Catch a Bubble (EY-2)", "Centering", "Check-In", "Circulate", "Controlled Dialogue",
    "Circle Time (EY-2)", "Countdown", "Find Somebody Who", "Good Things", "Grounding",
    "Hand Signals", "Help Now Strategies", "Joy Factor", "Mingle", "Morning Meetings",
    "No Opt Out", "Normalise Error", "Parking Lot", "Positive Framing", "Post the Plan",
    "Precise Praise", "Prioritisation Dots", "Resourcing", "Shift & Stay", "Social Contract",
    "Spectrum Lines", "Timeout", "Tracking", "Not Observed", "Other",
];

const ROUTINES = [
    "Arrival Routine", "Attendance Routine", "Class Cleaning Routines", "Collection Routine",
    "Departure Routine", "Grouping Routine", "Lining Up Strategies", "Not Observed", "Other",
];

const INSTRUCTIONAL_TOOLS = [
    "321", "+1 Routine", "Brainstorming", "Choral Call", "Cold Call", "Concept Map", "Do Now",
    "Entry Ticket", "Exit Ticket", "Go-round", "I Used to Think / Now I Know", "Imagine If", "KWL",
    "Options Diamonds", "Parts & Perspectives", "Put on Your Thinking Cap", "Quick Draw - Quick Write",
    "Reading Jigsaw", "Round Table Discussion", "See-Think-Wonder", "Show Call", "T-Chart",
    "Talking Sticks", "Think-Pair-Share", "Turn & Talk", "Venn Diagram", "Wait Time",
    "No Tools Observed", "Other",
];

const META_TAGS = [
    "Knowledge of Content and Pedagogy", "Knowledge of Students", "Knowledge of Resources",
    "Designing a Microplan", "Using Student Assessments",
    "Creating an Environment of Respect and Rapport", "Establishing a Culture for Learning",
    "Managing Classroom Procedures", "Managing Student Behaviour", "Communicating with Students",
    "Using Questioning and Discussion Techniques", "Using Assessment in Instruction",
    "Organizing Physical Space", "Cleanliness", "Use of Boards", "Reflecting on Teaching",
    "Maintaining Accurate Records", "Communicating with Families",
    "Participating in a Professional Community", "Growing and Developing Professionally",
];

type MatrixVal = "Yes" | "No" | "NA" | "";

const MatrixTable = ({
    rows, field, label, form, setMatrix, set, DARK, ACCENT, readOnly
}: {
    rows: string[]; field: "sectionAResponses" | "sectionBResponses" | "sectionCResponses"; label: string;
    form: any; setMatrix: any; set: any; DARK: string; ACCENT: string;
    readOnly?: boolean;
}) => (
    <div className="space-y-3">
        <div className="grid grid-cols-[1fr_80px_80px_120px] gap-2 text-xs font-bold capitalize tracking-wider px-3 py-2 rounded-lg" style={{ background: DARK, color: "white" }}>
            <span>Statement</span><span className="text-center">Yes</span><span className="text-center">No</span><span className="text-center">N/A</span>
        </div>
        {rows.map((row, i) => (
            <div key={row} className={`grid grid-cols-[1fr_80px_80px_120px] gap-2 items-center px-3 py-3 rounded-lg border ${i % 2 === 0 ? "bg-white" : "bg-slate-50"}`}>
                <span className="text-sm leading-snug">{row}</span>
                {(["Yes", "No", "NA"] as MatrixVal[]).map(val => (
                    <div key={val} className="flex justify-center">
                        <button type="button" onClick={() => !readOnly && setMatrix(field, row, val)}
                            disabled={readOnly}
                            className={cn("w-8 h-8 rounded-full border-2 text-xs font-bold transition-all",
                                (form[field] as Record<string, MatrixVal>)[row] === val ? "text-white border-transparent scale-110" : "border-slate-200 text-slate-400 hover:border-slate-400", readOnly && "cursor-default")}
                            style={(form[field] as Record<string, MatrixVal>)[row] === val ? { background: ACCENT } : {}}>
                            {val === "NA" ? "NA" : val[0]}
                        </button>
                    </div>
                ))}
            </div>
        ))}
        <div className="space-y-2 pt-2">
            <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">Share evidences for your rating ({label}) *</Label>
            <Textarea placeholder="Provide specific evidence..." className="min-h-[90px]"
                value={(form as any)[`section${label}Evidence`]}
                onChange={e => set(`section${label}Evidence`, e.target.value)} readOnly={readOnly} />
        </div>
    </div>
);

const CheckboxGroup = ({ items, field, label, form, toggleList, readOnly }: { items: string[]; field: "cultureTools" | "routinesObserved" | "instructionalTools" | "metaTags"; label: string; form: any; toggleList: any; readOnly?: boolean }) => (
    <div className="space-y-3">
        {label && <Label className="text-sm font-bold capitalize tracking-wider text-muted-foreground">{label}</Label>}
        <div className="grid grid-cols-2 md:grid-cols-3 gap-2">
            {items.map(item => {
                const checked = (form[field] as string[]).includes(item);
                return (
                    <div key={item} className={cn("flex items-center gap-2 p-2 rounded-lg border transition-all text-sm", checked ? "border-amber-300 bg-amber-50" : "border-slate-200 hover:bg-slate-50", readOnly ? "cursor-default" : "cursor-pointer")} onClick={() => !readOnly && toggleList(field, item)}>
                        <Checkbox checked={checked} onCheckedChange={() => !readOnly && toggleList(field, item)} disabled={readOnly} />
                        <span className="leading-tight">{item}</span>
                    </div>
                );
            })}
        </div>
    </div>
);

const PEObsPage: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const isViewMode = searchParams.get("mode") === "view";
    const [step, setStep] = useState(1);
    const [fetching, setFetching] = useState(false);
    const TOTAL_STEPS = 4;
    const ACCENT = "#B69D74";
    const DARK = "#1F2839";

    const initMatrix = (rows: string[]): Record<string, MatrixVal> =>
        Object.fromEntries(rows.map(r => [r, ""]));

    const [form, setForm] = useState({
        teacherId: searchParams.get("teacherId") || "",
        observerEmail: user?.email || "",
        teacherName: searchParams.get("teacherName") || "",
        teacherEmail: searchParams.get("teacherEmail") || "",
        observerName: user?.fullName || "",
        observerRole: "",
        observerRoleOther: "",
        observationDate: new Date().toISOString().split("T")[0],
        block: "",
        grade: "",
        section: "",
        sectionAResponses: initMatrix(SECTION_A_ROWS),
        sectionAEvidence: "",
        sectionBResponses: initMatrix(SECTION_B_ROWS),
        sectionBEvidence: "",
        sectionCResponses: initMatrix(SECTION_C_ROWS),
        sectionCEvidence: "",
        overallRating: "",
        cultureTools: [] as string[],
        routinesObserved: [] as string[],
        instructionalTools: [] as string[],
        discussedWithTeacher: "",
        feedback: "",
        teacherReflection: "",
        actionStep: "",
        metaTags: [] as string[],
        moduleType: "PHYSICAL_EDUCATION",
        academicYear: "AY 25-26",
    });

    const set = (key: string, val: any) => setForm(p => ({ ...p, [key]: val }));

    useEffect(() => {
        const obsId = searchParams.get("id");
        if (obsId) {
            const fetchObs = async () => {
                try {
                    setFetching(true);
                    const res = await api.get(`/growth/observations/${obsId}`);
                    const obs = res.data?.data?.observation;
                    if (obs) {
                        const payload = typeof obs.formPayload === 'string' ? JSON.parse(obs.formPayload) : obs.formPayload;
                        const data = payload || obs;

                        // Helper to merge legacy detailedReflection if it exists
                        const getSecData = (currentResponses: any, sectionRows: string[]) => {
                            const result = { ...currentResponses };
                            if (data.detailedReflection) {
                                sectionRows.forEach(row => {
                                    if (data.detailedReflection[row]) {
                                        result[row] = data.detailedReflection[row];
                                    }
                                });
                            }
                            return result;
                        };

                        setForm(p => ({
                            ...p,
                            ...(payload || obs),
                            teacherId: obs.teacherId,
                            teacherName: obs.teacher?.fullName || payload?.teacherName || obs.teacherName || "",
                            teacherEmail: obs.teacher?.email || payload?.teacherEmail || obs.teacherEmail || "",
                            observationDate: obs.observationDate ? new Date(obs.observationDate).toISOString().split("T")[0] : p.observationDate,
                            sectionAResponses: getSecData(data.sectionAResponses || p.sectionAResponses, SECTION_A_ROWS),
                            sectionBResponses: getSecData(data.sectionBResponses || p.sectionBResponses, SECTION_B_ROWS),
                            sectionCResponses: getSecData(data.sectionCResponses || p.sectionCResponses, SECTION_C_ROWS),
                            overallRating: obs.overallRating ? (Object.keys(ratingMap).find(k => ratingMap[k] === obs.overallRating) || payload?.overallRating || obs.overallRating) : (payload?.overallRating || obs.overallRating),
                            discussedWithTeacher: (payload?.discussedWithTeacher || obs.discussionMet) ? (payload?.discussedWithTeacher === true || payload?.discussedWithTeacher === 'Yes' || obs.discussionMet === true ? "Yes" : "No") : ""
                        }));
                    }
                } catch (e) {
                    toast.error("Failed to load observation data");
                } finally {
                    setFetching(false);
                }
            };
            fetchObs();
        }
    }, [searchParams]);

    const ratingMap: Record<string, number> = {
        "1": 1, // Basic
        "2": 2, // Developing
        "3": 3, // Effective
        "4": 4  // Highly Effective
    };

    const setMatrix = (field: "sectionAResponses" | "sectionBResponses" | "sectionCResponses", row: string, val: MatrixVal) =>
        setForm(p => ({ ...p, [field]: { ...(p[field] as any), [row]: val } }));

    const toggleList = (field: "cultureTools" | "routinesObserved" | "instructionalTools" | "metaTags", item: string) =>
        setForm(p => {
            const arr = p[field] as string[];
            return { ...p, [field]: arr.includes(item) ? arr.filter(x => x !== item) : [...arr, item] };
        });

    const validateStep = () => {
        if (step === 1) {
            if (!form.teacherId) {
                toast.error("Teacher ID is missing. Please select a teacher again."); return false;
            }
            if (!form.teacherName.trim() || !form.teacherEmail.trim() || !form.observerName.trim() || !form.observerRole) {
                toast.error("Please fill in all required fields"); return false;
            }
        }
        if (step === 2 && (!form.block || !form.grade || !form.section.trim())) {
            toast.error("Please fill in all classroom details"); return false;
        }
        if (step === 3) {
            const matrices = [
                { m: form.sectionAResponses, rows: SECTION_A_ROWS, label: "Section A" },
                { m: form.sectionBResponses, rows: SECTION_B_ROWS, label: "Section B" },
                { m: form.sectionCResponses, rows: SECTION_C_ROWS, label: "Section C" },
            ];
            for (const { m, rows, label } of matrices) {
                if (rows.some(r => !m[r])) { toast.error(`Please complete all rows in ${label}`); return false; }
            }
            if (!form.sectionAEvidence.trim() || !form.sectionBEvidence.trim() || !form.sectionCEvidence.trim()) {
                toast.error("Please provide evidence for all sections"); return false;
            }
            if (!form.overallRating) { toast.error("Please select an overall rating"); return false; }
        }
        if (step === 4) {
            if (!form.discussedWithTeacher || !form.feedback.trim() || !form.teacherReflection.trim() || !form.actionStep.trim()) {
                toast.error("Please complete all feedback fields"); return false;
            }
            if (form.metaTags.length === 0) { toast.error("Please select at least one meta tag"); return false; }
        }
        return true;
    };

    const handleNext = () => { if (validateStep()) { setStep(p => p + 1); window.scrollTo(0, 0); } };
    const handleBack = () => { setStep(p => p - 1); window.scrollTo(0, 0); };

    const handleSubmit = async () => {
        if (!validateStep()) return;
        const obsId = searchParams.get("id");

        const numericRating = ratingMap[form.overallRating] || 0;

        try {
            const payload = {
                ...form,
                formPayload: { ...form },
                discussedWithTeacher: form.discussedWithTeacher === "Yes",
                overallRating: numericRating,
                status: "SUBMITTED"
            };

            if (obsId) {
                await api.patch(`/growth/observations/${obsId}`, payload);
                toast.success("Observation updated successfully!");
            } else {
                await api.post("/growth/observations", payload);
                toast.success("PE Observation saved successfully!");
            }
            navigate(`/leader/growth/${form.teacherId}`);
        } catch (err) {
            toast.error("Failed to save observation");
        }
    };

    if (isViewMode && !fetching) {
        const reportData = {
            ...form,
            campus: (user as any)?.campus || (user as any)?.campusId || "N/A",
            strengths: form.feedback,
            areasOfGrowth: form.actionStep
        };

        return (

            <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
                <div className="pt-8 px-4">
                    <ObservationReport data={reportData} onBack={() => navigate(`/leader/growth/${form.teacherId}`)} />
                </div>
            </GrowthLayout>

        );
    }

    return (

        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div style={{ background: "#F5F5EF", minHeight: "100vh", paddingBottom: 60 }}>
                {fetching && (
                    <div className="fixed inset-0 z-50 bg-white/60 backdrop-blur-sm flex items-center justify-center">
                        <div className="flex flex-col items-center gap-3">
                            <div className="w-10 h-10 border-4 border-amber-500 border-t-transparent rounded-full animate-spin" />
                            <p className="font-bold text-amber-900">Loading observation data...</p>
                        </div>
                    </div>
                )}
                {/* Header */}
                <div className="sticky top-0 z-20 border-b mb-6 px-4 pt-4 pb-4" style={{ background: "#F5F5EF" }}>
                    <div className="flex items-center justify-between mb-3">
                        <div className="flex items-center gap-3">
                            <div>
                                <h1 className="text-xl font-bold" style={{ color: DARK }}>AY 25-26 Physical Education Observation_Master</h1>
                                <p className="text-xs text-muted-foreground">Step {step} of {TOTAL_STEPS}</p>
                            </div>
                        </div>
                        <div className="flex gap-1.5">
                            {Array.from({ length: TOTAL_STEPS }).map((_, i) => (
                                <div key={i} className={cn("h-1.5 rounded-full transition-all duration-500", i < step ? "w-10" : "w-6", i < step ? "opacity-100" : "opacity-30")} style={{ background: ACCENT }} />
                            ))}
                        </div>
                    </div>
                </div>

                <div className="max-w-4xl mx-auto px-4 space-y-6">

                    {/* PAGE 1 */}
                    {step === 1 && (
                        <Card className="  shadow-lg animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <CardHeader className="rounded-t-xl pb-4" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><Users className="w-5 h-5 text-white" /></div>
                                    <div><CardTitle className="text-white">Observer Details</CardTitle><CardDescription className="text-white/70">Page 1 of 4</CardDescription></div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-6 space-y-5">
                                <div className="space-y-2">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer Email (Auto-captured)</Label>
                                    <Input value={form.observerEmail} readOnly className="bg-slate-50 text-muted-foreground" />
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wide text-muted-foreground">Name of Teacher *</Label>
                                        <Input value={form.teacherName} onChange={e => set("teacherName", e.target.value)} placeholder="Full name" readOnly={isViewMode || !!searchParams.get("teacherName")} className={cn((isViewMode || !!searchParams.get("teacherName")) && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wide text-muted-foreground">Teacher Email ID *</Label>
                                        <Input type="email" value={form.teacherEmail} onChange={e => set("teacherEmail", e.target.value)} placeholder="teacher@ekya.in" readOnly={isViewMode || !!searchParams.get("teacherEmail")} className={cn((isViewMode || !!searchParams.get("teacherEmail")) && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer's Name *</Label>
                                        <Input value={form.observerName} onChange={e => set("observerName", e.target.value)} readOnly={isViewMode} className={cn(isViewMode && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Date of Observation *</Label>
                                        <Input type="date" value={form.observationDate} onChange={e => set("observationDate", e.target.value)} readOnly={isViewMode} className={cn(isViewMode && "bg-slate-50 text-muted-foreground")} />
                                    </div>
                                </div>
                                <div className="space-y-3">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Observer's Role *</Label>
                                    <RadioGroup value={form.observerRole} onValueChange={v => !isViewMode && set("observerRole", v)} disabled={isViewMode} className="grid grid-cols-2 md:grid-cols-3 gap-3">
                                        {["Academic Coordinator", "CCA Coordinator", "Head of School", "ELC Team Member", "PDI Team Member", "Other"].map(r => (
                                            <div key={r} className={cn("flex items-center gap-2 border p-3 rounded-xl transition-all", isViewMode ? "cursor-default" : "hover:bg-muted/50 cursor-pointer")}>
                                                <RadioGroupItem value={r} id={`role-${r}`} disabled={isViewMode} />
                                                <Label htmlFor={`role-${r}`} className={cn("text-sm", !isViewMode && "cursor-pointer")}>{r}</Label>
                                            </div>
                                        ))}
                                    </RadioGroup>
                                    {form.observerRole === "Other" && <Input placeholder="Specify role..." value={form.observerRoleOther} onChange={e => set("observerRoleOther", e.target.value)} readOnly={isViewMode} />}
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* PAGE 2 */}
                    {step === 2 && (
                        <Card className="  shadow-lg animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <CardHeader className="rounded-t-xl pb-4" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><BookOpen className="w-5 h-5 text-white" /></div>
                                    <div><CardTitle className="text-white">Classroom Details</CardTitle><CardDescription className="text-white/70">Page 2 of 4</CardDescription></div>
                                </div>
                            </CardHeader>
                            <CardContent className="p-6 space-y-6">
                                <div className="space-y-3">
                                    <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Block *</Label>
                                    <div className="flex flex-wrap gap-3">
                                        {["Early Years", "Primary", "Middle", "Senior"].map(b => (
                                            <button key={b} type="button" onClick={() => !isViewMode && set("block", b)}
                                                disabled={isViewMode}
                                                className={cn("px-5 py-2.5 rounded-xl border-2 text-sm font-semibold transition-all", form.block === b ? "text-white border-transparent" : "border-slate-200 hover:border-amber-300", isViewMode && "cursor-default")}
                                                style={form.block === b ? { background: ACCENT } : {}}>{b}</button>
                                        ))}
                                    </div>
                                </div>
                                <div className="grid md:grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Grade *</Label>
                                        <Select value={form.grade} onValueChange={v => set("grade", v)} disabled={isViewMode}>
                                            <SelectTrigger className={cn("h-11", isViewMode && "bg-slate-50 text-muted-foreground")}><SelectValue placeholder="Select grade" /></SelectTrigger>
                                            <SelectContent>{GRADES.map(g => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
                                        </Select>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Section *</Label>
                                        <Input maxLength={5} placeholder="e.g. A, Blue" value={form.section} onChange={e => set("section", e.target.value)} className="h-11" readOnly={isViewMode} />
                                    </div>
                                </div>
                            </CardContent>
                        </Card>
                    )}

                    {/* PAGE 3 */}
                    {step === 3 && (
                        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="p-5 rounded-2xl border" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><ClipboardCheck className="w-5 h-5 text-white" /></div>
                                    <div>
                                        <h2 className="text-lg font-bold text-white">PE Observation Matrix</h2>
                                        <p className="text-white/60 text-sm">Page 3 of 4 — Rate each indicator</p>
                                    </div>
                                </div>
                            </div>

                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#EEF2FF" }}>
                                    <h3 className="font-bold text-indigo-800">🟦 Section A – Curriculum and Instruction</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_A_ROWS} field="sectionAResponses" label="A" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#F0FDF4" }}>
                                    <h3 className="font-bold text-green-800">🟦 Section B – Culture and Environment</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_B_ROWS} field="sectionBResponses" label="B" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#FFF7ED" }}>
                                    <h3 className="font-bold text-orange-800">🟦 Section C – PE Classroom Procedures</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <MatrixTable rows={SECTION_C_ROWS} field="sectionCResponses" label="C" form={form} setMatrix={setMatrix} set={set} DARK={DARK} ACCENT={ACCENT} readOnly={isViewMode} />
                                </CardContent>
                            </Card>

                            {/* Overall Rating */}
                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: "#FDF4FF" }}>
                                    <h3 className="font-bold text-purple-800">Overall Classroom Rating *</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <RadioGroup value={form.overallRating} onValueChange={v => !isViewMode && set("overallRating", v)} disabled={isViewMode} className="grid grid-cols-2 md:grid-cols-4 gap-3">
                                        {[["1", "Basic"], ["2", "Developing"], ["3", "Effective"], ["4", "Highly Effective"]].map(([val, lbl]) => (
                                            <div key={val} className={cn("flex flex-col items-center gap-1 p-4 border-2 rounded-2xl transition-all", form.overallRating === val ? "border-amber-400 bg-amber-50" : "border-slate-200 hover:border-amber-200", isViewMode ? "cursor-default" : "cursor-pointer")}>
                                                <RadioGroupItem value={val} id={`rating-${val}`} disabled={isViewMode} />
                                                <Label htmlFor={`rating-${val}`} className={cn("font-bold text-lg", !isViewMode && "cursor-pointer")}>{val}</Label>
                                                <span className="text-xs text-muted-foreground text-center">{lbl}</span>
                                            </div>
                                        ))}
                                    </RadioGroup>
                                </CardContent>
                            </Card>

                            {/* Multi-selects */}
                            <Card className="  shadow-md">
                                <CardContent className="p-5 space-y-8">
                                    <CheckboxGroup items={CULTURE_TOOLS} field="cultureTools" label="Culture Tools Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                    <CheckboxGroup items={ROUTINES} field="routinesObserved" label="Routines Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                    <CheckboxGroup items={INSTRUCTIONAL_TOOLS} field="instructionalTools" label="Instructional Tools Observed" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* PAGE 4 */}
                    {step === 4 && (
                        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                            <div className="p-5 rounded-2xl border" style={{ background: DARK }}>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-xl bg-white/10"><MessageSquare className="w-5 h-5 text-white" /></div>
                                    <div><h2 className="text-lg font-bold text-white">Feedback Section</h2><p className="text-white/60 text-sm">Page 4 of 4</p></div>
                                </div>
                            </div>

                            <Card className="  shadow-md">
                                <CardContent className="p-6 space-y-5">
                                    <div className="space-y-3">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Have you met and discussed the observation? *</Label>
                                        <RadioGroup value={form.discussedWithTeacher} onValueChange={v => !isViewMode && set("discussedWithTeacher", v)} disabled={isViewMode} className="flex gap-6">
                                            {["Yes", "No"].map(v => (
                                                <div key={v} className={cn("flex items-center gap-2 border p-3 rounded-xl transition-all pr-6", isViewMode ? "cursor-default" : "cursor-pointer hover:bg-muted/50")}>
                                                    <RadioGroupItem value={v} id={`disc-${v}`} disabled={isViewMode} />
                                                    <Label htmlFor={`disc-${v}`} className={cn("font-semibold", !isViewMode && "cursor-pointer")}>{v}</Label>
                                                </div>
                                            ))}
                                        </RadioGroup>
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Your Feedback to the Teacher *</Label>
                                        <Textarea className="min-h-[100px]" placeholder="Share your feedback..." value={form.feedback} onChange={e => set("feedback", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">One Reflection Shared by Teacher *</Label>
                                        <Textarea className="min-h-[90px]" placeholder="Teacher's reflection..." value={form.teacherReflection} onChange={e => set("teacherReflection", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                    <div className="space-y-2">
                                        <Label className="text-xs font-bold capitalize tracking-wider text-muted-foreground">Action Step *</Label>
                                        <Textarea className="min-h-[90px]" placeholder="Agreed action step..." value={form.actionStep} onChange={e => set("actionStep", e.target.value)} readOnly={isViewMode} />
                                    </div>
                                </CardContent>
                            </Card>

                            <Card className="  shadow-md">
                                <CardHeader className="rounded-t-xl py-4 px-5" style={{ background: DARK }}>
                                    <h3 className="font-bold text-white">Meta Tags (select at least 1) *</h3>
                                </CardHeader>
                                <CardContent className="p-5">
                                    <CheckboxGroup items={META_TAGS} field="metaTags" label="" form={form} toggleList={toggleList} readOnly={isViewMode} />
                                </CardContent>
                            </Card>
                        </div>
                    )}

                    {/* Navigation */}
                    <div className="flex justify-between pt-4 pb-10">
                        {step > 1 ? (
                            <Button variant="outline" onClick={handleBack} className="gap-2"><ChevronLeft className="w-4 h-4" /> Back</Button>
                        ) : (
                            <Button variant="ghost" onClick={() => navigate("/leader/pe-obs")} className="gap-2"><ChevronLeft className="w-4 h-4" /> Cancel</Button>
                        )}
                        {step < TOTAL_STEPS ? (
                            <Button onClick={handleNext} className="gap-2" style={{ background: ACCENT, color: "white" }}>Next <ChevronRight className="w-4 h-4" /></Button>
                        ) : isViewMode ? (
                            <Button onClick={() => navigate(`/leader/growth/${form.teacherId}`)} className="gap-2 text-white" style={{ background: DARK }}>
                                <ChevronLeft className="w-4 h-4" /> Back to Growth
                            </Button>
                        ) : (
                            <Button onClick={handleSubmit} className="gap-2" style={{ background: DARK, color: "white" }}>
                                <Save className="w-4 h-4" /> {searchParams.get("id") ? "Update Observation" : "Submit Observation"}
                            </Button>
                        )}
                    </div>
                </div>
            </div>
        </GrowthLayout>

    );
};

export default PEObsPage;

import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Music, Plus, Search, Filter, Calendar, Star, Eye } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import { toast } from "sonner";
import { GrowthLayout } from "@/components/growth/GrowthLayout";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogTrigger } from "@/components/ui/dialog";
import { MessageSquare } from "lucide-react";

interface PAObs {
    id: string;
    teacherId: string;
    observationDate: string;
    teacherName: string;
    block: string;
    grade: string;
    overallRating: number;
    observerName: string;
    hasReflection: boolean;
    teacherReflection: string;
    detailedReflection: any;
}

const RATING_LABELS: Record<number, { label: string; color: string }> = {
    1: { label: "Basic", color: "bg-red-100 text-red-700" },
    2: { label: "Developing", color: "bg-yellow-100 text-yellow-700" },
    3: { label: "Effective", color: "bg-blue-100 text-blue-700" },
    4: { label: "Highly Effective", color: "bg-green-100 text-green-700" },
};

const PerformingArtsObsDashboard: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const teacherId = searchParams.get("teacherId");
    const [observations, setObservations] = useState<PAObs[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchText, setSearchText] = useState(searchParams.get("q") || "");
    const [blockFilter, setBlockFilter] = useState(searchParams.get("block") || "");
    const [gradeFilter, setGradeFilter] = useState(searchParams.get("grade") || "");
    const [ratingFilter, setRatingFilter] = useState(searchParams.get("rating") || "");

    useEffect(() => {
        const params = new URLSearchParams(searchParams);
        if (searchText) params.set("q", searchText); else params.delete("q");
        if (blockFilter) params.set("block", blockFilter); else params.delete("block");
        if (gradeFilter) params.set("grade", gradeFilter); else params.delete("grade");
        if (ratingFilter) params.set("rating", ratingFilter); else params.delete("rating");
        setSearchParams(params, { replace: true });
    }, [searchText, blockFilter, gradeFilter, ratingFilter]);

    useEffect(() => {
        const fetch = async () => {
            try {
                setLoading(true);
                const params: any = { moduleType: 'PERFORMING_ARTS' };
                if (teacherId) params.teacherId = teacherId;
                if (blockFilter) params.block = blockFilter;
                if (gradeFilter) params.grade = gradeFilter;
                if (ratingFilter) params.rating = ratingFilter;
                const res = await api.get("/growth/observations", { params });

                // Map the unified observation format to the old PAObs interface
                const mappedObservations = (res.data?.data?.observations || []).map((obs: any) => {
                    let formPayload = obs.formPayload;
                    if (typeof formPayload === 'string') {
                        try { formPayload = JSON.parse(formPayload); } catch (e) { formPayload = {}; }
                    }
                    return {
                        id: obs.id,
                        teacherId: obs.teacherId,
                        observationDate: obs.observationDate,
                        teacherName: obs.teacher?.fullName || obs.teacherEmail || formPayload?.teacherName || "Unknown Teacher",
                        block: formPayload?.block || "",
                        grade: formPayload?.grade || "",
                        overallRating: obs.overallRating || formPayload?.overallRating || 0,
                        observerName: obs.observer?.fullName || formPayload?.observer || formPayload?.observerName || "Unknown Observer",
                        hasReflection: obs.hasReflection || false,
                        teacherReflection: obs.teacherReflection || "",
                        detailedReflection: (() => {
                            if (!obs.detailedReflection) return null;
                            if (typeof obs.detailedReflection !== 'string') return obs.detailedReflection;
                            try { return JSON.parse(obs.detailedReflection); } catch (e) { return null; }
                        })()
                    };
                });

                setObservations(mappedObservations);
            } catch (e) {
                toast.error("Failed to load observations");
            } finally {
                setLoading(false);
            }
        };
        fetch();
    }, [blockFilter, gradeFilter, ratingFilter]);

    if (!user) return null;

    const filtered = observations.filter(o =>
        (!searchText ||
            o.teacherName.toLowerCase().includes(searchText.toLowerCase()) ||
            o.observerName.toLowerCase().includes(searchText.toLowerCase())) &&
        (!teacherId || o.teacherId === teacherId)
    );

    const teacherName = searchParams.get("teacherName");
    const teacherEmail = searchParams.get("teacherEmail");

    let newFormPath = "/leader/performing-arts-obs/new";
    if (teacherId) {
        const params = new URLSearchParams();
        params.set("teacherId", teacherId);
        if (teacherName) params.set("teacherName", teacherName);
        if (teacherEmail) params.set("teacherEmail", teacherEmail);
        newFormPath += `?${params.toString()}`;
    }

    return (

        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div className="animate-in fade-in duration-500 min-h-screen" style={{ background: "#F5F5EF", paddingBottom: "40px" }}>
                <div className="rounded-3xl border-2 overflow-hidden mt-4" style={{ borderColor: "#B69D74" }}>
                    <div className="p-6 md:p-8 lg:p-10 space-y-8">
                        {/* Header */}
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                            <div className="flex items-center gap-3">
                                <div className="p-3 rounded-xl text-white shadow-md" style={{ background: "#B69D74" }}>
                                    <Music className="w-6 h-6" />
                                </div>
                                <div>
                                    <h1 className="text-2xl font-bold" style={{ color: "#1F2839" }}>Performing Arts Observations</h1>
                                    <p className="text-sm text-muted-foreground font-medium italic">AY 25-26 · Music, Dance & Drama</p>
                                </div>
                            </div>
                            <Button
                                onClick={() => navigate(newFormPath)}
                                style={{ background: "#B69D74", color: "white" }}
                                className="hover:opacity-90 flex items-center gap-2 font-bold shadow-sm hover:shadow-md transition-all duration-300 px-6 h-11"
                            >
                                <Plus className="w-4 h-4" /> New Observation
                            </Button>
                        </div>

                        {/* Filters */}
                        <Card className="mb-6   shadow-sm" style={{ background: "white" }}>
                            <CardContent className="pt-4">
                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
                                    <div className="relative">
                                        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                        <Input
                                            placeholder="Search teacher / observer..."
                                            className="pl-9"
                                            value={searchText}
                                            onChange={e => setSearchText(e.target.value)}
                                        />
                                    </div>
                                    <Select value={blockFilter} onValueChange={v => setBlockFilter(v === "all" ? "" : v)}>
                                        <SelectTrigger><SelectValue placeholder="All Blocks" /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Blocks</SelectItem>
                                            {["Early Years", "Primary", "Middle", "Senior"].map(b => (
                                                <SelectItem key={b} value={b}>{b}</SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                    <Select value={gradeFilter} onValueChange={v => setGradeFilter(v === "all" ? "" : v)}>
                                        <SelectTrigger><SelectValue placeholder="All Grades" /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Grades</SelectItem>
                                            {["Nursery", "LKG", "UKG", "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5",
                                                "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"].map(g => (
                                                    <SelectItem key={g} value={g}>{g}</SelectItem>
                                                ))}
                                        </SelectContent>
                                    </Select>
                                    <Select value={ratingFilter} onValueChange={v => setRatingFilter(v === "all" ? "" : v)}>
                                        <SelectTrigger><SelectValue placeholder="All Ratings" /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="all">All Ratings</SelectItem>
                                            <SelectItem value="1">1 – Basic</SelectItem>
                                            <SelectItem value="2">2 – Developing</SelectItem>
                                            <SelectItem value="3">3 – Effective</SelectItem>
                                            <SelectItem value="4">4 – Highly Effective</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </CardContent>
                        </Card>

                        {/* Table */}
                        <Card className="  shadow-sm overflow-hidden">
                            <CardHeader className="border-b py-3 px-4" style={{ background: "#1F2839" }}>
                                <div className="grid grid-cols-11 gap-2 text-xs font-semibold text-white capitalize tracking-wider">
                                    <span>Sr.</span>
                                    <span className="col-span-1">Date</span>
                                    <span className="col-span-2">Teacher</span>
                                    <span>Block</span>
                                    <span>Grade</span>
                                    <span>Rating</span>
                                    <span className="col-span-2">Comments</span>
                                    <span className="col-span-2 px-2">View Observation</span>
                                </div>
                            </CardHeader>
                            <CardContent className="p-0">
                                {loading ? (
                                    <div className="flex items-center justify-center py-16 text-muted-foreground">
                                        Loading observations...
                                    </div>
                                ) : filtered.length === 0 ? (
                                    <div className="flex flex-col items-center justify-center py-16 gap-3 text-muted-foreground">
                                        <Music className="w-12 h-12 opacity-20" />
                                        <p className="font-medium">No observations yet</p>
                                        <Button variant="outline" onClick={() => navigate(newFormPath)}>
                                            <Plus className="w-4 h-4 mr-2" /> Start First Observation
                                        </Button>
                                    </div>
                                ) : (
                                    filtered.map((obs, idx) => {
                                        const rating = RATING_LABELS[obs.overallRating];
                                        return (
                                            <div
                                                key={obs.id}
                                                className={`grid grid-cols-11 gap-2 px-4 py-3 items-center hover:bg-amber-50 cursor-pointer border-b transition-colors text-sm ${idx % 2 === 0 ? "bg-white" : "bg-slate-50/50"}`}
                                                onClick={() => navigate(`/leader/performing-arts-obs/new?teacherId=${obs.teacherId}&id=${obs.id}`)}
                                            >
                                                <span className="font-medium text-slate-500">{idx + 1}</span>
                                                <span className="col-span-1 text-muted-foreground flex items-center gap-1">
                                                    <Calendar className="w-3 h-3" />{obs.observationDate ? obs.observationDate.slice(0, 19) : "—"}
                                                </span>
                                                <span className="col-span-2 font-medium text-slate-800">{obs.teacherName}</span>
                                                <span>{obs.block}</span>
                                                <span>{obs.grade}</span>
                                                <span>
                                                    {rating ? (
                                                        <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${rating.color}`}>
                                                            <Star className="w-3 h-3" />{rating.label}
                                                        </span>
                                                    ) : obs.overallRating}
                                                </span>
                                                <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                                    <Dialog>
                                                        <DialogTrigger asChild>
                                                            <Button variant="outline" size="sm" className="h-7 text-xs gap-1 bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100 hover:text-blue-800">
                                                                <MessageSquare className="w-3 h-3" /> View Comment
                                                            </Button>
                                                        </DialogTrigger>
                                                        <DialogContent className="sm:max-w-[500px]">
                                                            <DialogHeader>
                                                                <DialogTitle>Teacher Comment</DialogTitle>
                                                                <DialogDescription>
                                                                    Insights and comments from the teacher.
                                                                </DialogDescription>
                                                            </DialogHeader>
                                                            <div className="space-y-4 py-4">
                                                                {obs.detailedReflection?.strengths && (
                                                                    <div>
                                                                        <h4 className="font-semibold text-sm mb-1">Identified Strengths</h4>
                                                                        <p className="text-sm text-muted-foreground">{obs.detailedReflection.strengths}</p>
                                                                    </div>
                                                                )}
                                                                {obs.detailedReflection?.improvements && (
                                                                    <div>
                                                                        <h4 className="font-semibold text-sm mb-1">Areas for Growth</h4>
                                                                        <p className="text-sm text-muted-foreground">{obs.detailedReflection.improvements}</p>
                                                                    </div>
                                                                )}
                                                                {obs.detailedReflection?.goal && (
                                                                    <div>
                                                                        <h4 className="font-semibold text-sm mb-1">Action Goal</h4>
                                                                        <p className="text-sm text-muted-foreground">{obs.detailedReflection.goal}</p>
                                                                    </div>
                                                                )}
                                                                {obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                                    <div>
                                                                        <h4 className="font-semibold text-sm mb-1">General Comments</h4>
                                                                        <p className="text-sm text-muted-foreground">{obs.teacherReflection}</p>
                                                                    </div>
                                                                )}
                                                                {!obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                                    <div className="text-center py-6 text-muted-foreground">
                                                                        <MessageSquare className="w-8 h-8 mx-auto mb-2 opacity-20" />
                                                                        <p className="text-sm">No comments provided by the teacher yet.</p>
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </DialogContent>
                                                    </Dialog>
                                                </span>
                                                <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                                    <Button
                                                        variant="outline"
                                                        size="sm"
                                                        className="h-7 text-xs gap-1 bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100 hover:text-amber-800"
                                                        onClick={() => navigate(`/leader/performing-arts-obs/new?teacherId=${obs.teacherId}&id=${obs.id}&mode=view`)}
                                                    >
                                                        <Eye className="w-3 h-3" /> VIEW
                                                    </Button>
                                                </span>
                                            </div>
                                        );
                                    })
                                )}
                            </CardContent>
                        </Card>

                        {filtered.length > 0 && (
                            <p className="text-xs text-muted-foreground text-right mt-2 font-medium">
                                {filtered.length} observation{filtered.length !== 1 ? "s" : ""} found
                            </p>
                        )}
                    </div>
                </div>
            </div>
        </GrowthLayout>

    );
};

export default PerformingArtsObsDashboard;

import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { MessageSquare, Plus, Search, Calendar, Star } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import { toast } from "sonner";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { GrowthLayout } from "@/components/growth/GrowthLayout";

const RATING_COLORS: Record<number, string> = {
    1: "bg-red-100 text-red-700",
    2: "bg-yellow-100 text-yellow-700",
    3: "bg-blue-100 text-blue-700",
    4: "bg-green-100 text-green-700",
};

const QuickFeedbackDashboard: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams] = useSearchParams();
    const teacherId = searchParams.get("teacherId");

    const [observations, setObservations] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchText, setSearchText] = useState("");
    const [blockFilter, setBlockFilter] = useState("");
    const [gradeFilter, setGradeFilter] = useState("");

    useEffect(() => {
        const fetch = async () => {
            try {
                setLoading(true);
                const params: any = { moduleType: "QUICK_FEEDBACK" };
                if (teacherId) params.teacherId = teacherId;
                const res = await api.get("/growth/observations", { params });
                const all = res.data?.data?.observations || res.data?.observations || [];

                const mappedObservations = all.map((obs: any) => {
                    let formPayload = obs.formPayload;
                    if (typeof formPayload === 'string') {
                        try { formPayload = JSON.parse(formPayload); } catch (e) { formPayload = {}; }
                    }
                    return {
                        id: obs.id,
                        teacherId: obs.teacherId,
                        observationDate: obs.observationDate,
                        teacherName: obs.teacher?.fullName || obs.teacherEmail || formPayload?.teacherName || "Unknown Teacher",
                        teacher: obs.teacher?.fullName || formPayload?.teacherName || "Unknown Teacher",
                        type: "Quick Feedback",
                        domain: "Quick Feedback",
                        overallRating: obs.overallRating || formPayload?.overallRating || "",
                        observerName: obs.observer?.fullName || formPayload?.observer || "Unknown Observer",
                        block: formPayload?.block || obs.classroom?.block || "",
                        grade: formPayload?.grade || obs.classroom?.grade || "",
                        hasReflection: obs.hasReflection || false,
                        teacherReflection: obs.teacherReflection || "",
                        detailedReflection: (() => {
                            if (!obs.detailedReflection) return null;
                            if (typeof obs.detailedReflection !== 'string') return obs.detailedReflection;
                            try { return JSON.parse(obs.detailedReflection); } catch (e) { return null; }
                        })()
                    };
                });

                setObservations(mappedObservations);
            } catch {
                toast.error("Failed to load feedback records");
            } finally {
                setLoading(false);
            }
        };
        fetch();
    }, []);

    if (!user) return null;

    const getTeacherName = (o: any): string => {
        if (!o.teacher) return o.teacherName || "—";
        if (typeof o.teacher === "string") return o.teacher;
        return o.teacher.fullName || o.teacher.name || "—";
    };
    const getBlock = (o: any) => o.block || o.classroom?.block || "—";
    const getGrade = (o: any) => o.grade || o.classroom?.grade || "—";

    const filtered = observations.filter(o => {
        const name = getTeacherName(o).toLowerCase();
        return (
            (!searchText || name.includes(searchText.toLowerCase())) &&
            (!blockFilter || getBlock(o) === blockFilter) &&
            (!gradeFilter || getGrade(o) === gradeFilter) &&
            (!teacherId || o.teacherId === teacherId)
        );
    });

    const teacherName = searchParams.get("teacherName");
    const teacherEmail = searchParams.get("teacherEmail");

    let newPath = "/leader/quick-feedback/new";
    if (teacherId) {
        const params = new URLSearchParams();
        params.set("teacherId", teacherId);
        if (teacherName) params.set("teacherName", teacherName);
        if (teacherEmail) params.set("teacherEmail", teacherEmail);
        newPath += `?${params.toString()}`;
    }

    return (
        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div className="space-y-8 animate-in fade-in duration-500">
                {/* Header */}
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                    <div className="flex items-center gap-3">
                        <div className="p-3 rounded-xl text-white" style={{ background: "#B69D74" }}>
                            <MessageSquare className="w-6 h-6" />
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold" style={{ color: "#1F2839" }}>Quick Feedback Master</h1>
                            <p className="text-sm text-muted-foreground">Fast, actionable feedback loops for non-core subjects</p>
                        </div>
                    </div>
                    <Button
                        onClick={() => navigate(newPath)}
                        style={{ background: "#B69D74", color: "white" }}
                        className="hover:opacity-90 flex items-center gap-2 font-semibold"
                    >
                        <Plus className="w-4 h-4" /> New Feedback
                    </Button>
                </div>

                {/* Filters */}
                <Card className="mb-6   shadow-sm">
                    <CardContent className="pt-4">
                        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                <Input placeholder="Search teacher..." className="pl-9" value={searchText} onChange={e => setSearchText(e.target.value)} />
                            </div>
                            <Select value={blockFilter} onValueChange={v => setBlockFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Blocks" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Blocks</SelectItem>
                                    {["Early Years", "Primary", "Middle", "Senior"].map(b => (
                                        <SelectItem key={b} value={b}>{b}</SelectItem>
                                    ))}
                                </SelectContent>
                            </Select>
                            <Select value={gradeFilter} onValueChange={v => setGradeFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Grades" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Grades</SelectItem>
                                    {["Nursery", "LKG", "UKG", "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5",
                                        "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"].map(g => (
                                            <SelectItem key={g} value={g}>{g}</SelectItem>
                                        ))}
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                {/* Table */}
                <Card className="  shadow-sm overflow-hidden">
                    <CardHeader className="py-3 px-4 border-b" style={{ background: "#1F2839" }}>
                        <div className="grid grid-cols-7 gap-2 text-xs font-semibold text-white capitalize tracking-wider">
                            <span>Date</span>
                            <span className="col-span-2">Teacher</span>
                            <span>Block</span>
                            <span>Grade</span>
                            <span>Score</span>
                            <span>Reflection</span>
                        </div>
                    </CardHeader>
                    <CardContent className="p-0">
                        {loading ? (
                            <div className="flex items-center justify-center py-16 text-muted-foreground">Loading records...</div>
                        ) : filtered.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-16 gap-3 text-muted-foreground">
                                <MessageSquare className="w-12 h-12 opacity-20" />
                                <p className="font-medium">No feedback records yet</p>
                                <Button variant="outline" onClick={() => navigate(newPath)}>
                                    <Plus className="w-4 h-4 mr-2" /> Start First Feedback
                                </Button>
                            </div>
                        ) : (
                            filtered.map((obs, idx) => (
                                <div
                                    key={obs.id}
                                    className={`grid grid-cols-7 gap-2 px-4 py-3 items-center hover:bg-amber-50 cursor-pointer border-b transition-colors text-sm ${idx % 2 === 0 ? "bg-white" : "bg-slate-50/50"}`}
                                    onClick={() => navigate(`/leader/quick-feedback/new?teacherId=${obs.teacherId || (typeof obs.teacher === 'object' ? obs.teacher?.id : '')}&id=${obs.id}`)}
                                >
                                    <span className="text-muted-foreground flex items-center gap-1">
                                        <Calendar className="w-3 h-3" />{obs.observationDate ? new Date(obs.observationDate).toLocaleDateString() : "—"}
                                    </span>
                                    <span className="col-span-2 font-medium text-slate-800">{getTeacherName(obs)}</span>
                                    <span>{getBlock(obs)}</span>
                                    <span>{getGrade(obs)}</span>
                                    <span>
                                        {obs.score != null ? (
                                            <span className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-semibold ${RATING_COLORS[Math.round(obs.score)] || "bg-slate-100 text-slate-700"}`}>
                                                <Star className="w-3 h-3" />{obs.score}
                                            </span>
                                        ) : "—"}
                                    </span>
                                    <span onClick={(e) => e.stopPropagation()}>
                                        <Dialog>
                                            <DialogTrigger asChild>
                                                {obs.hasReflection ? (
                                                    <Button variant="outline" size="sm" className="h-7 text-xs gap-1 bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100 hover:text-blue-800">
                                                        <MessageSquare className="w-3 h-3" /> View Reflection
                                                    </Button>
                                                ) : (
                                                    <Badge variant="secondary" className="text-xs text-muted-foreground font-normal bg-slate-100">
                                                        Pending
                                                    </Badge>
                                                )}
                                            </DialogTrigger>
                                            {obs.hasReflection && (
                                                <DialogContent className="sm:max-w-[500px]">
                                                    <DialogHeader>
                                                        <DialogTitle>Teacher Reflection</DialogTitle>
                                                    </DialogHeader>
                                                    <div className="space-y-4 py-4">
                                                        {obs.detailedReflection?.strengths && (
                                                            <div>
                                                                <h4 className="font-semibold text-sm mb-1">Identified Strengths</h4>
                                                                <p className="text-sm text-muted-foreground">{obs.detailedReflection.strengths}</p>
                                                            </div>
                                                        )}
                                                        {obs.detailedReflection?.improvements && (
                                                            <div>
                                                                <h4 className="font-semibold text-sm mb-1">Areas for Growth</h4>
                                                                <p className="text-sm text-muted-foreground">{obs.detailedReflection.improvements}</p>
                                                            </div>
                                                        )}
                                                        {obs.detailedReflection?.goal && (
                                                            <div>
                                                                <h4 className="font-semibold text-sm mb-1">Action Goal</h4>
                                                                <p className="text-sm text-muted-foreground">{obs.detailedReflection.goal}</p>
                                                            </div>
                                                        )}
                                                        {obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                            <div>
                                                                <h4 className="font-semibold text-sm mb-1">General Comments</h4>
                                                                <p className="text-sm text-muted-foreground">{obs.teacherReflection}</p>
                                                            </div>
                                                        )}
                                                    </div>
                                                </DialogContent>
                                            )}
                                        </Dialog>
                                    </span>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>
                {filtered.length > 0 && (
                    <p className="text-xs text-muted-foreground text-right mt-2">{filtered.length} record{filtered.length !== 1 ? "s" : ""} found</p>
                )}
            </div>
        </GrowthLayout>
    );
};

export default QuickFeedbackDashboard;

import React, { useEffect, useState } from "react";
import { useNavigate, useSearchParams } from "react-router-dom";

import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Palette, Plus, Search, Calendar, Star, Eye } from "lucide-react";
import { useAuth } from "@/hooks/useAuth";
import api from "@/lib/api";
import { toast } from "sonner";
import { GrowthLayout } from "@/components/growth/GrowthLayout";
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { MessageSquare } from "lucide-react";

const RATING_COLORS: Record<string, string> = {
    "Highly Effective": "bg-green-100 text-green-700",
    "Effective": "bg-blue-100 text-blue-700",
    "Developing": "bg-yellow-100 text-yellow-700",
    "Needs Improvement": "bg-red-100 text-red-700",
};

const VAObsDashboard: React.FC = () => {
    const { user } = useAuth();
    const navigate = useNavigate();
    const [searchParams, setSearchParams] = useSearchParams();
    const teacherId = searchParams.get("teacherId");
    const [observations, setObservations] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchText, setSearchText] = useState(searchParams.get("q") || "");
    const [blockFilter, setBlockFilter] = useState(searchParams.get("block") || "");
    const [gradeFilter, setGradeFilter] = useState(searchParams.get("grade") || "");
    const [ratingFilter, setRatingFilter] = useState(searchParams.get("rating") || "");

    useEffect(() => {
        const params = new URLSearchParams(searchParams);
        if (searchText) params.set("q", searchText); else params.delete("q");
        if (blockFilter) params.set("block", blockFilter); else params.delete("block");
        if (gradeFilter) params.set("grade", gradeFilter); else params.delete("grade");
        if (ratingFilter) params.set("rating", ratingFilter); else params.delete("rating");
        setSearchParams(params, { replace: true });
    }, [searchText, blockFilter, gradeFilter, ratingFilter]);

    useEffect(() => {
        const fetchData = async () => {
            try {
                setLoading(true);
                const params: any = { moduleType: 'VISUAL_ARTS' };
                if (teacherId) params.teacherId = teacherId;
                const res = await api.get("/growth/observations", { params });

                const mappedObservations = (res.data?.data?.observations || []).map((obs: any) => {
                    let formPayload = obs.formPayload;
                    if (typeof formPayload === 'string') {
                        try { formPayload = JSON.parse(formPayload); } catch (e) { formPayload = {}; }
                    }
                    return {
                        id: obs.id,
                        teacherId: obs.teacherId,
                        observationDate: obs.observationDate,
                        teacherName: obs.teacher?.fullName || obs.teacherEmail || formPayload?.teacherName || "Unknown Teacher",
                        block: formPayload?.block || "",
                        grade: formPayload?.grade || "",
                        overallRating: obs.overallRating || formPayload?.overallRating || "",
                        observerName: obs.observer?.fullName || formPayload?.observer || formPayload?.observerName || "Unknown Observer",
                        hasReflection: obs.hasReflection || false,
                        teacherReflection: obs.teacherReflection || "",
                        detailedReflection: (() => {
                            if (!obs.detailedReflection) return null;
                            if (typeof obs.detailedReflection !== 'string') return obs.detailedReflection;
                            try { return JSON.parse(obs.detailedReflection); } catch (e) { return null; }
                        })()
                    };
                });

                setObservations(mappedObservations);
            } catch {
                toast.error("Failed to load Visual Arts observations");
            } finally {
                setLoading(false);
            }
        };
        fetchData();
    }, []);

    if (!user) return null;

    const filtered = observations.filter(o => {
        const name = (o.teacherName || "").toLowerCase();
        return (
            (!searchText || name.includes(searchText.toLowerCase())) &&
            (!blockFilter || o.block === blockFilter) &&
            (!gradeFilter || o.grade === gradeFilter) &&
            (!ratingFilter || o.overallRating === ratingFilter) &&
            (!teacherId || o.teacherId === teacherId)
        );
    });

    const teacherName = searchParams.get("teacherName");
    const teacherEmail = searchParams.get("teacherEmail");

    let newPath = "/leader/va-obs/new";
    if (teacherId) {
        const params = new URLSearchParams();
        params.set("teacherId", teacherId);
        if (teacherName) params.set("teacherName", teacherName);
        if (teacherEmail) params.set("teacherEmail", teacherEmail);
        newPath += `?${params.toString()}`;
    }

    return (

        <GrowthLayout allowedRoles={['LEADER', 'SCHOOL_LEADER', 'ADMIN', 'SUPERADMIN']}>
            <div className="animate-in fade-in duration-500" style={{ background: "#F5F5EF", minHeight: "100vh", padding: "0 0 40px" }}>
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-8">
                    <div className="flex items-center gap-3">
                        <div className="p-3 rounded-xl text-white" style={{ background: "#1F2839" }}>
                            <Palette className="w-6 h-6" />
                        </div>
                        <div>
                            <h1 className="text-2xl font-bold" style={{ color: "#1F2839" }}>Visual Arts Observation</h1>
                            <p className="text-sm text-muted-foreground">AY 25–26 Visual Arts Observation_Master</p>
                        </div>
                    </div>
                    <Button onClick={() => navigate(newPath)} style={{ background: "#B69D74", color: "white" }} className="hover:opacity-90 flex items-center gap-2 font-semibold">
                        <Plus className="w-4 h-4" /> New Observation
                    </Button>
                </div>

                <Card className="mb-6   shadow-sm">
                    <CardContent className="pt-4">
                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
                            <div className="relative">
                                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
                                <Input placeholder="Search teacher..." className="pl-9" value={searchText} onChange={e => setSearchText(e.target.value)} />
                            </div>
                            <Select value={blockFilter} onValueChange={v => setBlockFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Blocks" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Blocks</SelectItem>
                                    {["Early Years", "Primary", "Middle", "Senior"].map(b => <SelectItem key={b} value={b}>{b}</SelectItem>)}
                                </SelectContent>
                            </Select>
                            <Select value={gradeFilter} onValueChange={v => setGradeFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Grades" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Grades</SelectItem>
                                    {["Nursery", "LKG", "UKG", "Grade 1", "Grade 2", "Grade 3", "Grade 4", "Grade 5", "Grade 6", "Grade 7", "Grade 8", "Grade 9", "Grade 10", "Grade 11", "Grade 12"].map(g => <SelectItem key={g} value={g}>{g}</SelectItem>)}
                                </SelectContent>
                            </Select>
                            <Select value={ratingFilter} onValueChange={v => setRatingFilter(v === "all" ? "" : v)}>
                                <SelectTrigger><SelectValue placeholder="All Ratings" /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Ratings</SelectItem>
                                    {["Highly Effective", "Effective", "Developing", "Needs Improvement"].map(r => <SelectItem key={r} value={r}>{r}</SelectItem>)}
                                </SelectContent>
                            </Select>
                        </div>
                    </CardContent>
                </Card>

                <Card className="  shadow-sm overflow-hidden">
                    <CardHeader className="py-3 px-4 border-b" style={{ background: "#1F2839" }}>
                        <div className="grid grid-cols-10 gap-2 text-xs font-semibold text-white capitalize tracking-wider">
                            <span>Sr.</span>
                            <span>Date</span>
                            <span className="col-span-2">Teacher</span>
                            <span className="col-span-2">Rating</span>
                            <span className="col-span-2">Comments</span>
                            <span className="col-span-2 px-2">View Observation</span>
                        </div>
                    </CardHeader>
                    <CardContent className="p-0">
                        {loading ? (
                            <div className="flex items-center justify-center py-16 text-muted-foreground">Loading observations...</div>
                        ) : filtered.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-16 gap-3 text-muted-foreground">
                                <Palette className="w-12 h-12 opacity-20" />
                                <p className="font-medium">No Visual Arts observations yet</p>
                                <Button variant="outline" onClick={() => navigate(newPath)}><Plus className="w-4 h-4 mr-2" /> Start First Observation</Button>
                            </div>
                        ) : (
                            filtered.map((obs, idx) => (
                                <div key={obs.id} className={`grid grid-cols-10 gap-2 px-4 py-3 items-center hover:bg-amber-50 cursor-pointer border-b transition-colors text-sm ${idx % 2 === 0 ? "bg-white" : "bg-slate-50/50"}`}
                                    onClick={() => navigate(`/leader/va-obs/new?teacherId=${obs.teacherId}&id=${obs.id}`)}>
                                    <span className="font-medium text-slate-500">{idx + 1}</span>
                                    <span className="text-muted-foreground flex items-center gap-1"><Calendar className="w-3 h-3" />{obs.observationDate ? new Date(obs.observationDate).toLocaleDateString() : "—"}</span>
                                    <span className="col-span-2 font-medium text-slate-800">{obs.teacherName}</span>
                                    <span className="col-span-2">
                                        {obs.overallRating ? (
                                            <Badge className={`text-xs ${RATING_COLORS[obs.overallRating] || "bg-slate-100 text-slate-700"}`}>
                                                <Star className="w-3 h-3 mr-1" />{obs.overallRating}
                                            </Badge>
                                        ) : "—"}
                                    </span>
                                    <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                        <Dialog>
                                            <DialogTrigger asChild>
                                                <Button variant="outline" size="sm" className="h-7 text-xs gap-1 bg-blue-50 text-blue-700 border-blue-200 hover:bg-blue-100 hover:text-blue-800">
                                                    <MessageSquare className="w-3 h-3" /> View Comment
                                                </Button>
                                            </DialogTrigger>
                                            <DialogContent className="sm:max-w-[500px]">
                                                <DialogHeader>
                                                    <DialogTitle>Teacher Comment</DialogTitle>
                                                    <DialogDescription>
                                                        Insights and comments from the teacher.
                                                    </DialogDescription>
                                                </DialogHeader>
                                                <div className="space-y-4 py-4">
                                                    {obs.detailedReflection?.strengths && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Identified Strengths</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.strengths}</p>
                                                        </div>
                                                    )}
                                                    {obs.detailedReflection?.improvements && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Areas for Growth</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.improvements}</p>
                                                        </div>
                                                    )}
                                                    {obs.detailedReflection?.goal && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">Action Goal</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.detailedReflection.goal}</p>
                                                        </div>
                                                    )}
                                                    {obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                        <div>
                                                            <h4 className="font-semibold text-sm mb-1">General Comments</h4>
                                                            <p className="text-sm text-muted-foreground">{obs.teacherReflection}</p>
                                                        </div>
                                                    )}
                                                    {!obs.teacherReflection && !obs.detailedReflection?.strengths && (
                                                        <div className="text-center py-6 text-muted-foreground">
                                                            <MessageSquare className="w-8 h-8 mx-auto mb-2 opacity-20" />
                                                            <p className="text-sm">No comments provided by the teacher yet.</p>
                                                        </div>
                                                    )}
                                                </div>
                                            </DialogContent>
                                        </Dialog>
                                    </span>
                                    <span className="col-span-2" onClick={(e) => e.stopPropagation()}>
                                        <Button
                                            variant="outline"
                                            size="sm"
                                            className="h-7 text-xs gap-1 bg-amber-50 text-amber-700 border-amber-200 hover:bg-amber-100 hover:text-amber-800"
                                            onClick={() => navigate(`/leader/va-obs/new?teacherId=${obs.teacherId}&id=${obs.id}&mode=view`)}
                                        >
                                            <Eye className="w-3 h-3" /> VIEW
                                        </Button>
                                    </span>
                                </div>
                            ))
                        )}
                    </CardContent>
                </Card>
                {filtered.length > 0 && <p className="text-xs text-muted-foreground text-right mt-2">{filtered.length} record{filtered.length !== 1 ? "s" : ""} found</p>}
            </div>
        </GrowthLayout>

    );
};

export default VAObsDashboard;
